use std::collections::BinaryHeap;

struct GameSession {
    score: i32,
}

struct EventLogger {
    heap: BinaryHeap<GameSession>,
    capacity: usize,
}

impl EventLogger {
    fn new(capacity: usize) -> Self {
        EventLogger { 
            heap: BinaryHeap::new(),
            capacity
        }
    }

    fn add_score(&mut self, score: i32) {
        if self.heap.len() < self.capacity {
            self.heap.push(GameSession { score });
        } else if let Some(min_score) = self.heap.peek() {
            if score > min_score.score {
                self.heap.pop();
                self.heap.push(GameSession { score });
            }
        }
    }

    fn pop_highest_score(&mut self) -> Option<GameSession> {
        self.heap.pop()
    }
}

fn main() {
    let mut logger = EventLogger::new(500);

    // Example usage
    logger.add_score(100);
    logger.add_score(200);

    if let Some(session) = logger.pop_highest_score() {
        println!("Highest score session: {}", session.score);
    }
}
