use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct GameSessionManager {
    heap: BinaryHeap<Reverse<i32>>,
    capacity: usize,
}

impl GameSessionManager {
    fn new(capacity: usize) -> Self {
        Self {
            heap: BinaryHeap::with_capacity(capacity),
            capacity,
        }
    }

    fn add_score(&mut self, score: i32) {
        if self.heap.len() < self.capacity {
            self.heap.push(Reverse(score));
        } else if let Some(&Reverse(lowest)) = self.heap.peek() {
            if score > lowest {
                self.heap.pop();
                self.heap.push(Reverse(score));
            }
        }
    }

    fn get_top_score(&self) -> Option<i32> {
        self.heap.peek().map(|&Reverse(score)| score)
    }

    fn remove_top_score(&mut self) -> Option<i32> {
        self.heap.pop().map(|Reverse(score)| score)
    }
}

fn main() {
    let mut manager = GameSessionManager::new(500);

    // Example usage:
    manager.add_score(1500);
    manager.add_score(3000);

    if let Some(top_score) = manager.get_top_score() {
        println!("Top score: {}", top_score);
    }

    manager.remove_top_score();

    if let Some(top_score) = manager.get_top_score() {
        println!("New top score after removal: {}", top_score);
    }
}
