use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct EventLogger {
    max_heap: BinaryHeap<Reverse<u32>>,
    removed_scores: Vec<u32>,
}

impl EventLogger {
    fn new() -> Self {
        Self {
            max_heap: BinaryHeap::with_capacity(500),
            removed_scores: Vec::with_capacity(1000),
        }
    }

    fn push(&mut self, score: u32) {
        self.max_heap.push(Reverse(score));
        if self.max_heap.len() > 500 {
            if let Some(Reverse(removed_score)) = self.max_heap.pop() {
                self.log_removed_score(removed_score);
            }
        }
    }

    fn pop(&mut self) -> Option<u32> {
        if let Some(Reverse(score)) = self.max_heap.pop() {
            self.log_removed_score(score);
            return Some(score);
        }
        None
    }

    fn peek(&self) -> Option<u32> {
        self.max_heap.peek().map(|Reverse(score)| *score)
    }

    fn log_removed_score(&mut self, score: u32) {
        if self.removed_scores.len() < 1000 {
            self.removed_scores.push(score);
        }
    }
}

fn main() {
    let mut logger = EventLogger::new();
    logger.push(300);
    logger.push(450);
    logger.push(200);

    println!("Top score: {:?}", logger.peek());
    logger.pop();
    println!("Removed scores: {:?}", logger.removed_scores);
}
