public class RealTimeMessaging {
    private PriorityQueue<Message> queue;
    private static final int MAX_CAPACITY = 100;

    public RealTimeMessaging() {
        queue = new PriorityQueue<>(MAX_CAPACITY, Comparator.comparingInt(Message::getUrgency).reversed());
    }

    public synchronized boolean offerMessage(Message message) {
        if (queue.size() >= MAX_CAPACITY) {
            return false; // Unable to add as queue is full
        }
        return queue.offer(message);
    }

    public synchronized Message pollMessage() {
        return queue.poll(); // Retrieves and removes the most urgent message
    }
}
