    private final PriorityQueue<Message> messageQueue;
    private static final int MAX_CAPACITY = 100;

    public MessagingSystem() {
        this.messageQueue = new PriorityQueue<>(MAX_CAPACITY);
    }

    public boolean offerMessage(String content, int urgency) {
        if (messageQueue.size() < MAX_CAPACITY) {
            return messageQueue.offer(new Message(content, urgency));
        }
        // Handle overflow scenario if needed
        return false;
    }

    public Message pollMessage() {
        return messageQueue.poll();
    }

    public Message peekMessage() {
        return messageQueue.peek();
    }

    public static void main(String[] args) {
