import java.util.Comparator;
import java.util.LinkedList;
import java.util.PriorityQueue;

public class MessageHandler {

    private static class Message {
        private String content;
        private int priority;

        public Message(String content, int priority) {
            this.content = content;
            this.priority = priority;
        }

        public int getPriority() {
            return priority;
        }

        @Override
        public String toString() {
            return "Message{content='" + content + "', priority=" + priority + '}';
        }
    }

    private PriorityQueue<Message> messageQueue;
    private LinkedList<Message> processedMessages;
    private final int MAX_CAPACITY = 100;

    public MessageHandler() {
        messageQueue = new PriorityQueue<>(Comparator.comparingInt(Message::getPriority).reversed());
        processedMessages = new LinkedList<>();
    }

    public boolean addMessage(String content, int priority) {
        if (messageQueue.size() < MAX_CAPACITY) {
            messageQueue.offer(new Message(content, priority));
            return true;
        } else {
            System.out.println("Queue is at maximum capacity. Cannot add new message.");
            return false;
        }
    }

    public Message processNextMessage() {
        Message nextMessage = messageQueue.poll();
        if (nextMessage != null) {
            processedMessages.add(nextMessage);
        }
        return nextMessage;
    }

    public Message peekNextMessage() {
        return messageQueue.peek();
    }

    public LinkedList<Message> getProcessedMessages() {
        return processedMessages;
    }

    public static void main(String[] args) {
        // Example usage
        MessageHandler handler = new MessageHandler();
        handler.addMessage("Urgent message", 10);
        handler.addMessage("Regular message", 5);
        handler.addMessage("Low priority message", 1);

        System.out.println("Next message to process: " + handler.peekNextMessage());

        System.out.println("Processing: " + handler.processNextMessage());
        System.out.println("Processing: " + handler.processNextMessage());

        System.out.println("Processed messages: " + handler.getProcessedMessages());
    }
}
