import java.util.PriorityQueue;
import java.util.LinkedList;

public class MessagingSystem {

    private PriorityQueue<Message> messageQueue;
    private LinkedList<Message> processedMessages;
    private final int QUEUE_CAPACITY = 100;
    private final int LIST_CAPACITY = 200;

    public MessagingSystem() {
        messageQueue = new PriorityQueue<>(QUEUE_CAPACITY, (a, b) -> b.getUrgency() - a.getUrgency());
        processedMessages = new LinkedList<>();
    }

    public boolean offerMessage(Message message) {
        if (messageQueue.size() < QUEUE_CAPACITY) {
            return messageQueue.offer(message);
        }
        return false; // Queue overflow, cannot add more messages
    }

    public Message pollMessage() {
        if (!messageQueue.isEmpty()) {
            Message message = messageQueue.poll();
            storeProcessedMessage(message);
            return message;
        }
        return null; // No messages to process
    }

    public Message peekMessage() {
        return messageQueue.peek(); // Debugging and monitoring
    }

    private void storeProcessedMessage(Message message) {
        if (processedMessages.size() >= LIST_CAPACITY) {
            processedMessages.removeFirst(); // Manage overflow
        }
        processedMessages.add(message);
    }

    class Message {
        private int urgency;
        private String content;

        public Message(int urgency, String content) {
            this.urgency = urgency;
            this.content = content;
        }

        public int getUrgency() {
            return urgency;
        }

        public String getContent() {
            return content;
        }
    }
}
