use std::collections::HashSet;
use std::sync::{Mutex, Arc};
use std::thread;

// Maximum number of tags per instance
const MAX_TAGS: usize = 10;
// Maximum concurrent instances
const MAX_INSTANCES: usize = 5;

// Struct to manage tags and enforce limits
struct TagManager {
    tags: HashSet<String>,
}

impl TagManager {
    fn new() -> Self {
        TagManager {
            tags: HashSet::with_capacity(MAX_TAGS),
        }
    }

    fn add_tag(&mut self, tag: &str) -> Result<(), &'static str> {
        if self.tags.len() >= MAX_TAGS {
            return Err("Cannot add more than 10 tags.");
        }
        self.tags.insert(tag.to_string());
        Ok(())
    }

    fn contains_tag(&self, tag: &str) -> bool {
        self.tags.contains(tag)
    }

    fn remove_tag(&mut self, tag: &str) -> bool {
        self.tags.remove(tag)
    }
}

fn main() {
    // Arc to manage a limited number of TagManager instances
    let tag_managers: Arc<Mutex<Vec<TagManager>>> = Arc::new(Mutex::new(Vec::new()));

    // Example usage with concurrent instances administered by threads
    let handles: Vec<_> = (0..MAX_INSTANCES).map(|_| {
        let tag_managers = Arc::clone(&tag_managers);
        thread::spawn(move || {
            let mut tm = TagManager::new();
            tm.add_tag("technology").unwrap();
            tm.add_tag("rust").unwrap();

            let contains_rust = tm.contains_tag("rust");
            if contains_rust {
                println!("'rust' tag exists");
            }

            tm.remove_tag("rust");
            println!("'rust' tag removed");

            // Add instance of TagManager to the vector
            let mut managers_guard = tag_managers.lock().unwrap();
            managers_guard.push(tm);
        })
    }).collect();

    for handle in handles {
        handle.join().unwrap();
    }

    println!("Total instances created: {}", tag_managers.lock().unwrap().len());
}
