use std::collections::HashSet;
use std::sync::{Arc, Mutex};

struct TagManager {
    tags_set: HashSet<String>,
}

impl TagManager {
    fn new() -> TagManager {
        TagManager {
            tags_set: HashSet::with_capacity(10),
        }
    }

    fn insert_tag(&mut self, tag: String) -> Result<(), &'static str> {
        if self.tags_set.len() >= 10 {
            return Err("Cannot add more than 10 tags");
        }
        self.tags_set.insert(tag);
        Ok(())
    }

    fn contains_tag(&self, tag: &str) -> bool {
        self.tags_set.contains(tag)
    }
}

struct ConcurrentTagManager {
    instances: Arc<Mutex<i32>>,
    max_instances: i32,
}

impl ConcurrentTagManager {
    fn new(max_instances: i32) -> Self {
        Self {
            instances: Arc::new(Mutex::new(0)),
            max_instances,
        }
    }

    fn create_instance(&self) -> Result<TagManager, &'static str> {
        let mut current_instances = self.instances.lock().unwrap();
        if *current_instances >= self.max_instances {
            return Err("Maximum concurrent instances exceeded");
        }
        *current_instances += 1;
        Ok(TagManager::new())
    }

    fn release_instance(&self) {
        let mut current_instances = self.instances.lock().unwrap();
        if *current_instances > 0 {
            *current_instances -= 1;
        }
    }
}

fn main() {
    let concurrent_manager = ConcurrentTagManager::new(5);
    match concurrent_manager.create_instance() {
        Ok(mut manager) => {
            manager.insert_tag("rust".to_string()).unwrap();
            println!("Contains 'rust': {}", manager.contains_tag("rust"));
            concurrent_manager.release_instance();
        }
        Err(e) => println!("{}", e),
    }
}
