package main

import (
	"fmt"
	"sync"
)

type Classroom struct {
	students []string
	maxCap   int
	mu       sync.Mutex
}

func NewClassroom() *Classroom {
	return &Classroom{
		students: make([]string, 0, 50),
		maxCap:   50,
	}
}

func (c *Classroom) AddStudent(name string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	if len(c.students) < c.maxCap {
		c.students = append(c.students, name)
	}
}

func (c *Classroom) GetReport() []string {
	c.mu.Lock()
	defer c.mu.Unlock()
	report := make([]string, len(c.students))
	copy(report, c.students)
	return report
}

func (c *Classroom) TotalCount() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return len(c.students)
}

func main() {
	classroom := NewClassroom()
	classroom.AddStudent("John Doe")
	classroom.AddStudent("Jane Smith")

	fmt.Println("Current students:", classroom.GetReport())
	fmt.Println("Total student count:", classroom.TotalCount())
}
