		stack:       make([]string, 0),
		maxSize:     50,
		leftStudents: make([]string, 0),
		maxLeftSize:  20,
	}
}

func (c *Classroom) push(name string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	if len(c.stack) < c.maxSize {
		c.stack = append(c.stack, name)
	}
}

func (c *Classroom) pop() string {
	c.mu.Lock()
	defer c.mu.Unlock()
	if len(c.stack) == 0 {
		return ""
	}
	student := c.stack[len(c.stack)-1]
	c.stack = c.stack[:len(c.stack)-1]

	if len(c.leftStudents) < c.maxLeftSize {
		c.leftStudents = append(c.leftStudents, student)
	}

	return student
}

func (c *Classroom) count() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return len(c.stack)
}

func (c *Classroom) copyCurrentStack() []string {
	c.mu.Lock()
	defer c.mu.Unlock()
	copyStack := make([]string, len(c.stack))
	copy(copyStack, c.stack)
	return copyStack
}

func (c *Classroom) contains(name string) bool {
	c.mu.Lock()
	defer c.mu.Unlock()
	for _, student := range c.stack {
		if student == name {
			return true
		}
	}
	return false
}

