use std::collections::HashSet;

#[derive(Debug, Clone)]
struct DocumentVersion {
    timestamp: u64,
    content: String,
}

#[derive(Debug)]
struct DocumentTracking {
    histories: Vec<DocumentVersion>,
    timestamps: HashSet<u64>,
}

impl DocumentTracking {
    fn new() -> Self {
        DocumentTracking {
            histories: Vec::new(),
            timestamps: HashSet::new(),
        }
    }

    fn add_version(&mut self, version: DocumentVersion) -> Result<(), String> {
        if self.timestamps.contains(&version.timestamp) {
            return Err("Duplicate timestamp detected!".to_string());
        }
        self.timestamps.insert(version.timestamp);
        self.histories.push(version);
        Ok(())
    }

    fn insert_version(&mut self, index: usize, version: DocumentVersion) -> Result<(), String> {
        if self.timestamps.contains(&version.timestamp) {
            return Err("Duplicate timestamp detected!".to_string());
        }
        if index <= self.histories.len() {
            self.timestamps.insert(version.timestamp);
            self.histories.insert(index, version);
            Ok(())
        } else {
            Err("Index out of bounds!".to_string())
        }
    }
}

fn main() {
    let mut tracking = DocumentTracking::new();
    match tracking.add_version(DocumentVersion {
        timestamp: 1633024800,
        content: String::from("Initial document version"),
    }) {
        Ok(_) => println!("Version added successfully."),
        Err(e) => println!("Error: {}", e),
