use std::time::SystemTime;
use std::{collections::HashSet, error::Error, fmt};

#[derive(Debug, Clone)]
struct DocumentVersion {
    content: String,
    timestamp: SystemTime,
}

#[derive(Debug)]
struct VersionOverflowError;
impl fmt::Display for VersionOverflowError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Exceeded maximum number of document versions.")
    }
}
impl Error for VersionOverflowError {}

#[derive(Debug)]
struct DuplicateTimestampError;
impl fmt::Display for DuplicateTimestampError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Duplicate timestamp detected.")
    }
}
impl Error for DuplicateTimestampError {}

struct DocumentTracker {
    versions: Vec<DocumentVersion>,
    timestamps: HashSet<SystemTime>,
    max_versions: usize,
}

impl DocumentTracker {
    fn new() -> Self {
        Self {
            versions: Vec::new(),
            timestamps: HashSet::new(),
            max_versions: 100,
        }
    }

    fn add_version(&mut self, content: String, timestamp: SystemTime) -> Result<(), Box<dyn Error>> {
        if self.versions.len() >= self.max_versions {
            return Err(Box::new(VersionOverflowError));
        }

        if !self.timestamps.insert(timestamp) {
            return Err(Box::new(DuplicateTimestampError));
        }

        let version = DocumentVersion { content, timestamp };
        self.versions.push(version);
        self.versions.sort_by_key(|v| v.timestamp);

        Ok(())
    }
}

fn main() {
    let mut tracker = DocumentTracker::new();
    let timestamp = SystemTime::now();

    match tracker.add_version("Initial Version".to_string(), timestamp) {
        Ok(_) => println!("Version added successfully."),
        Err(e) => println!("Error: {}", e),
    }
}
