#[derive(Debug)]
struct DocumentTracker {
    history: Vec<DocumentVersion>,
    timestamp_set: HashSet<u64>,
    max_versions: usize,
}

impl DocumentTracker {
    fn new(max_versions: usize) -> Self {
        DocumentTracker {
            history: Vec::new(),
            timestamp_set: HashSet::new(),
            max_versions,
        }
    }

    fn add_version(&mut self, content: String) -> Result<(), String> {
        if self.history.len() >= self.max_versions {
            return Err("Cannot add new version: maximum capacity reached".into());
        }

        let timestamp = SystemTime::now().duration_since(UNIX_EPOCH)
            .expect("Time went backwards")
            .as_secs();

        if self.timestamp_set.contains(&timestamp) {
            return Err("Cannot add new version: duplicate timestamp detected".into());
        }

        let new_version = DocumentVersion { timestamp, content };

        self.history.push(new_version);
        self.timestamp_set.insert(timestamp);

        // Ensure history is sorted by timestamps
        self.history.sort_by_key(|version| version.timestamp);

        Ok(())
    }

    fn get_version_history(&self) -> VecDeque<DocumentVersion> {
        VecDeque::from(self.history.clone())
    }
}

