use std::collections::VecDeque;
use std::time::SystemTime;
use std::cmp::Ordering;

#[derive(Debug, Clone)]
struct DocumentVersion {
    timestamp: SystemTime,
    content: String,
}

#[derive(Debug)]
struct DocumentTracker {
    versions: Vec<DocumentVersion>,
    history: VecDeque<DocumentVersion>,
    max_versions: usize,
}

impl DocumentTracker {
    fn new() -> Self {
        DocumentTracker {
            versions: Vec::new(),
            history: VecDeque::new(),
            max_versions: 100,
        }
    }

    fn add_version(&mut self, content: String) -> Result<(), &'static str> {
        let timestamp = SystemTime::now();

        // Check for duplicate timestamps
        if self.versions.iter().any(|v| v.timestamp == timestamp) {
            return Err("Duplicate timestamp detected");
        }

        // Check for capacity overflow
        if self.versions.len() >= self.max_versions {
            return Err("Maximum number of document versions exceeded");
        }

        let new_version = DocumentVersion {
            timestamp,
            content,
        };

        // Push the new version and maintain sorted order by timestamp
        self.versions.push(new_version);
        self.versions.sort_by(|a, b| a.timestamp.cmp(&b.timestamp));

        Ok(())
    }

    fn push_history(&mut self, version: DocumentVersion) {
        self.history.push_back(version);
    }

    fn pop_front_history(&mut self) -> Option<DocumentVersion> {
        self.history.pop_front()
    }

    fn pop_back_history(&mut self) -> Option<DocumentVersion> {
        self.history.pop_back()
    }
}

fn main() {
    let mut tracker = DocumentTracker::new();

    match tracker.add_version("First version".to_string()) {
        Ok(_) => println!("Document version added successfully."),
        Err(e) => println!("Error adding version: {}", e),
    }

    match tracker.add_version("Second version".to_string()) {
        Ok(_) => println!("Document version added successfully."),
        Err(e) => println!("Error adding version: {}", e),
    }

    // Example of pushing to history
    if let Some(last_version) = tracker.versions.last() {
        tracker.push_history(last_version.clone());
    }

    // Example of popping from history
    if let Some(first_history) = tracker.pop_front_history() {
        println!("Popped from history: {:?}", first_history);
    }
}
