            songs: LinkedList::new(),
        }
    }

    fn add_song(&mut self, song: String) {
        if self.songs.len() >= 10 {
            self.songs.pop_front();
        }
        self.songs.push_back(song);
    }

    fn remove_oldest_song(&mut self) {
        self.songs.pop_front();
    }

    fn count_songs(&self) -> usize {
        self.songs.len()
    }

    fn shuffle_playlist(&mut self) {
        let mut song_vec: Vec<_> = self.songs.iter().cloned().collect();
        let mut rng = rand::thread_rng();
        song_vec.shuffle(&mut rng);
        self.songs = song_vec.into_iter().collect();
    }

    fn find_song(&self, title: &str) -> Option<&String> {
        self.songs.iter().find(|&&ref song| song == title)
    }
}

fn main() {
    let mut playlist = Playlist::new();

    // Add songs to the playlist
    playlist.add_song("Song A".to_string());
    playlist.add_song("Song B".to_string());
    playlist.add_song("Song C".to_string());

    // Remove the oldest song from the playlist
    playlist.remove_oldest_song();

    // Count the current number of songs
    let song_count = playlist.count_songs();
    println!("Number of songs in playlist: {}", song_count);

    // Shuffle the playlist
    playlist.shuffle_playlist();

    // Find a song by title
    if let Some(song) = playlist.find_song("Song B") {
        println!("Found song: {}", song);
    } else {
        println!("Song not found");
    }
}
