			if res.Date == detail.Date && res.TableNo == detail.TableNo {
				return "Double booking not allowed on the same date and table."
			}
		}
		rs.reservations[name] = detail
		return "Reservation added."
	} else {
		rs.waitlist = append(rs.waitlist, detail)
		return "Reservation added to the waitlist."
	}
}

// CancelReservation removes a reservation and handles the waitlist
func (rs *ReservationSystem) CancelReservation(name string) string {
	if _, exists := rs.reservations[name]; exists {
		delete(rs.reservations, name)
		if len(rs.waitlist) > 0 {
