			rs.waitlist = rs.waitlist[1:]
			for waitName, waitDetail := range rs.reservations {
				if waitDetail == (ReservationDetail{}) {
					rs.reservations[waitName] = next
					break
				}
			}
		}
		return "Reservation cancelled."
	} else {
		return "Reservation not found."
	}
}

