		if r.Date.Equal(reservation.Date) && r.TableNumber == reservation.TableNumber {
			rs.reservations[name] = append(rs.reservations[name][:i], rs.reservations[name][i+1:]...)
			if len(rs.reservations[name]) == 0 {
