package main

import (
	"fmt"
	"sync"
	"time"
)

// Reservation stores a reservation with date and table number
type Reservation struct {
	Date      time.Time
	TableNumber int
}

// ReservationSystem manages reservations and waitlist
type ReservationSystem struct {
	mu          sync.Mutex
	reservations map[string]Reservation
	waitlist     []struct{ Name string; Details Reservation }
	maxCapacity  int
}

// NewReservationSystem initializes a new ReservationSystem
func NewReservationSystem() *ReservationSystem {
	return &ReservationSystem{
		reservations: make(map[string]Reservation),
		waitlist:     []struct{ Name string; Details Reservation }{},
		maxCapacity:  50,
	}
}

// AddReservation adds a new reservation, handles waitlist if full
func (rs *ReservationSystem) AddReservation(name string, date time.Time, table int) bool {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	// Prevents double bookings for the same table on identical dates
	for _, r := range rs.reservations {
		if r.Date.Equal(date) && r.TableNumber == table {
			return false
		}
	}

	// Check capacity
	if len(rs.reservations) < rs.maxCapacity {
		rs.reservations[name] = Reservation{Date: date, TableNumber: table}
		return true
	} else {
		rs.waitlist = append(rs.waitlist, struct{ Name string; Details Reservation }{name, Reservation{Date: date, TableNumber: table}})
		return false
	}
}

// CancelReservation cancels existing reservation and shifts waitlisted reservation
func (rs *ReservationSystem) CancelReservation(name string) {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	delete(rs.reservations, name)

	// Shift waitlist reservations if there's space
	if len(rs.waitlist) > 0 && len(rs.reservations) < rs.maxCapacity {
		wait := rs.waitlist[0]
		rs.waitlist = rs.waitlist[1:]
		rs.reservations[wait.Name] = wait.Details
	}
}

// RetrieveReservation retrieves reservation details
func (rs *ReservationSystem) RetrieveReservation(name string) (Reservation, bool) {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	res, exists := rs.reservations[name]
	return res, exists
}

// CleanupExpiredReservations removes past reservations
func (rs *ReservationSystem) CleanupExpiredReservations() {
	rs.mu.Lock()
	defer rs.mu.Unlock()

	now := time.Now()
	for name, res := range rs.reservations {
		if res.Date.Before(now) {
			delete(rs.reservations, name)
		}
	}

	// Shift waitlist if any space is available
	for len(rs.waitlist) > 0 && len(rs.reservations) < rs.maxCapacity {
		wait := rs.waitlist[0]
		if wait.Details.Date.After(now) { // only shift if not expired
			rs.waitlist = rs.waitlist[1:]
			rs.reservations[wait.Name] = wait.Details
		} else {
			rs.waitlist = rs.waitlist[1:]
		}
	}
}

func main() {
	// Example usage (add main logic)
	rs := NewReservationSystem()
	rs.AddReservation("Alice", time.Now().AddDate(0, 0, 1), 1)
	rs.CancelReservation("Alice")
	rs.CleanupExpiredReservations()
	fmt.Println(rs.RetrieveReservation("Alice"))
}
