	return &ReservationSystem{
		Reservations: make(map[string][]Reservation),
		Waitlist:     []Reservation{},
	}
}

func (rs *ReservationSystem) AddReservation(name string, reservation Reservation) bool {
	if countActiveReservations(rs.Reservations) >= MaxReservations {
		rs.Waitlist = append(rs.Waitlist, reservation)
		return false
	}

	for _, res := range rs.Reservations[name] {
		if res.Date.Equal(reservation.Date) && res.Table == reservation.Table {
			return false
		}
	}

	rs.Reservations[name] = append(rs.Reservations[name], reservation)
	return true
}

func (rs *ReservationSystem) DeleteReservation(name string, index int) bool {
	if _, exists := rs.Reservations[name]; exists && index < len(rs.Reservations[name]) {
		rs.Reservations[name] = removeIndex(rs.Reservations[name], index)
		shiftWaitlist(rs)
		return true
	}
	return false
}

func (rs *ReservationSystem) UpdateReservation(name string, index int, reservation Reservation) bool {
	if _, exists := rs.Reservations[name]; exists && index < len(rs.Reservations[name]) {
		rs.Reservations[name][index] = reservation
		return true
	}
	return false
}

func (rs *ReservationSystem) CleanupExpiredReservations() {
	now := time.Now()
	for name, reservations := range rs.Reservations {
		validReservations := []Reservation{}
		for _, res := range reservations {
			if res.Date.After(now) {
				validReservations = append(validReservations, res)
			}
		}
		rs.Reservations[name] = validReservations
	}
	shiftWaitlist(rs)
}

func countActiveReservations(reservations map[string][]Reservation) int {
	count := 0
	for _, res := range reservations {
		count += len(res)
	}
	return count
}

func shiftWaitlist(rs *ReservationSystem) {
	for countActiveReservations(rs.Reservations) < MaxReservations && len(rs.Waitlist) > 0 {
		waitlistReservation := rs.Waitlist[0]
		rs.Waitlist = rs.Waitlist[1:]
		rs.AddReservation("", waitlistReservation)
	}
}

func removeIndex(s []Reservation, index int) []Reservation {
	return append(s[:index], s[index+1:]...)
}

func main() {
	// Example usage
	system := NewReservationSystem()
	reservation := Reservation{
		Date:  time.Now().Add(24 * time.Hour),
		Table: 1,
		Detail: "Dinner",
	}
	system.AddReservation("John Doe", reservation)
}
