import "fmt"

type Inventory struct {
	stocks []int
}

func NewInventory() *Inventory {
	return &Inventory{stocks: make([]int, 0, 10)}
}

func (inv *Inventory) AddStock(stock int) error {
	if len(inv.stocks) >= 10 {
		return fmt.Errorf("inventory is full")
	}
	inv.stocks = append(inv.stocks, stock)
	return nil
}

func (inv *Inventory) UpdateStock(stock int) error {
	if len(inv.stocks) >= 10 {
		// dequeue operation to remove the first element
		inv.stocks[len(inv.stocks)-10] = 0 // Just ensuring freeing up the memory
		inv.stocks = inv.stocks[1:]
	}

	inv.stocks = append(inv.stocks, stock)
	return nil
}

func (inv *Inventory) RemoveOutOfStock() error {
	if len(inv.stocks) == 0 {
		return fmt.Errorf("inventory is empty")
	}
	inv.stocks[len(inv.stocks)-len(inv.stocks)] = 0 // Just ensuring freeing up the memory
	inv.stocks = inv.stocks[1:] // dequeue operation
	return nil
}

func (inv *Inventory) Peek() (int, error) {
	if len(inv.stocks) == 0 {
		return 0, fmt.Errorf("inventory is empty")
	}
	return inv.stocks[0], nil
}

func main() {
	inv := NewInventory()

	err := inv.AddStock(5)
	if err != nil {
		fmt.Println(err)
	}
	err = inv.UpdateStock(10)
	if err != nil {
		fmt.Println(err)
	}
	peekVal, err := inv.Peek()
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Printf("Stock to be checked out: %d\n", peekVal)
	}

	err = inv.RemoveOutOfStock()
	if err != nil {
		fmt.Println(err)
	}
}
