	if len(ls.stack) == 0 {
		return nil
	}
	log := ls.stack[len(ls.stack)-1]
	ls.stack = ls.stack[:len(ls.stack)-1]
	return log
}

func (ls *LogStack) Peek() *LogEntry {
	if len(ls.stack) == 0 {
		return nil
	}
	return ls.stack[len(ls.stack)-1]
}

