	logStack.Push(&LogEntry{Timestamp: time.Now(), Message: "First log entry"})
	logStack.Push(&LogEntry{Timestamp: time.Now(), Message: "Second log entry"})

	peekLog := logStack.Peek()
	fmt.Println("Peek:", peekLog)

	poppedLog := logStack.Pop()
	fmt.Println("Popped:", poppedLog)
