class StackOverflowException : public std::exception {
public:
    const char* what() const throw() {
        return "Stack overflow: Maximum size of 10 exceeded.";
    }
};

int evaluatePostfix(const std::string& expression) {
    std::stack<int> s;
    size_t maxStackSize = 10;

    for (size_t i = 0; i < expression.size(); ++i) {
        char token = expression[i];

        if (isspace(token)) continue;

        if (isdigit(token)) {
            int num = token - '0';
            if (s.size() >= maxStackSize) throw StackOverflowException();
            s.push(num);
        } 
        else {
            if (s.size() < 2) return -1; // Invalid expression error
            int b = s.top(); s.pop();
            int a = s.top(); s.pop();

            int result;
            switch (token) {
                case '+':
                    result = a + b;
                    break;
                case '-':
                    result = a - b;
                    break;
                case '*':
                    result = a * b;
                    break;
                case '/':
                    if (b == 0) return -1; // Division by zero error
                    result = a / b;
                    break;
                default:
                    return -1; // Unknown token error
            }
            if (s.size() >= maxStackSize) throw StackOverflowException();
            s.push(result);
        }
    }
    return (s.size() == 1 ? s.top() : -1); // Final result or error
}

int main() {
    std::string expression = "23*54*+";
    try {
        int result = evaluatePostfix(expression);
        if (result == -1) std::cout << "Error in expression\n";
        else std::cout << "Result: " << result << "\n";
    } catch (const std::exception& e) {
        std::cout << e.what() << "\n";
    }
    return 0;
