#include <iostream>
#include <stack>
#include <string>
#include <stdexcept>

class StackLimitedSize : public std::stack<int> {
public:
    void push(int x) {
        if (this->size() >= 10) {
            throw std::overflow_error("Stack size exceeded the limit of 10");
        }
        std::stack<int>::push(x);
    }

    int pop() {
        if (this->empty()) {
            throw std::underflow_error("Stack underflow");
        }
        int top = std::stack<int>::top();
        std::stack<int>::pop();
        return top;
    }
};

int performOperation(int a, int b, char op) {
    switch(op) {
        case '+':
            return a + b;
        case '-':
            return a - b;
        case '*':
            return a * b;
        case '/':
            if (b == 0) {
                throw std::runtime_error("Division by zero");
            }
            return a / b;
        default:
            throw std::runtime_error("Invalid operation");
    }
}

std::string evaluatePostfix(const std::string& expression) {
    StackLimitedSize stack;
    int operationCount[4] = {0, 0, 0, 0}; // Indexes: 0 - addition, 1 - subtraction, 2 - multiplication, 3 - division

    for (size_t i = 0; i < expression.size(); ++i) {
        char token = expression[i];

        if (std::isdigit(token)) {
            stack.push(token - '0');
        } else if (token == '+' || token == '-' || token == '*' || token == '/') {
            try {
                int b = stack.pop();
                int a = stack.pop();
                int result = performOperation(a, b, token);

                stack.push(result);

                switch(token) {
                    case '+': operationCount[0]++; break;
                    case '-': operationCount[1]++; break;
                    case '*': operationCount[2]++; break;
                    case '/': operationCount[3]++; break;
                }
            } catch (const std::exception& e) {
                return e.what();
            }
        } else if (!std::isspace(token)) {
            return "Invalid symbol";
        }
    }

    try {
        if (stack.size() != 1) {
            throw std::runtime_error("Invalid postfix expression");
        }
        int result = stack.pop();
        return "Result: " + std::to_string(result) + "\nOperations: Add=" + std::to_string(operationCount[0]) +
               " Subtract=" + std::to_string(operationCount[1]) + " Multiply=" + std::to_string(operationCount[2]) +
               " Divide=" + std::to_string(operationCount[3]);
    } catch (const std::exception& e) {
        return e.what();
    }
}

int main() {
    std::string expression1 = "53+82-*";
    std::string expression2 = "12345678901+";
    std::string expression3 = "56/0+";

    std::cout << evaluatePostfix(expression1) << std::endl; // Valid expression
    std::cout << evaluatePostfix(expression2) << std::endl; // Overflow test
    std::cout << evaluatePostfix(expression3) << std::endl; // Division by zero test

    return 0;
}
