use std::collections::HashMap;

struct Inventory {
    stock: HashMap<String, i32>,
    max_capacity: usize,
}

impl Inventory {
    fn new(max_capacity: usize) -> Self {
        Self {
            stock: HashMap::new(),
            max_capacity,
        }
    }

    fn update_stock(&mut self, product_id: String, quantity: i32) {
        if self.stock.contains_key(&product_id) {
            self.stock.insert(product_id.clone(), self.stock.get(&product_id).unwrap() + quantity);
        } else {
            if self.stock.len() >= self.max_capacity {
                let least_recently_updated = self.stock.keys().next().unwrap().clone();
                self.stock.remove(&least_recently_updated);
            }
            self.stock.insert(product_id.clone(), quantity);
        }

        if let Some(&q) = self.stock.get(&product_id) {
            if q <= 0 {
                self.stock.remove(&product_id);
            }
        }
    }

    fn get_stock(&self, product_id: &str) -> Option<i32> {
        self.stock.get(product_id).copied()
    }
}

fn main() {
    let mut inventory = Inventory::new(50);

    inventory.update_stock("product_1".to_string(), 20);
    inventory.update_stock("product_2".to_string(), 30);

    if let Some(stock) = inventory.get_stock("product_1") {
        println!("Product 1 stock: {}", stock);
    } else {
        println!("Product 1 not in stock");
    }

    inventory.update_stock("product_1".to_string(), -20);

    if let Some(stock) = inventory.get_stock("product_1") {
