use std::collections::HashMap;

struct Inventory {
    stock: HashMap<String, i32>,
    access_order: Vec<String>,
    capacity: usize,
}

impl Inventory {
    fn new(capacity: usize) -> Self {
        Inventory {
            stock: HashMap::new(),
            access_order: Vec::new(),
            capacity,
        }
    }

    fn manage_inventory(&mut self, product_id: String, quantity: i32) {
        if quantity > 0 {
            if self.stock.contains_key(&product_id) || self.stock.len() < self.capacity {
                self.stock.insert(product_id.clone(), quantity);
                self.access_order.push(product_id);
            } else {
                let lru_item = self.access_order.remove(0);
                self.stock.remove(&lru_item);
                self.stock.insert(product_id.clone(), quantity);
                self.access_order.push(product_id);
            }
        } else if quantity == 0 {
            self.stock.remove(&product_id);
            self.access_order.retain(|id| id != &product_id);
        }
    }

    fn get_stock(&self, product_id: &str) -> Option<&i32> {
        match self.stock.get(product_id) {
            Some(quantity) => {
                let mut idx = None;
                for (i, id) in self.access_order.iter().enumerate() {
                    if id == product_id {
                        idx = Some(i);
                        break;
                    }
                }
                if let Some(i) = idx {
                    self.access_order.push(self.access_order.remove(i));
                }
                Some(quantity)
            }
            None => None,
        }
    }
}

fn main() {
    let mut inventory = Inventory::new(50);
    inventory.manage_inventory("product1".to_string(), 10);
    inventory.manage_inventory("product2".to_string(), 5);
