use std::collections::{HashMap, HashSet};
use std::time::{Duration, Instant};

struct InventoryManager {
    stock: HashMap<String, (i32, Instant)>,
    inactive: HashSet<String>,
    capacity: usize,
}

impl InventoryManager {
    fn new(capacity: usize) -> Self {
        Self {
            stock: HashMap::new(),
            inactive: HashSet::new(),
            capacity,
        }
    }

    fn manage_inventory(&mut self, product_id: String, quantity: i32) {
        let now = Instant::now();

        if self.stock.contains_key(&product_id) {
            let (current_quantity, _) = self.stock.get(&product_id).unwrap();
            let new_quantity = current_quantity + quantity;

            if new_quantity > 0 {
                self.stock.insert(product_id.clone(), (new_quantity, now));
            } else {
                self.stock.remove(&product_id);
            }
        } else if quantity > 0 {
            if self.stock.len() >= self.capacity {
                let lru_key = self.stock.iter()
                    .min_by_key(|(_, &(_, time))| time)
                    .map(|(key, _)| key.clone())
                    .unwrap();

                self.stock.remove(&lru_key);
            }

            self.stock.insert(product_id.clone(), (quantity, now));
        }

        self.inactive.clear();
        for (key, &(_, last_access_time)) in &self.stock {
            if now.duration_since(last_access_time) > Duration::from_secs(3600) {
                self.inactive.insert(key.clone());
            }
        }
    }

    fn get_stock_level(&self, product_id: &String) -> Option<i32> {
        self.stock.get(product_id).map(|&(quantity, _)| quantity)
    }

    fn get_inactive_products(&self) -> HashSet<String> {
        self.inactive.clone()
    }
}
