use std::collections::{HashMap, HashSet};
use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct InventoryManager {
    stock: HashMap<String, i32>,
    access_order: Vec<String>,
    max_capacity: usize,
    inactive_products: HashSet<String>,
    restock_alerts: BinaryHeap<Reverse<(i32, String)>>,
    inactive_threshold: i32,
}

impl InventoryManager {
    fn new(max_capacity: usize, inactive_threshold: i32) -> Self {
        InventoryManager {
            stock: HashMap::new(),
            access_order: Vec::new(),
            max_capacity,
            inactive_products: HashSet::new(),
            restock_alerts: BinaryHeap::new(),
            inactive_threshold,
        }
    }

    fn update_stock(&mut self, product_id: &str, quantity: i32) {
        self.access_order.push(product_id.to_string());

        if let Some(&current_quantity) = self.stock.get(product_id) {
            let updated_quantity = current_quantity + quantity;
            if updated_quantity > 0 {
                self.stock.insert(product_id.to_string(), updated_quantity);
            } else {
                self.stock.remove(product_id);
            }
        } else if quantity > 0 {
            if self.stock.len() >= self.max_capacity {
                self.evict_lru_item();
            }
            self.stock.insert(product_id.to_string(), quantity);
        }

        if quantity > 0 && quantity < self.inactive_threshold {
            self.inactive_products.insert(product_id.to_string());
            self.restock_alerts.push(Reverse((quantity, product_id.to_string())));
        }
    }

    fn get_stock(&mut self, product_id: &str) -> Option<i32> {
        self.access_order.push(product_id.to_string());
        self.stock.get(product_id).copied()
    }

    fn evict_lru_item(&mut self) {
        if let Some(lru_item) = self.access_order.first().cloned() {
            self.stock.remove(&lru_item);
            self.access_order.retain(|item| item != &lru_item);
            self.inactive_products.remove(&lru_item);
        }
    }

    fn get_inactive_products(&self) -> HashSet<String> {
        self.inactive_products.clone()
    }

    fn get_restock_alerts(&self) -> Vec<(i32, String)> {
        self.restock_alerts.clone().into_sorted_vec().into_iter().map(|item| item.0).collect()
    }
}
