public class BrowserHistory {
    private Vector<String> history;
    private static final int MAX_PAGES = 10;

    public BrowserHistory() {
        history = new Vector<>();
    }

    public void navigateTo(String page) {
        if (history.size() >= MAX_PAGES) {
            // Pop the last page
            history.remove(MAX_PAGES - 1);
        }
        // Push the new page
        history.add(0, page);
    }

    public String goBack() {
        if (history.size() > 1) {
            // Pop the current page and return to the previous one
            return history.remove(0);
        }
        return null; // No page to go back to
    }

    public String getCurrentPage() {
        if (!history.isEmpty()) {
            // Peek the current page
            return history.firstElement();
        }
        return null; // History is empty
    }

    public static void main(String[] args) {
        BrowserHistory browserHistory = new BrowserHistory();
        browserHistory.navigateTo("Page 1");
        browserHistory.navigateTo("Page 2");
        System.out.println("Current Page: " + browserHistory.getCurrentPage()); // Page 2
        browserHistory.goBack();
        System.out.println("Current Page: " + browserHistory.getCurrentPage()); // Page 1
    }
