import java.util.HashMap;
import java.util.LinkedList;
import java.util.HashSet;

public class InventoryManager {
    private final HashSet<String> inventory;
    private final LinkedList<String> accessOrder;
    private final int MAX_CAPACITY = 50;
    private final Object lock = new Object();

    public InventoryManager() {
        inventory = new HashSet<>(MAX_CAPACITY);
        accessOrder = new LinkedList<>();
    }

    public boolean addProduct(String product) {
        synchronized (lock) {
            if (inventory.size() >= MAX_CAPACITY) {
                String leastAccessed = accessOrder.poll();
                if (leastAccessed != null) {
                    inventory.remove(leastAccessed);
                }
            }
            boolean added = inventory.add(product);
            if (added) {
                accessOrder.add(product);
            }
            return added;
        }
    }

    public boolean removeProduct(String product) {
        synchronized (lock) {
            boolean removed = inventory.remove(product);
            if (removed) {
                accessOrder.remove(product);
            }
            return removed;
        }
    }

    public boolean containsProduct(String product) {
        synchronized (lock) {
            boolean contains = inventory.contains(product);
            if (contains) {
                accessOrder.remove(product);
                accessOrder.add(product);
            }
            return contains;
        }
    }

    public int inventorySize() {
        synchronized (lock) {
            return inventory.size();
        }
    }
}
