enum Priority {
    Normal,
    Urgent,
}

#[derive(Debug)]
struct FloorRequest {
    floor: u32,
    priority: Priority,
}

struct ElevatorQueue {
    normal_requests: Vec<FloorRequest>,
    urgent_requests: Vec<FloorRequest>,
}

impl ElevatorQueue {
    fn new() -> Self {
        ElevatorQueue {
            normal_requests: Vec::with_capacity(10),
            urgent_requests: Vec::with_capacity(10),
        }
    }

    fn push(&mut self, request: FloorRequest) {
        match request.priority {
            Priority::Urgent => {
                if self.urgent_requests.len() + self.normal_requests.len() < 15 {
                    self.urgent_requests.push(request);
                }
            }
            Priority::Normal => {
                if self.normal_requests.len() + self.urgent_requests.len() < 15 {
                    self.normal_requests.push(request);
                }
            }
        }
    }

    fn pop(&mut self) -> Option<FloorRequest> {
        if !self.urgent_requests.is_empty() {
            self.urgent_requests.remove(0)
        } else if !self.normal_requests.is_empty() {
            self.normal_requests.remove(0)
        } else {
            None
        }
    }

    fn clear(&mut self) {
        self.urgent_requests.clear();
        self.normal_requests.clear();
    }
}

