use std::collections::HashMap;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Priority {
    Normal,
    Urgent,
}

#[derive(Debug, Clone, Copy)]
struct FloorRequest {
    floor: u32,
    priority: Priority,
}

struct ElevatorQueue {
    queue: Vec<FloorRequest>,
    statuses: HashMap<u32, bool>,
    max_size: usize,
}

impl ElevatorQueue {
    fn new() -> Self {
        ElevatorQueue {
            queue: Vec::with_capacity(10),
            statuses: HashMap::new(),
            max_size: 15,
        }
    }

    fn push(&mut self, request: FloorRequest) {
        if self.queue.len() < self.max_size {
            self.queue.push(request);
            self.statuses.insert(request.floor, false);
        }
    }

    fn pop(&mut self) -> Option<FloorRequest> {
        if let Some(urgent_index) = self.queue.iter().position(|r| r.priority == Priority::Urgent) {
            let request = self.queue.remove(urgent_index);
            self.statuses.insert(request.floor, true);
            Some(request)
        } else if let Some(request) = self.queue.first().cloned() {
            self.queue.remove(0);
            self.statuses.insert(request.floor, true);
            Some(request)
        } else {
            None
        }
    }

    fn clear(&mut self) {
        self.queue.clear();
        self.statuses.clear();
    }
}

fn main() {
    let mut elevator_queue = ElevatorQueue::new();

    elevator_queue.push(FloorRequest { floor: 5, priority: Priority::Normal });
    elevator_queue.push(FloorRequest { floor: 3, priority: Priority::Urgent });
    elevator_queue.push(FloorRequest { floor: 7, priority: Priority::Normal });

    while let Some(request) = elevator_queue.pop() {
        println!("Handling request to floor: {}. Status: {}", request.floor, if elevator_queue.statuses[&request.floor] { "Completed" } else { "Pending" });
    }
}
