import java.util.Comparator;

public class OnlineMeetingPlatform {
    private Vector<String> agendaItems = new Vector<>();
    private PriorityQueue<AgendaItem> priorityQueue = new PriorityQueue<>(new AgendaComparator());

    private class AgendaComparator implements Comparator<AgendaItem> {
        public int compare(AgendaItem a1, AgendaItem a2) {
            return Integer.compare(a2.priority, a1.priority); // High priority first
        }
    }

    private class AgendaItem {
        String item;
        int priority;

        AgendaItem(String item, int priority) {
            this.item = item;
            this.priority = priority;
        }
    }

    public synchronized void addAgendaItem(String item, int priority) {
        if (agendaItems.size() < 10) {
            agendaItems.add(item);
            priorityQueue.offer(new AgendaItem(item, priority));
            updateUsers();
