public class OnlineMeetingPlatform {
    private Vector<String> agendaItems;
    private PriorityQueue<AgendaItem> agendaQueue;

    public OnlineMeetingPlatform() {
        agendaItems = new Vector<>();
        agendaQueue = new PriorityQueue<>(Comparator.comparingInt(AgendaItem::getPriority).reversed());
    }

    public synchronized boolean addAgendaItem(String item, int priority) {
        if (agendaItems.size() >= 10) {
            return false;
        }
        agendaItems.add(item);
        agendaQueue.offer(new AgendaItem(item, priority));
        updatePlatform();
        return true;
    }

    public synchronized boolean removeAgendaItem(String item) {
        boolean removed = agendaItems.remove(item);
        if (removed) {
            agendaQueue.removeIf(agendaItem -> agendaItem.getItem().equals(item));
            updatePlatform();
        }
        return removed;
    }

    public synchronized boolean replaceAgendaItem(String oldItem, String newItem, int priority) {
        int index = agendaItems.indexOf(oldItem);
        if (index != -1 && agendaItems.size() < 10) {
            agendaItems.set(index, newItem);
            agendaQueue.removeIf(agendaItem -> agendaItem.getItem().equals(oldItem));
            agendaQueue.offer(new AgendaItem(newItem, priority));
            updatePlatform();
            return true;
        }
        return false;
    }

    public synchronized AgendaItem pollHighPriorityAgendaItem() {
        return agendaQueue.poll();
    }

    public synchronized AgendaItem peekHighPriorityAgendaItem() {
        return agendaQueue.peek();
    }

