from collections import Counter, defaultdict

def analyze_word_frequency(text, non_essential_words=None):
    if non_essential_words is None:
        non_essential_words = ["the", "and", "is"]

    if len(non_essential_words) > 5:
        non_essential_words = non_essential_words[:5]

    word_count = Counter()
    words = text.split()

    for word in words:
        word_count[word] += 1

    for word in non_essential_words:
        if word in word_count:
            word_count.subtract({word: word_count[word]})

    # Ensure the list is exactly 5 items long
    while len(non_essential_words) < 5:
        non_essential_words.append("")
    while len(non_essential_words) > 5:
        non_essential_words.remove(non_essential_words[-1])

    return word_count

