public:
    void push_back(int task) {
        if (tasks.size() >= MAX_SIZE) {
            throw std::overflow_error("Queue is full, cannot add more tasks.");
        }
        tasks.push_back(task);
    }

    int pop_front() {
        if (tasks.empty()) {
            throw std::underflow_error("Queue is empty, cannot remove tasks.");
        }
        int task = tasks.front();
        tasks.pop_front();
        return task;
    }

    bool isEmpty() {
        return tasks.empty();
    }

    bool isFull() {
        return tasks.size() >= MAX_SIZE;
    }
};

int main() {
