    try {
        queue.push_back(1);
        queue.push_back(2);

        std::cout << "Removed task: " << queue.pop_front() << std::endl;

        for (int i = 0; i < 9; ++i) {
            queue.push_back(i + 3);
        }

        std::cout << "Try adding one more task to a full queue:" << std::endl;
        queue.push_back(100); // This will throw an exception

    } catch (const std::exception &e) {
        std::cerr << "Exception: " << e.what() << std::endl;
