def event_registration():
    registrations = {}
    maximum_capacity = 100
    total_operations = 0

    def register_attendee(name):
        nonlocal total_operations
        if len(registrations) < maximum_capacity:
            registrations[name] = 'registered'
        else:
            print("Maximum capacity reached, transferring registrations to list.")
            all_attendees = list(registrations.keys())
            registrations.clear()  # Clear all registrations after transferring
            total_operations += 1  # 'clear' operation counted
            return all_attendees
        total_operations += 1  # registration operation counted

    def is_registered(name):
        nonlocal total_operations
        total_operations += 1  # 'get' operation counted
        return registrations.get(name, None) is not None

    def remove_attendee(name):
        nonlocal total_operations
        if name in registrations:
            registrations.pop(name)
            total_operations += 1  # 'pop' operation counted

    def fetch_attendees():
        nonlocal total_operations
        total_operations += 1  # 'keys' operation counted
        return list(registrations.keys())

    def get_total_operations():
        return total_operations

    return {
        'register_attendee': register_attendee,
        'is_registered': is_registered,
        'remove_attendee': remove_attendee,
        'fetch_attendees': fetch_attendees,
        'get_total_operations': get_total_operations
    }
