from collections import deque

class CustomerQueue:
    def __init__(self):
        self.queue = deque(maxlen=10)

    def add_customer(self, customer_id, priority=False):
        if len(self.queue) >= 10:
            print("Queue is at maximum capacity. Cannot add more customers.")
            return
        if priority:
            self.queue.appendleft(customer_id)
        else:
            self.queue.append(customer_id)
        self.sort_queue()

    def process_customer(self):
        if len(self.queue) == 0:
            print("Queue is empty. No customers to process.")
            return None
        return self.queue.popleft()

    def remove_customer(self, customer_id):
        try:
            self.queue.remove(customer_id)
        except ValueError:
            print(f"Customer ID {customer_id} is not in the queue.")

    def current_queue_size(self):
        return len(self.queue)

    def sort_queue(self):
        sorted_queue = sorted(self.queue)  # Sort based on customer priority
        self.queue = deque(sorted_queue, maxlen=10)

# Example usage:
queue = CustomerQueue()
queue.add_customer('C1')
queue.add_customer('C2', priority=True)
queue.add_customer('C3')
print(queue.process_customer())
print(queue.current_queue_size())
queue.remove_customer('C2')
