    private final int MAX_TRACKS = 50;

    public PlaylistManager() {
        playlist = new LinkedList<>();
    }

    public synchronized void addTrack(String track) {
        if (playlist.size() >= MAX_TRACKS) {
            playlist.removeLast(); // Remove the oldest track
        }
        playlist.addFirst(track);
    }

    public synchronized String removeCurrentTrack() {
        return playlist.isEmpty() ? null : playlist.removeFirst();
    }

    public synchronized String peekCurrentTrack() {
        return playlist.isEmpty() ? null : playlist.peek();
    }

    public synchronized int getPlaylistSize() {
        return playlist.size();
    }
}
