import java.util.PriorityQueue;

public class PlaylistManager {
    private final LinkedList<String> playlist = new LinkedList<>();
    private final PriorityQueue<String> removedTracks = new PriorityQueue<>();
    private static final int MAX_TRACKS = 50;

    public synchronized void addTrack(String track) {
        if (playlist.size() == MAX_TRACKS) {
            String removedTrack = playlist.removeLast();
            removedTracks.offer(removedTrack);
        }
        playlist.addFirst(track);
    }

    public synchronized String removeTrack() {
        if (playlist.isEmpty()) {
            return null;
        }
        String removedTrack = playlist.removeFirst();
        removedTracks.offer(removedTrack);
        return removedTrack;
    }

    public synchronized String peekTrack() {
        return playlist.peekFirst();
    }

    public synchronized int getPlaylistSize() {
        return playlist.size();
    }
}
