public class PlaylistManager {
    private final LinkedList<String> playlist = new LinkedList<>();
    private final PriorityQueue<String> removedTracks = new PriorityQueue<>();
    private final int maxTracks = 50;

    public synchronized void addFirst(String track) {
        if (playlist.size() >= maxTracks) {
            removeFirst();
        }
        playlist.addFirst(track);
    }

    public synchronized String removeFirst() {
        if (!playlist.isEmpty()) {
            String removedTrack = playlist.removeFirst();
            removedTracks.offer(removedTrack);
            return removedTrack;
        }
        return null;
    }

    public synchronized String peek() {
        return playlist.peek();
    }

    public synchronized int size() {
        return playlist.size();
    }

    public synchronized String peekRemoved() {
        return removedTracks.peek();
    }
}
