    log: Arc<Mutex<HashMap<usize, String>>>,
}

impl SupportPlatform {
    fn new() -> Self {
        SupportPlatform {
            queries: Arc::new(Mutex::new(VecDeque::with_capacity(10))),
            log: Arc::new(Mutex::new(HashMap::new())),
        }
    }

