        if queries.len() == 10 {
            queries.pop_front();
        }
        queries.push_back(query);
    }

    fn process_next_query(&self) -> Option<String> {
        let mut queries = self.queries.lock().unwrap();
        if let Some(query) = queries.pop_front() {
            let mut log = self.log.lock().unwrap();
            let log_id = log.len() + 1;
            log.insert(log_id, query.clone());
            return Some(query);
        }
        None
    }

    fn peek_next_query(&self) -> Option<String> {
        let queries = self.queries.lock().unwrap();
        queries.front().cloned()
    }
}

