#include <iostream>
#include <queue>
#include <stack>
#include <mutex>
#include <thread>

class ConferenceManager {
private:
    std::priority_queue<std::pair<int, std::string>> speakerQueue; // pair<rating, name>
    std::stack<std::pair<int, std::string>> canceledSpeakers;
    std::mutex queueMutex;
    static const int MAX_SPEAKERS = 20;

public:
    void addSpeaker(int rating, const std::string& name) {
        std::lock_guard<std::mutex> lock(queueMutex);
        if (speakerQueue.size() >= MAX_SPEAKERS) {
            speakerQueue.pop(); // Remove the lowest-rated speaker
        }
        speakerQueue.push(std::make_pair(rating, name));
    }

    std::pair<int, std::string> nextSpeaker() {
        std::lock_guard<std::mutex> lock(queueMutex);
        if (speakerQueue.empty()) {
            throw std::runtime_error("No speakers available");
        } else {
            auto topSpeaker = speakerQueue.top();
            speakerQueue.pop();
            return topSpeaker;
        }
    }

    std::pair<int, std::string> currentTopSpeaker() {
        std::lock_guard<std::mutex> lock(queueMutex);
        if (speakerQueue.empty()) {
            throw std::runtime_error("No speakers available");
        } else {
            return speakerQueue.top();
        }
    }

    void cancelSpeaker(int rating, const std::string& name) {
        std::lock_guard<std::mutex> lock(queueMutex);
        canceledSpeakers.push(std::make_pair(rating, name));
    }
};

int main() {
    ConferenceManager manager;
    try {
        manager.addSpeaker(90, "Alice");
        manager.addSpeaker(85, "Bob");

        auto topSpeaker = manager.currentTopSpeaker();
        std::cout << "Current top speaker: " << topSpeaker.second << " with rating: " << topSpeaker.first << std::endl;

        manager.cancelSpeaker(85, "Bob");

        auto nextSpeaker = manager.nextSpeaker();
        std::cout << "Next speaker: " << nextSpeaker.second << " with rating: " << nextSpeaker.first << std::endl;
    } catch (const std::runtime_error& e) {
        std::cerr << e.what() << std::endl;
    }

    return 0;
}
