package main

import (
	"fmt"
)

// Queue represents a FIFO queue with constraints
type Queue struct {
	maxCapacity int
	data        []string
}

// NewQueue initializes a new queue with a maximum capacity of 10
func NewQueue() *Queue {
	return &Queue{
		maxCapacity: 10,
		data:        make([]string, 0),
	}
}

// PushBack adds a user ID to the back of the queue
func (q *Queue) PushBack(userID string) bool {
	if len(q.data) >= q.maxCapacity || len(q.data) >= q.maxCapacity*70/100 {
		return false // Queue is at or above capacity limit
	}
	q.data = append(q.data, userID)
	return true
}

// PushFront adds a priority request to the front of the queue without bypassing 20% limit
func (q *Queue) PushFront(userID string) bool {
	priorityLimit := len(q.data) * 20 / 100
	if len(q.data) >= q.maxCapacity || len(q.data) >= q.maxCapacity*70/100 || priorityLimit == 0 {
		return false // Queue is at or above capacity or priority limit
	}
	q.data = append([]string{userID}, q.data...)
	return true
}

// GetQueue returns the current state of the queue
func (q *Queue) GetQueue() []string {
	return q.data
}

func main() {
	queue := NewQueue()
	fmt.Println(queue.PushBack("User1"))  // true
	fmt.Println(queue.PushBack("User2"))  // true
	fmt.Println(queue.PushFront("User3")) // false due to 20% limit
	fmt.Println(queue.PushBack("User4"))  // true
	fmt.Println(queue.GetQueue())         // ["User1", "User2", "User4"]
}
