package main

import (
	"errors"
	"fmt"
)

type Queue struct {
	Requests        []string
	MaxCapacity     int
	CurrentCapacity int
	MaxPriority     int
}

func NewQueue() *Queue {
	return &Queue{
		Requests:    make([]string, 0, 10),
		MaxCapacity: 10,
	}
}

func (q *Queue) PushBack(userID string) error {
	if q.CurrentCapacity >= q.MaxCapacity {
		return errors.New("queue is full")
	}
	if q.CurrentCapacity >= 7 {
		return errors.New("queue operating above 70% capacity")
	}
	q.Requests = append(q.Requests, userID)
	q.CurrentCapacity++
	q.MaxPriority = int(float64(q.CurrentCapacity) * 0.2)
	return nil
}

func (q *Queue) PushFront(userID string) error {
	if q.CurrentCapacity >= q.MaxCapacity {
		return errors.New("queue is full")
	}
	if q.CurrentCapacity >= 7 {
		return errors.New("queue operating above 70% capacity")
	}
	if len(q.Requests) >= q.MaxPriority {
		return errors.New("priority requests exceed 20% of the queue size")
	}
	q.Requests = append([]string{userID}, q.Requests...)
	q.CurrentCapacity++
	q.MaxPriority = int(float64(q.CurrentCapacity) * 0.2)
	return nil
}

func (q *Queue) Remove(userID string) error {
	for i, v := range q.Requests {
		if v == userID {
			q.Requests = append(q.Requests[:i], q.Requests[i+1:]...)
			q.CurrentCapacity--
			q.MaxPriority = int(float64(q.CurrentCapacity) * 0.2)
			return nil
		}
	}
	return errors.New("user ID not found in queue")
}

func main() {
	queue := NewQueue()

	err := queue.PushBack("user1")
	if err != nil {
		fmt.Println("Error:", err)
	}

	err = queue.PushFront("priority_user")
	if err != nil {
		fmt.Println("Error:", err)
	}

	fmt.Println("Queue:", queue.Requests)

	err = queue.Remove("user1")
	if err != nil {
		fmt.Println("Error:", err)
	}

	fmt.Println("Queue after removal:", queue.Requests)
}
