import "fmt"

type Queue struct {
	queue        []int
	maxCapacity  int
	stack        []int
	prioritySize int
}

func NewQueue(maxCapacity int) *Queue {
	return &Queue{
		queue:        []int{},
		maxCapacity:  maxCapacity,
		stack:        []int{},
		prioritySize: 0,
	}
}

func (q *Queue) pushBack(userID int) {
	if len(q.queue) < int(0.7*float64(q.maxCapacity)) {
		q.queue = append(q.queue, userID)
	} else {
		q.stack = append(q.stack, userID) // Store in stack if max 70% capacity
	}
}

func (q *Queue) pushFront(userID int) {
	allowedPriority := len(q.queue) / 5 // 20% of queue size
	if q.prioritySize < allowedPriority && len(q.queue) < int(0.7*float64(q.maxCapacity)) {
		q.queue = append([]int{userID}, q.queue...)
		q.prioritySize++
	} else {
		q.stack = append(q.stack, userID) // Store in stack if priority requests maxed
	}
}

func (q *Queue) pop() int {
	if len(q.queue) == 0 {
		fmt.Println("Queue is empty.")
		return -1
	}
	userID := q.queue[0]
	q.queue = q.queue[1:]
	if q.prioritySize > 0 {
		q.prioritySize--
	}
	return userID
}

func main() {
	queue := NewQueue(10)

	// Example usage
	queue.pushBack(1)
	queue.pushBack(2)
	queue.pushFront(3)
	fmt.Println("Queue:", queue.queue)
	fmt.Println("Popped:", queue.pop())
	fmt.Println("Queue:", queue.queue)
