struct InventorySystem {
    inventory: BTreeSet<u32>,
    access_log: VecDeque<u32>,
}

impl InventorySystem {
    fn new() -> Self {
        InventorySystem {
            inventory: BTreeSet::new(),
            access_log: VecDeque::with_capacity(100),
        }
    }

    fn add_product_id(&mut self, product_id: u32) -> Result<(), &'static str> {
        if self.inventory.len() >= 50 {
            return Err("Error: Inventory full, cannot add more product IDs.");
        }
        if !self.inventory.insert(product_id) {
            return Err("Error: Duplicate product ID, cannot be added.");
        }
        self.record_access(product_id);
        Ok(())
    }

    fn remove_product_id(&mut self, product_id: u32) -> Result<(), &'static str> {
        if !self.inventory.remove(&product_id) {
            return Err("Error: Product ID not found, cannot be removed.");
        }
        self.record_access(product_id);
        Ok(())
    }

    fn record_access(&mut self, product_id: u32) {
        if self.access_log.len() == 100 {
            self.access_log.pop_front();
        }
        self.access_log.push_back(product_id);
    }

    fn query_product_id(&mut self, product_id: u32) -> bool {
        self.record_access(product_id);
        self.inventory.contains(&product_id)
    }
