            log: VecDeque::with_capacity(100),
        }
    }

    fn add_product_id(&mut self, product_id: u32) -> Result<(), InventoryError> {
        if self.inventory.len() >= 50 {
            return Err(InventoryError::MaxCapacityError);
        }

        if self.inventory.contains(&product_id) {
            return Err(InventoryError::DuplicateIdError);
        }

        self.inventory.insert(product_id);

        self.update_log(product_id);

        Ok(())
    }

    fn remove_product_id(&mut self, product_id: u32) -> Result<(), InventoryError> {
        if self.inventory.remove(&product_id) {
            Ok(())
        } else {
            Err(InventoryError::IdNotFoundError)
        }
    }

    fn update_log(&mut self, product_id: u32) {
        if self.log.len() >= 100 {
            self.log.pop_front();
        }
        self.log.push_back(product_id);
    }
}
