package main

import (
	"container/list"
	"fmt"
)

func ManageTasks() *list.List {
	tasks := list.New()

	// Insert a task at a specific position based on priority
	insertTask := func(task string, position int) {
		if position <= 0 || tasks.Len() == 0 {
			tasks.PushFront(task)
			return
		}
		if position >= tasks.Len() {
			tasks.PushBack(task)
			return
		}

		count := 0
		for e := tasks.Front(); e != nil; e = e.Next() {
			if count+1 == position {
				tasks.InsertBefore(task, e.Next())
				break
			}
			count++
		}
	}

	// Remove a task by index
	removeTask := func(index int) {
		if index < 0 || index >= tasks.Len() {
			return
		}

		count := 0
		for e := tasks.Front(); e != nil; e = e.Next() {
			if count == index {
				tasks.Remove(e)
				break
			}
			count++
		}
	}

	// Example usage
	insertTask("Task 1", 0)
	insertTask("Task 2", 1)
	insertTask("Task 3", 1)
	removeTask(1)

	for e := tasks.Front(); e != nil; e = e.Next() {
		fmt.Println(e.Value)
	}

	return tasks
}

func main() {
	ManageTasks()
}
