type Task struct {
	Name     string
	Priority int
}

type TaskManager struct {
	tasks []Task
}

func NewTaskManager() *TaskManager {
	return &TaskManager{tasks: []Task{}}
}

func (tm *TaskManager) InsertBefore(index int, task Task) error {
	if len(tm.tasks) >= 10 {
		return errors.New("task list cannot exceed 10 tasks")
	}
	if index < 0 || index > len(tm.tasks) {
		return errors.New("index out of bounds")
	}
	tm.tasks = append(tm.tasks[:index], append([]Task{task}, tm.tasks[index:]...)...)
	return nil
}

func (tm *TaskManager) Remove(index int) error {
	if index < 0 || index >= len(tm.tasks) {
		return errors.New("index out of bounds")
	}
	tm.tasks = append(tm.tasks[:index], tm.tasks[index+1:]...)
	return nil
}

func (tm *TaskManager) PrintTasks() {
	for i, task := range tm.tasks {
		fmt.Printf("Task %d: %s with priority %d\n", i, task.Name, task.Priority)
	}
}

func main() {
	taskManager := NewTaskManager()

	taskManager.InsertBefore(0, Task{Name: "Task 1", Priority: 1})
	taskManager.InsertBefore(1, Task{Name: "Task 2", Priority: 3})
	taskManager.Remove(1)

	taskManager.PrintTasks()
}
