import (
	"container/heap"
	"fmt"
)

type Task struct {
	priority int
	name     string
	index    int
}

type PriorityQueue []*Task

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].priority < pq[j].priority
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	task := x.(*Task)
	task.index = n
	*pq = append(*pq, task)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	task := old[n-1]
	old[n-1] = nil
	*pq = old[0 : n-1]
	return task
}

type Stack struct {
	tasks       []*Task
	priorityQ   PriorityQueue
}

func NewStack() *Stack {
	return &Stack{priorityQ: make(PriorityQueue, 0)}
}

func (s *Stack) push(task *Task) {
	if len(s.tasks) >= 10 {
		heap.Init(&s.priorityQ)
		heap.Push(&s.priorityQ, task)
		oldest := heap.Pop(&s.priorityQ).(*Task)
		s.removeTask(oldest)
	}
	s.tasks = append(s.tasks, task)
}

func (s *Stack) pop() *Task {
	if len(s.tasks) == 0 {
		return nil
	}
	task := s.tasks[len(s.tasks)-1]
	s.tasks = s.tasks[:len(s.tasks)-1]
	return task
}

func (s *Stack) peek() *Task {
	if len(s.tasks) == 0 {
		return nil
	}
	return s.tasks[len(s.tasks)-1]
}

func (s *Stack) removeTask(task *Task) {
	for i, t := range s.tasks {
		if t == task {
			s.tasks = append(s.tasks[:i], s.tasks[i+1:]...)
			break
		}
	}
}

func main() {
	stack := NewStack()
	stack.push(&Task{priority: 1, name: "Task 1"})
	stack.push(&Task{priority: 2, name: "Task 2"})
	stack.push(&Task{priority: 3, name: "Task 3"})

	fmt.Println("Peek:", stack.peek().name)
	stack.pop()
	fmt.Println("Peek after pop:", stack.peek().name)
}
