package main

import (
	"container/heap"
	"fmt"
)

type Task struct {
	Name     string
	Urgency  int
	Index    int
}

type PriorityQueue []*Task

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].Urgency > pq[j].Urgency
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].Index = i
	pq[j].Index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	task := x.(*Task)
	task.Index = n
	*pq = append(*pq, task)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	task := old[n-1]
	old[n-1] = nil
	task.Index = -1
	*pq = old[0 : n-1]
	return task
}

type TaskManager struct {
	maxCapacity int
	stack       PriorityQueue
}

func NewTaskManager(capacity int) *TaskManager {
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	return &TaskManager{maxCapacity: capacity, stack: pq}
}

func (tm *TaskManager) PushTask(name string, urgency int) {
	task := &Task{Name: name, Urgency: urgency}
	heap.Push(&tm.stack, task)
	if tm.stack.Len() > tm.maxCapacity {
		heap.Pop(&tm.stack)
	}
}

func (tm *TaskManager) PopTask() *Task {
	if tm.stack.Len() == 0 {
		return nil
	}
	return heap.Pop(&tm.stack).(*Task)
}

func (tm *TaskManager) PeekTask() *Task {
	if tm.stack.Len() == 0 {
		return nil
	}
	return tm.stack[0]
}

func main() {
	tm := NewTaskManager(10)

	tm.PushTask("Task1", 1)
	tm.PushTask("Task2", 5)
	tm.PushTask("Task3", 3)

	fmt.Println("Current Top Task:", tm.PeekTask().Name)

