#include <iostream>
#include <vector>
#include <queue>

class TrainSchedule {
private:
    std::vector<int> schedules;
    std::queue<int> buffer;
    const size_t max_size = 50;

public:
    void addSchedule(int time) {
        if (schedules.size() < max_size) {
            schedules.push_back(time);
        } else {
            buffer.push(time);
        }
        maintainCapacity();
    }

    void cancelLastSchedule() {
        if (!schedules.empty()) {
            schedules.pop_back();
        }
        if (!buffer.empty()) {
            schedules.push_back(buffer.front());
            buffer.pop();
        }
    }

    size_t currentCapacity() const {
        return schedules.size();
    }

private:
    void maintainCapacity() {
        while (schedules.size() > max_size) {
            schedules.erase(schedules.begin());
        }
        while (schedules.size() < max_size && !buffer.empty()) {
            schedules.push_back(buffer.front());
            buffer.pop();
        }
    }
};

int main() {
    TrainSchedule trainSchedule;

    // Example usage
    for (int i = 1; i <= 55; ++i) {
        trainSchedule.addSchedule(i);
    }

    std::cout << "Current capacity: " << trainSchedule.currentCapacity() << std::endl;

    trainSchedule.cancelLastSchedule();

    std::cout << "Current capacity after cancellation: " << trainSchedule.currentCapacity() << std::endl;

    return 0;
}
