```cpp
#include <iostream>
#include <vector>
#include <queue>

class TrainScheduleSystem {
private:
    std::vector<int> trainSchedules;
    std::queue<int> scheduleBuffer;
    const size_t maxSize = 50;

public:
    void addSchedule(int departureTime) {
        if (trainSchedules.size() < maxSize) {
            trainSchedules.push_back(departureTime);
        } else {
            if (!scheduleBuffer.empty()) {
                scheduleBuffer.push(departureTime);
            } else {
                removeOldestSchedule();
                trainSchedules.push_back(departureTime);
            }
        }
    }

    void removeLastSchedule() {
        if (!trainSchedules.empty()) {
            trainSchedules.pop_back();
            if (!scheduleBuffer.empty()) {
                int nextSchedule = scheduleBuffer.front();
                scheduleBuffer.pop();
                trainSchedules.push_back(nextSchedule);
            }
        }
    }

    void removeOldestSchedule() {
        if (!trainSchedules.empty()) {
            trainSchedules.erase(trainSchedules.begin());
        }
    }

    size_t currentSize() const {
        return trainSchedules.size();
    }

    void displaySchedules() const {
        for (int time : trainSchedules) {
            std::cout << time << " ";
        }
        std::cout << std::endl;
    }
};

int main() {
    TrainScheduleSystem system;
    system.addSchedule(1000);
    system.addSchedule(1200);
    system.removeLastSchedule();
    system.displaySchedules();
    return 0;
}
