	remove := func(slice []int, index int) []int {
		return append(slice[:index], slice[index+1:]...)
	}

	for _, score := range newScores {
		if len(scores) >= 100 {
			scores = pop(scores) // Remove oldest entry to add new one if at capacity
		}
		scores = append(scores, score) // Add new score
