	// Calculating highest, lowest and average score
	if len(scores) == 0 {
		return 0, 0, 0
	}
	highest, lowest, sum := scores[0], scores[0], 0
	for _, score := range scores {
		if score > highest {
			highest = score
		}
		if score < lowest {
			lowest = score
		}
