    public static int maxSumNonConsecutive(int[] nums) {
        HashMap<Integer, Integer> map = new HashMap<>();
        Stack<Integer> stack = new Stack<>();
        return maxSumHelper(nums, 0, map, stack);
    }

    private static int maxSumHelper(int[] nums, int index, HashMap<Integer, Integer> map, Stack<Integer> stack) {
        if (index >= nums.length) {
            return 0;
        }
        if (map.size() >= 10) {
            map.clear(); // reset map if it exceeds 10 entries
        }
        if (map.containsKey(index)) {
            return map.get(index);
        }

        int include = nums[index] + maxSumHelper(nums, index + 2, map, stack);
        stack.push(index);
        int exclude = maxSumHelper(nums, index + 1, map, stack);

        int result = Math.max(include, exclude);
        map.put(index, result);

        return result;
    }

    public static void main(String[] args) {
        int[] array = {3, 2, 7, 10};
        System.out.println(maxSumNonConsecutive(array)); // Output the largest sum
    }
