    public int computeLargestSum(int[] nums) {
        HashMap<Integer, Integer> sumCache = new HashMap<>();
        Stack<Integer> indexStack = new Stack<>();

        return computeSum(nums, 0, sumCache, indexStack);
    }

    private int computeSum(int[] nums, int currentIndex, HashMap<Integer, Integer> sumCache, Stack<Integer> indexStack) {
        if (currentIndex >= nums.length) {
            return 0;
        }

        if (sumCache.containsKey(currentIndex)) {
            return sumCache.get(currentIndex);
        }

        int includeCurrent = 0;
        if (indexStack.size() < 5) {
            indexStack.push(currentIndex);
            includeCurrent = nums[currentIndex] + computeSum(nums, currentIndex + 2, sumCache, indexStack);
            indexStack.pop();
        }

        int excludeCurrent = computeSum(nums, currentIndex + 1, sumCache, indexStack);

        int result = Math.max(includeCurrent, excludeCurrent);
        if (sumCache.size() < 10) {
            sumCache.put(currentIndex, result);
        }

        return result;
    }
