import java.util.HashMap;
import java.util.Stack;

public class MaxSumNonConsecutive {

    public static int maxSum(int[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }

        HashMap<Integer, Integer> sumMap = new HashMap<>();
        Stack<Integer> indexStack = new Stack<>();
        int n = nums.length;

        sumMap.put(0, nums[0]);
        indexStack.push(0);

        for (int i = 1; i < n; i++) {
            int maxSumExcludingCurrent = (i > 1) ? sumMap.getOrDefault(i - 2, 0) : 0;
            int currentSum = nums[i] + maxSumExcludingCurrent;
            int previousMaxSum = sumMap.getOrDefault(i - 1, 0);

            int finalSum = Math.max(previousMaxSum, currentSum);
            sumMap.put(i, finalSum);

            // Ensure the hash map does not exceed 10 entries
            if (sumMap.size() > 10) {
                sumMap.remove(i - 10);
            }

            // Use stack to track indices of used elements
            if (finalSum == currentSum) {
                if (indexStack.size() < 5) {
                    indexStack.push(i);
                }
            }
        }

        return sumMap.get(n - 1);
    }

    public static void main(String[] args) {
        int[] nums = {3, 2, 7, 10};
        System.out.println(maxSum(nums)); // Output should be 13 (3 + 10)
    }
}
