        if (followersMap.size() >= 50) {
            System.out.println("Max capacity reached. Cannot add more entries.");
            return;
        }

        if (!followersMap.containsKey(followee)) {
            followersMap.put(followee, new HashSet<>());
        }

        followersMap.get(followee).add(follower);
        followEvents.add(new String[]{follower, followee});
