        Set<String> followers1 = followersMap.get(user1);
        Set<String> followers2 = followersMap.get(user2);

        if (followers1 == null || followers2 == null) {
            return null;
        }

        Set<String> commonFollowers = new HashSet<>(followers1);
        commonFollowers.retainAll(followers2);

        for (int i = followEvents.size() - 1; i >= 0; i--) {
            String[] event = followEvents.get(i);
            if (commonFollowers.contains(event[0]) &&
                (event[1].equals(user1) || event[1].equals(user2))) {
                return event[0];
            }
        }

        return null;
