            for (int i = followEvents.size() - 1; i >= 0; i--) {
                String[] eventParts = followEvents.get(i).split("->");
                String follower = eventParts[0];
                if (followersUser1.contains(follower) && followersUser2.contains(follower)) {
                    return follower;
                }
            }
        }
        return null;
    }

