import java.util.ArrayList;

public class MaxSubarraySumWithStack {

    public int maxSubarraySum(int[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }

        ArrayList<Integer> stack = new ArrayList<>(10);
        for (int i = 0; i < 10; i++) {
            stack.add(null);
        }

        int maxSum = Integer.MIN_VALUE;
        int currentSum = 0;

        for (int num : nums) {
            currentSum += num;

            // Push operation (add to the stack)
            for (int i = 0; i < 10; i++) {
                if (stack.get(i) == null) {
                    stack.set(i, num);
                    break;
                }
            }

            maxSum = Math.max(maxSum, currentSum);

            // If stack size reached 10 and we need to pop
            if (currentSum < 0 || num < 0) {
                // Pop operation (remove from the stack)
                for (int i = 0; i < 10; i++) {
                    if (stack.get(i) != null) {
                        currentSum -= stack.get(i);
                        stack.set(i, null);
                        break;
                    }
                }
            }
        }

        return maxSum;
    }

    public static void main(String[] args) {
        MaxSubarraySumWithStack mss = new MaxSubarraySumWithStack();
        int[] inputArray = {-2, 1, -3, 4, -1, 2, 1, -5, 4};
        System.out.println("Maximum contiguous subarray sum: " + mss.maxSubarraySum(inputArray));
    }
}
