import time

class ReservationSystem:
    def __init__(self):
        self.reservations = {f"Guest{i}": f"Reservation{i}" for i in range(1, 11)}
        self.reservation_names = set(self.reservations.keys())
        self.lock = Lock()
        self.log_queue = Queue(maxsize=10)

    def check_reservation(self, name):
        with self.lock:
            if name in self.reservations:
                return self.reservations.get(name)
            return None

    def remove_reservation(self, name):
        with self.lock:
            if name in self.reservations:
                reservation = self.reservations.pop(name)
                self.reservation_names.discard(name)
                self.add_new_reservation()
                self.log_checkin(name)
                return reservation
            return None

    def add_new_reservation(self):
        new_name = f"Guest{len(self.reservations) + 1}"
        if len(self.reservations) < 10:
            self.reservations[new_name] = f"Reservation{len(self.reservations) + 1}"
            self.reservation_names.add(new_name)

    def log_checkin(self, name):
        timestamp = time.time()
        if self.log_queue.full():
            self.log_queue.get()
        self.log_queue.put((name, timestamp))

    def enqueue(self, item):
        if not self.log_queue.full():
            self.log_queue.put(item)

    def dequeue(self):
        if not self.log_queue.empty():
            return self.log_queue.get()

# Example usage
