import java.util.ArrayList;
import java.util.PriorityQueue;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class EventScheduler {

    private final PriorityQueue<Event> eventQueue;
    private final ArrayList<Event> eventRecords;
    private final Lock lock;
    private final int maxQueueSize = 10;
    private final int maxRecordSize = 100;

    public EventScheduler() {
        eventQueue = new PriorityQueue<>();
        eventRecords = new ArrayList<>();
        lock = new ReentrantLock();
    }

    public void addEvent(Event event) {
        lock.lock();
        try {
            if (eventQueue.size() >= maxQueueSize) {
                eventQueue.poll();
            }
            eventQueue.offer(event);
        } finally {
            lock.unlock();
        }
    }

    public Event getMostRecentEvent() {
        lock.lock();
        try {
            if (eventQueue.isEmpty()) {
                throw new IllegalStateException("No events available.");
            }
            return eventQueue.peek();
        } finally {
            lock.unlock();
        }
    }

    public Event processMostRecentEvent() {
        lock.lock();
        try {
            if (eventQueue.isEmpty()) {
                throw new IllegalStateException("No events available.");
            }
            Event event = eventQueue.poll();
            if (eventRecords.size() >= maxRecordSize) {
                eventRecords.remove(0);
            }
            eventRecords.add(event);
            return event;
        } finally {
            lock.unlock();
        }
    }

    public int getQueueSize() {
        lock.lock();
        try {
            return eventQueue.size();
        } finally {
            lock.unlock();
        }
    }

    public static class Event implements Comparable<Event> {
        private final String name;
        private final long timestamp;

        public Event(String name, long timestamp) {
            this.name = name;
            this.timestamp = timestamp;
        }

        @Override
        public int compareTo(Event other) {
            return Long.compare(this.timestamp, other.timestamp);
        }

        @Override
        public String toString() {
            return "Event{" +
                    "name='" + name + '\'' +
                    ", timestamp=" + timestamp +
                    '}';
        }
    }
}
