import java.util.HashSet;
import java.util.LinkedList;
import java.util.logging.Level;
import java.util.logging.Logger;

public class SessionManager {
    private static final int MAX_SESSIONS = 500;
    private HashSet<String> sessions = new HashSet<>();
    private LinkedList<String> sessionOrder = new LinkedList<>();
    private static final Logger logger = Logger.getLogger(SessionManager.class.getName());

    public void addSession(String sessionId) {
        synchronized (this) {
            if (!sessions.contains(sessionId)) {
                if (sessions.size() >= MAX_SESSIONS) {
                    String oldestSession = sessionOrder.removeFirst();
                    sessions.remove(oldestSession);
                    logger.log(Level.INFO, "Removed oldest session {0} due to capacity limit at {1}", new Object[]{oldestSession, System.currentTimeMillis()});
                }
                sessions.add(sessionId);
                sessionOrder.addLast(sessionId);
                logger.log(Level.INFO, "Added session {0} at {1}", new Object[]{sessionId, System.currentTimeMillis()});
            } else {
                logger.log(Level.INFO, "Session {0} already exists, skipped adding at {1}", new Object[]{sessionId, System.currentTimeMillis()});
            }
        }
    }

    public void removeSession(String sessionId) {
        synchronized (this) {
            if (sessions.remove(sessionId)) {
                sessionOrder.remove(sessionId);
                logger.log(Level.INFO, "Removed session {0} at {1}", new Object[]{sessionId, System.currentTimeMillis()});
            } else {
                logger.log(Level.INFO, "Session {0} not found during removal at {1}", new Object[]{sessionId, System.currentTimeMillis()});
            }
        }
    }
}
