import java.util.HashSet;
import java.util.LinkedList;
import java.util.PriorityQueue;
import java.util.logging.Logger;
import java.util.logging.Level;
import java.time.LocalDateTime;

public class SessionManager {
    private static final int MAX_SESSIONS = 500;
    private HashSet<String> sessions = new HashSet<>();
    private LinkedList<String> sessionOrder = new LinkedList<>();
    private PriorityQueue<SessionEntry> sessionQueue = new PriorityQueue<>();
    private static final Logger logger = Logger.getLogger(SessionManager.class.getName());

    class SessionEntry implements Comparable<SessionEntry> {
        String sessionId;
        LocalDateTime timestamp;

        SessionEntry(String sessionId, LocalDateTime timestamp) {
            this.sessionId = sessionId;
            this.timestamp = timestamp;
        }

        @Override
        public int compareTo(SessionEntry other) {
            return this.timestamp.compareTo(other.timestamp);
        }
    }

    public void login(String sessionId) {
        LocalDateTime currentTime = LocalDateTime.now();
        if (sessions.contains(sessionId)) {
            logger.log(Level.INFO, "Session already exists: {0} at {1}", new Object[]{sessionId, currentTime});
            return;
        }

        if (sessions.size() >= MAX_SESSIONS) {
            removeOldestSession();
        }

        sessions.add(sessionId);
        sessionOrder.add(sessionId);
        sessionQueue.add(new SessionEntry(sessionId, currentTime));
        logger.log(Level.INFO, "Added session: {0} at {1}", new Object[]{sessionId, currentTime});
    }

    public void logout(String sessionId) {
        LocalDateTime currentTime = LocalDateTime.now();
        if (sessions.contains(sessionId)) {
            sessions.remove(sessionId);
            sessionOrder.remove(sessionId);
            sessionQueue.removeIf(entry -> entry.sessionId.equals(sessionId));
            logger.log(Level.INFO, "Removed session: {0} at {1}", new Object[]{sessionId, currentTime});
        } else {
            logger.log(Level.WARNING, "Session not found: {0} at {1}", new Object[]{sessionId, currentTime});
        }
    }

    private void removeOldestSession() {
        SessionEntry oldestEntry = sessionQueue.poll();
        if (oldestEntry != null) {
            sessions.remove(oldestEntry.sessionId);
            sessionOrder.remove(oldestEntry.sessionId);
            logger.log(Level.INFO, "Removed oldest session: {0} at {1}", new Object[]{oldestEntry.sessionId, oldestEntry.timestamp});
        }
    }
}
