use std::collections::{HashSet, HashMap};
use std::time::{SystemTime, Duration};

struct UserManager {
    authorized_users: HashSet<String>,
    last_login_time: HashMap<String, SystemTime>,
}

impl UserManager {
    fn new() -> Self {
        UserManager {
            authorized_users: HashSet::new(),
            last_login_time: HashMap::new(),
        }
    }

    fn register_user(&mut self, user_id: &str) -> bool {
        if self.authorized_users.len() < 100 {
            self.authorized_users.insert(user_id.to_string());
            self.last_login_time.insert(user_id.to_string(), SystemTime::now());
            true
        } else {
            false
        }
    }

    fn is_authorized(&self, user_id: &str) -> bool {
        self.authorized_users.contains(user_id)
    }

    fn len(&self) -> usize {
        self.authorized_users.len()
    }

    fn remove_user(&mut self, user_id: &str) -> bool {
        self.authorized_users.remove(user_id)
    }

    fn clear_inactive_users(&mut self) {
        let thirty_days = Duration::new(30 * 24 * 60 * 60, 0);
        let now = SystemTime::now();
        for user_id in self.authorized_users.clone() {
            if let Some(login_time) = self.last_login_time.get(&user_id) {
                if let Ok(duration) = now.duration_since(*login_time) {
                    if duration > thirty_days {
                        self.authorized_users.remove(&user_id);
                        self.last_login_time.remove(&user_id);
                    }
                }
            }
        }
    }
}
