use std::collections::{HashSet, HashMap};
use std::time::{SystemTime, Duration};

struct AuthManager {
    authorized_users: HashSet<String>,
    last_login: HashMap<String, SystemTime>,
    max_capacity: usize,
}

impl AuthManager {
    fn new() -> Self {
        AuthManager {
            authorized_users: HashSet::new(),
            last_login: HashMap::new(),
            max_capacity: 100,
        }
    }

    fn register_user(&mut self, user_id: String) -> bool {
        if self.authorized_users.len() >= self.max_capacity {
            return false;
        }
        let success = self.authorized_users.insert(user_id.clone());
        if success {
            self.last_login.insert(user_id, SystemTime::now());
        }
        success
    }

    fn is_authorized(&self, user_id: &String) -> bool {
        self.authorized_users.contains(user_id)
    }

    fn current_capacity(&self) -> usize {
        self.authorized_users.len()
    }

    fn remove_user(&mut self, user_id: &String) -> bool {
        self.authorized_users.remove(user_id) &&
        self.last_login.remove(user_id).is_some()
    }

    fn clear_inactive(&mut self) {
        let threshold = SystemTime::now() - Duration::new(30 * 24 * 60 * 60, 0); // 30 days ago
        let inactive_users: Vec<String> = self.last_login.iter()
            .filter(|(_, &time)| time < threshold)
            .map(|(user_id, _)| user_id.clone())
            .collect();

        for user_id in inactive_users {
            self.remove_user(&user_id);
        }
    }

    fn clear_all(&mut self) {
        self.authorized_users.drain();
        self.last_login.clear();
    }

    fn generate_activity_report(&self) -> Vec<String> {
        self.authorized_users.iter().cloned().collect()
    }
}
