```go
package main

import (
	"container/list"
	"fmt"
)

// Cache structure with a map for storing page details and a LinkedList for tracking LRU order
type Cache struct {
	capacity int
	pages    map[string]string
	order    *list.List
}

// Constructor for initializing the Cache with a specified capacity
func NewCache(capacity int) *Cache {
	return &Cache{
		capacity: capacity,
		pages:    make(map[string]string),
		order:    list.New(),
	}
}

// AddPage method for adding a page to the cache
func (c *Cache) AddPage(key, value string) {
	// If the page is already present, move it to the front of the list
	if _, exists := c.pages[key]; exists {
		for e := c.order.Front(); e != nil; e = e.Next() {
			if e.Value.(string) == key {
				c.order.MoveToFront(e)
				break
			}
		}
		return
	}

	// If cache is at capacity, remove the least recently used page from the cache
	if c.order.Len() >= c.capacity {
		lru := c.order.Back()
		delete(c.pages, lru.Value.(string))
		c.order.Remove(lru)
	}

	// Add the new page to the cache and mark it as most recently used
	c.pages[key] = value
	c.order.PushFront(key)
}

// DeletePage method for deleting a specific page from the cache
func (c *Cache) DeletePage(key string) {
	if _, exists := c.pages[key]; exists {
		delete(c.pages, key)
		for e := c.order.Front(); e != nil; e = e.Next() {
			if e.Value.(string) == key {
				c.order.Remove(e)
				break
			}
		}
	}
}

// Main function to demonstrate Cache operations
func main() {
	cache := NewCache(10)

	// Add pages to the cache
	cache.AddPage("Page1", "Content of Page 1")
	cache.AddPage("Page2", "Content of Page 2")

	// Delete a page from the cache
	cache.DeletePage("Page1")

	// Add more pages to trigger LRU policy
	for i := 3; i <= 12; i++ {
		cache.AddPage(fmt.Sprintf("Page%d", i), fmt.Sprintf("Content of Page %d", i))
	}

	// Display the current cache pages
	for k := range cache.pages {
		fmt.Println(k, cache.pages[k])
	}
}
