package main

import (
	"container/list"
	"fmt"
)

type Cache struct {
	cacheMap       map[string]string
	orderList      *list.List
	maxCapacity    int
}

func NewCache(maxCapacity int) *Cache {
	return &Cache{
		cacheMap:    make(map[string]string),
		orderList:   list.New(),
		maxCapacity: maxCapacity,
	}
}

func (c *Cache) AddPage(pageKey string, pageDetail string) {
	if _, found := c.cacheMap[pageKey]; found {
		c.updateAccessOrder(pageKey)
		return
	}

	if len(c.cacheMap) >= c.maxCapacity {
		c.removeLeastRecentlyUsed()
	}

	c.cacheMap[pageKey] = pageDetail
	c.orderList.PushFront(pageKey)
}

func (c *Cache) updateAccessOrder(pageKey string) {
	for e := c.orderList.Front(); e != nil; e = e.Next() {
		if e.Value == pageKey {
			c.orderList.MoveToFront(e)
			break
		}
	}
}

func (c *Cache) removeLeastRecentlyUsed() {
	lruKey := c.orderList.Back().Value.(string)
	delete(c.cacheMap, lruKey)
	c.orderList.Remove(c.orderList.Back())
}

func (c *Cache) DeletePage(pageKey string) {
	if _, found := c.cacheMap[pageKey]; found {
		delete(c.cacheMap, pageKey)
		for e := c.orderList.Front(); e != nil; e = e.Next() {
			if e.Value == pageKey {
				c.orderList.Remove(e)
				break
			}
		}
	}
}

func main() {
	cache := NewCache(10)
	cache.AddPage("Page1", "Details of Page 1")
	cache.AddPage("Page2", "Details of Page 2")

	fmt.Println("Cache:", cache.cacheMap)
	fmt.Println("Order list:")
	for e := cache.orderList.Front(); e != nil; e = e.Next() {
		fmt.Println(e.Value)
	}

	cache.DeletePage("Page1")
	fmt.Println("Cache after deletion:", cache.cacheMap)
	fmt.Println("Order list after deletion:")
	for e := cache.orderList.Front(); e != nil; e = e.Next() {
		fmt.Println(e.Value)
	}

	cache.AddPage("Page3", "Details of Page 3")
	fmt.Println("Cache after adding a page:", cache.cacheMap)
	fmt.Println("Order list after adding a page:")
	for e := cache.orderList.Front(); e != nil; e = e.Next() {
		fmt.Println(e.Value)
	}
}
