    const int MAX_CAPACITY = 50;

public:
    std::string push(const std::string& guest) {
        if (guests.size() < MAX_CAPACITY) {
            guests.push(guest);
            return "Guest added: " + guest;
        } else {
            return "Stack is full, cannot add more guests.";
        }
    }

    std::string pop() {
        if (!guests.empty()) {
            std::string removedGuest = guests.top();
            guests.pop();
            return "Guest removed: " + removedGuest;
        } else {
            return "No guests to remove.";
        }
    }

    int size() const {
        return guests.size();
    }
};

