    def remove_product(self, category, product):
        if category.startswith(('A', 'B')):
            products = self.catalog.get(category, [])
            if product in products:
                products.remove(product)
                products.append(None)  # Maintain pre-allocated space
                self.catalog.setdefault(category, products)

