        let color_map = Arc::clone(&color_map);
        let colors = color_batch.to_vec();

        let handle = thread::spawn(move || {
            for color in colors {
                let lowercase_color = color.to_lowercase();
                let mut map = color_map.lock().unwrap();
                let count = map.get(&lowercase_color).cloned().unwrap_or(0);
                if map.len() < 100 || map.contains_key(&lowercase_color) {
                    map.insert(lowercase_color, count + 1);
                }
            }
        });

        handles.push(handle);
    }

    for handle in handles {
        handle.join().expect("The thread panicked");
    }

    let color_map = Arc::try_unwrap(color_map).unwrap().into_inner().unwrap();
    let mut result: Vec<(String, usize)> = color_map.into_iter().collect();
    if result.len() > 100 {
        result.truncate(100);
    }

    Some(result)
