    void calculateInterest() override {
        balance += balance * 0.03;  // 3% interest
        logAction("Interest added: 3%");
    }
};

class CheckingAccount : public Account {
public:
    CheckingAccount() { accountType = "Checking"; }
    void calculateInterest() override {
        balance += balance * 0.01;  // 1% interest
        logAction("Interest added: 1%");
    }
};

class JointAccount : public Account {
public:
    JointAccount() { accountType = "Joint"; }
    void calculateInterest() override {
        balance += balance * 0.02;  // 2% interest
        logAction("Interest added: 2%");
    }
};

