    try {
        for (int i = 0; i < 300; ++i) {
            if (i % 3 == 0) {
                accountStack.push(std::make_shared<SavingsAccount>());
            } else if (i % 3 == 1) {
                accountStack.push(std::make_shared<CheckingAccount>());
            } else {
