const maxMessages = 200

type Message struct {
	Text      string
	Timestamp time.Time
}

var (
	messageChan = make(chan Message, maxMessages)
	timestamps  = make(map[int]time.Time)
	mutex       sync.Mutex
)

func addMessage(text string) {
	mutex.Lock()
	defer mutex.Unlock()
	if len(messageChan) < cap(messageChan) {
		msg := Message{
			Text:      text,
			Timestamp: time.Now(),
		}
		messageChan <- msg
		timestamps[len(messageChan)] = msg.Timestamp
	} else {
		fmt.Println("Message channel is full. Unable to add new messages.")
	}
}

func processMessages() {
	for msg := range messageChan {
		fmt.Printf("Processing message: %s at %s\n", msg.Text, msg.Timestamp)
		clearMessage()
	}
}

func clearMessage() {
	mutex.Lock()
	defer mutex.Unlock()
	if len(messageChan) > 0 {
		<-messageChan
		delete(timestamps, len(messageChan))
	}
}

func main() {
	// Example of adding and processing messages
	go addMessage("Hello!")
	go addMessage("How are you?")

	go processMessages()

	time.Sleep(1 * time.Second)
}
