from collections import defaultdict
from collections import deque

class ExpressionEvaluator:
    def __init__(self, max_cache_size=1000):
        self.cache = defaultdict(str)
        self.cache_order = deque()
        self.max_cache_size = max_cache_size

    def _add_to_cache(self, expr, result):
        # Ensure cache does not exceed the max_cache_size
        if len(self.cache_order) >= self.max_cache_size:
            oldest_expr = self.cache_order.popleft()
            if oldest_expr in self.cache:
                del self.cache[oldest_expr]

        if expr not in self.cache:
            self.cache_order.append(expr)
        self.cache[expr] = result

    def evaluate(self, expr):
        # Check if the result is already cached
        if expr in self.cache:
            return self.cache[expr]

        # Evaluate the expression
        try:
            result = eval(expr)
        except Exception as e:
            raise ValueError(f"Error evaluating expression '{expr}': {e}")

        # Cache the result
        self._add_to_cache(expr, result)

        return result

# Example usage:
