from collections import defaultdict, deque

class LimitedSizeDict(defaultdict):
    def __init__(self, *args, **kwargs):
        self.max_size = kwargs.pop('max_size', 1000)
        super().__init__(*args, **kwargs)
        self.stack = deque()

    def set(self, key, value):
        if len(self.stack) >= self.max_size:
            old_key = self.stack.pop()
            super().pop(old_key, None)
        self[key] = value
        self.stack.appendleft(key)

    def get(self, key):
        return super().get(key, None)

def evaluate_expression(expression):
    cache = LimitedSizeDict(max_size=1000)

    def compute(expression):
        # Internal helper functions
        def precedence(op):
            if op in ('+', '-'):
                return 1
            if op in ('*', '/'):
                return 2
            return 0

        def apply_op(operands, operators):
            right = operands.pop()
            left = operands.pop()
            op = operators.pop()
            if op == '+':
                operands.append(left + right)
            elif op == '-':
                operands.append(left - right)
            elif op == '*':
                operands.append(left * right)
            elif op == '/':
                operands.append(left / right)

        # Main computation logic
        operands = deque()
        operators = deque()
        i = 0
        while i < len(expression):
            if expression[i] == ' ':
                i += 1
                continue
            elif expression[i] == '(':
                operators.append(expression[i])
            elif expression[i].isdigit():
                val = 0
                while i < len(expression) and expression[i].isdigit():
                    val = val * 10 + int(expression[i])
                    i += 1
                operands.append(val)
                i -= 1
            elif expression[i] == ')':
                while operators and operators[-1] != '(':
                    apply_op(operands, operators)
                operators.pop()  # pop opening parenthesis
            else:
                while (operators and operators[-1] != '(' and
                       precedence(operators[-1]) >= precedence(expression[i])):
