from collections import defaultdict, deque

class LimitedCache:
    def __init__(self, max_size=1000):
        self.cache = defaultdict(int)
        self.max_size = max_size
        self.access_order = deque()

    def get(self, key):
        return self.cache.get(key)

    def set(self, key, value):
        if key in self.cache:
            self.access_order.remove(key)
        elif len(self.cache) >= self.max_size:
            oldest_key = self.access_order.popleft()
            del self.cache[oldest_key]
        self.cache[key] = value
        self.access_order.append(key)

cache = LimitedCache()

def eval_expr(expr):
    if (cached_result := cache.get(expr)) is not None:
        return cached_result

    def apply_op(operators, values):
        right = values.pop()
        left = values.pop()
        op = operators.pop()
        if op == '+':
            values.append(left + right)
        elif op == '-':
            values.append(left - right)
        elif op == '*':
            values.append(left * right)
        elif op == '/':
            values.append(left / right)

    def precedence(op):
        return 1 if op in ('+', '-') else 2

    def perform_calculation(expression):
        operators = deque()
        values = deque()
        i = 0
        while i < len(expression):
            if expression[i] == ' ':
                i += 1
                continue
            if expression[i] == '(':
                operators.append('(')
            elif expression[i] == ')':
                while operators and operators[-1] != '(':
                    apply_op(operators, values)
                operators.pop()
            elif expression[i].isdigit() or (expression[i] == '-' and (i == 0 or expression[i-1] == '(')):
                start = i
                i += 1
                while i < len(expression) and (expression[i].isdigit() or expression[i] == '.'):
                    i += 1
                values.append(float(expression[start:i]))
                continue
            else:
                while (operators and operators[-1] != '(' and
                       precedence(operators[-1]) >= precedence(expression[i])):
                    apply_op(operators, values)
                operators.append(expression[i])
            i += 1
        while operators:
            apply_op(operators, values)

        return values.pop()

    result = perform_calculation(expr)
    cache.set(expr, result)
    return result
