from collections import defaultdict, deque

def evaluate_expression(expression):
    cache = defaultdict(lambda: None)
    stack = deque()

    def eval_expr(expr):
        if expr in cache:
            return cache[expr]

        num, op, i = 0, '+', 0
        n = len(expr)
        interim_results = []

        while i < n:
            char = expr[i]

            if char.isdigit():
                num = num * 10 + int(char)

            if char == '(':
                balance = 1
                j = i + 1
                while j < n and balance != 0:
                    if expr[j] == '(':
                        balance += 1
                    elif expr[j] == ')':
                        balance -= 1
                    j += 1

                num = eval_expr(expr[i + 1:j - 1])
                i = j - 1

            if char in '+-*/' or i == n - 1:
                if op == '+':
                    stack.append(num)
                elif op == '-':
                    stack.append(-num)
                elif op == '*':
                    stack[-1] *= num
                elif op == '/':
                    stack[-1] = int(stack[-1] / num)

                interim_results.append(stack[-1])
                num, op = 0, char

            i += 1

        result = sum(stack)

        if len(cache) >= 1000:
            cache.clear()

        cache[expr] = result
        return result

    return eval_expr(expression)
