        ScheduledExecutorService executor = Executors.newSingleThreadScheduledExecutor();
        executor.scheduleAtFixedRate(this::removeInactiveSessions, SESSION_TIMEOUT_MINUTES, SESSION_TIMEOUT_MINUTES, TimeUnit.MINUTES);
    }

