        if (sessions.size() >= MAX_CAPACITY || sessions.size() > MAX_ACTIVE_SESSIONS) {
            return false;
        }
        sessions.put(sessionId, System.currentTimeMillis());
        return true;
    }

    public boolean removeSession(String sessionId) {
        return sessions.remove(sessionId) != null;
    }

    private void removeInactiveSessions() {
        long cutoff = System.currentTimeMillis() - TimeUnit.MINUTES.toMillis(SESSION_TIMEOUT_MINUTES);
        sessions.forEach((id, lastAccessTime) -> {
            if (lastAccessTime < cutoff) {
                sessions.remove(id);
            }
        });
    }

    public Long getSessionTimestamp(String sessionId) {
        return sessions.get(sessionId);
    }

    public boolean containsSession(String sessionId) {
        return sessions.containsKey(sessionId);
    }

