import java.util.concurrent.ConcurrentHashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class SessionManager {
    private final ConcurrentHashMap<String, Long> sessionMap = new ConcurrentHashMap<>(1000);
    private final Set<String> inactiveSessions = new HashSet<>();

    // Monitor and limit active sessions
    public void monitorSessions() {
        if (sessionMap.size() > 1000) {
            throw new IllegalStateException("Session limit exceeded!");
        }
    }

    // Create a new session
    public void createSession(String sessionId) {
        if (sessionMap.size() >= 1000) return; // Enforce capacity limit
        sessionMap.put(sessionId, System.currentTimeMillis());
    }

    // Read session timestamp
    public Long readSession(String sessionId) {
        return sessionMap.get(sessionId);
    }

    // Update session timestamp
    public void updateSession(String sessionId) {
        sessionMap.computeIfPresent(sessionId, (id, oldValue) -> System.currentTimeMillis()); 
    }

    // Delete a session
    public void deleteSession(String sessionId) {
        sessionMap.remove(sessionId);
    }

    // Expire old sessions
    public void expireSessions(long expirationTime) {
        sessionMap.entrySet().removeIf(entry -> {
            boolean isExpired = System.currentTimeMillis() - entry.getValue() > expirationTime;
            if (isExpired) inactiveSessions.add(entry.getKey());
            return isExpired;
        });
    }

    // Segregate sessions
    public void segregateSessions() {
        inactiveSessions.forEach(sessionMap::remove);
    }

    // Check if session is active
    public boolean isActive(String sessionId) {
        return sessionMap.containsKey(sessionId) && !inactiveSessions.contains(sessionId);
    }

    // Check if session is inactive
    public boolean isInactive(String sessionId) {
        return inactiveSessions.contains(sessionId);
    }

    // Remove expired session
    public void removeExpiredSession(String sessionId) {
        inactiveSessions.remove(sessionId);
        sessionMap.remove(sessionId);
    }

    // Initialize session status
    public void initializeSessionStatus() {
        inactiveSessions.clear();
    }
}
