        while (!minHeap.isEmpty()) {
            Element current = minHeap.poll();
            mergedList.add(current.value);

            LinkedList<Integer> currentList = lists.get(current.listIndex);
            if (!currentList.isEmpty()) {
                minHeap.offer(new Element(currentList.removeFirst(), current.listIndex));
            }
        }

        if (mergedList.size() > 10000) {
            throw new IllegalStateException("LinkedList size exceeded 10,000 elements");
        } else if (mergedList.size() < 10) {
            throw new IllegalStateException("LinkedList must maintain at least 10 elements");
        }

        return mergedList;
