package main

import (
	"fmt"
	"errors"
)

type StudentRecord struct {
	Name  string
	Grade string
}

type GradeManager struct {
	records []StudentRecord
}

func (gm *GradeManager) AddGrade(name, grade string) error {
	if len(gm.records) >= 2000 {
		return errors.New("maximum records reached")
	}
	for _, record := range gm.records {
		if record.Name == name {
			return errors.New("student already exists")
		}
	}
	gm.records = append(gm.records, StudentRecord{Name: name, Grade: grade})
	return nil
}

func (gm *GradeManager) UpdateGrade(name, grade string) error {
	for i, record := range gm.records {
		if record.Name == name {
			gm.records[i].Grade = grade
			return nil
		}
	}
	return errors.New("student not found")
}

func (gm *GradeManager) ListGrades() {
	fmt.Println("Student Grades:")
	for _, record := range gm.records {
		fmt.Printf("Name: %s, Grade: %s\n", record.Name, record.Grade)
