	if len(s.records) == 0 {
		return errors.New("stack is empty")
	}
	if s.records[len(s.records)-1].Name == record.Name {
		s.records[len(s.records)-1].Grade = record.Grade
		return nil
	}
	return errors.New("no match found at the top of the stack")
}

func (s *Stack) Pop() (StudentGrade, error) {
	if len(s.records) == 0 {
		return StudentGrade{}, errors.New("stack is empty")
	}
	top := s.records[len(s.records)-1]
	s.records = s.records[:len(s.records)-1]
	return top, nil
}

func (s *Stack) Iterate() []StudentGrade {
	return s.records
}

