fn max_non_adjacent_sum(nums: &[u32]) -> u32 {
    let mut include = 0;
    let mut exclude = 0;
    let mut computed_sums = HashSet::new();

    for &num in nums {
        let new_exclude = include.max(exclude);
        include = exclude + num;
        exclude = new_exclude;

        // Maintain memory efficiency
        if computed_sums.len() < 1500 {
            computed_sums.insert(include);
            computed_sums.insert(exclude);
        }
    }

    include.max(exclude)
}

fn main() {
