fn max_sum_non_adjacent(nums: &[i32]) -> i32 {
    let mut dp: Vec<i32> = vec![0; nums.len() + 1];
    let mut sums_hashset: HashSet<i32> = HashSet::new();

    dp[0] = 0;
    if !nums.is_empty() {
        dp[1] = nums[0];
        sums_hashset.insert(nums[0]);
