    for i in 2..=nums.len() {
        let sum_with_current = dp[i - 2] + nums[i - 1];
        dp[i] = dp[i - 1].max(sum_with_current);

        if sums_hashset.len() < 1500 {
            sums_hashset.insert(dp[i]);
        }
    }

    dp[nums.len()]
}

