        let max_excluding_current = prev_two;
        let max_including_current = prev_one + num;

        if hash_set.len() < 750 {
            hash_set.insert(max_including_current.max(max_excluding_current));
        }

        prev_two = prev_one;
        prev_one = max_including_current.max(max_excluding_current);
    }

    prev_one
}

