public class WordFrequency {
    public static Map<String, Integer> getWordFrequency(String input) {
        Map<String, Integer> frequencyMap = new HashMap<>();
        String[] words = input.toLowerCase().replaceAll("[^a-zA-Z ]", "").split("\\s+");

        for (String word : words) {
            Integer count = frequencyMap.get(word);
            if (count == null) {
                frequencyMap.put(word, 1);
            } else {
                frequencyMap.put(word, count + 1);
            }
        }
        return frequencyMap;
    }

    public static List<Map.Entry<String, Integer>> sortWordsByFrequency(Map<String, Integer> frequencyMap) {
        List<Map.Entry<String, Integer>> sortedList = new LinkedList<>(frequencyMap.entrySet());
        sortedList.sort((entry1, entry2) -> entry2.getValue().compareTo(entry1.getValue()));
        return sortedList;
    }

    public static void main(String[] args) {
        String input = "This is a test. This test is only a test!";
        Map<String, Integer> frequencyMap = getWordFrequency(input);
        List<Map.Entry<String, Integer>> sortedWords = sortWordsByFrequency(frequencyMap);

        for (Map.Entry<String, Integer> entry : sortedWords) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }
