        if (reservations.size() >= maxSeats) {
            std::cerr << "Error: Flight overbooked.\n";
            return false;
        }
        for (const auto &res : reservations) {
            if (res.seatNumber == seatNumber) {
                std::cerr << "Error: Seat already booked.\n";
                return false;
            }
        }
        reservations.emplace_back(userName, seatNumber);
        return true;
    }

    bool removeReservation(int seatNumber) {
        for (auto it = reservations.begin(); it != reservations.end(); ++it) {
            if (it->seatNumber == seatNumber) {
                reservations.erase(it);
                return true;
            }
        }
        std::cerr << "Error: Reservation not found.\n";
        return false;
    }

    bool checkReservation(int seatNumber) {
        for (const auto &res : reservations) {
            if (res.seatNumber == seatNumber) {
                return true;
            }
