use std::collections::VecDeque;
use std::fs::File;
use std::io::{self, BufRead, BufReader, Write};

#[derive(Debug, Clone)]
struct Task {
    description: String,
    completed: bool,
    high_priority: bool,
}

fn add_task(tasks: &mut VecDeque<Task>, description: String, high_priority: bool) {
    if tasks.len() >= 50 {
        tasks.pop_back(); // Ensure VecDeque never exceeds 50 elements
    }
    let task = Task {
        description,
        completed: false,
        high_priority,
    };
    if high_priority {
        tasks.push_front(task);
    } else {
        tasks.push_back(task);
    }
}

fn remove_task(tasks: &mut VecDeque<Task>) {
    tasks.pop_back();
}

fn view_tasks(tasks: &VecDeque<Task>) {
    for task in tasks {
        println!("{:?}", task);
    }
}

fn save_tasks_to_file(tasks: &VecDeque<Task>, filename: &str) -> io::Result<()> {
    let mut file = File::create(filename)?;
    for task in tasks {
        writeln!(file, "{:?},{},{},{}", task.description, task.completed, task.high_priority)?;
    }
    Ok(())
}

fn load_tasks_from_file(filename: &str) -> VecDeque<Task> {
    let file = File::open(filename).unwrap_or_else(|_| File::create(filename).unwrap());
    let reader = BufReader::new(file);
    let mut tasks = VecDeque::new();
    for line in reader.lines() {
        if let Ok(line) = line {
            let parts: Vec<&str> = line.split(',').collect();
            if parts.len() == 3 {
                let task = Task {
                    description: parts[0].to_string(),
                    completed: parts[1].parse().unwrap_or(false),
                    high_priority: parts[2].parse().unwrap_or(false),
                };
                tasks.push_back(task);
            }
        }
    }
    tasks
}

fn main() {
    let mut tasks = load_tasks_from_file("tasks.txt");

    // Simulate CLI logic
    add_task(&mut tasks, String::from("Task 1"), false);
    add_task(&mut tasks, String::from("Task 2"), true);
    view_tasks(&tasks);

    remove_task(&mut tasks);
    view_tasks(&tasks);

    save_tasks_to_file(&tasks, "tasks.txt").unwrap();
}
