#include <iostream>
#include <vector>
#include <unordered_set>
#include <tuple>
#include <queue>
#include <climits>

using namespace std;

struct PairHash {
    size_t operator()(const pair<int, int>& p) const {
        return hash<int>()(p.first) ^ hash<int>()(p.second);
    }
};

int shortestPath(vector<vector<int>>& grid) {
    int rows = grid.size();
    int cols = grid[0].size();
    vector<vector<int>> dp(rows, vector<int>(cols, INT_MAX));
    unordered_set<pair<int, int>, PairHash> visited;

    priority_queue<tuple<int, int, int>, vector<tuple<int, int, int>>, greater<tuple<int, int, int>>> pq;
    pq.push({grid[0][0], 0, 0}); // {cost, row, col}
    dp[0][0] = grid[0][0];

    vector<pair<int, int>> directions = {{0, 1}, {1, 0}, {0, -1}, {-1, 0}};

    while (!pq.empty()) {
        auto [currentCost, row, col] = pq.top();
        pq.pop();

        if (visited.find({row, col}) != visited.end())
            continue;
        visited.insert({row, col});

        for (auto [dr, dc] : directions) {
            int newRow = row + dr;
            int newCol = col + dc;

            if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols) {
                int newCost = currentCost + grid[newRow][newCol];
                if (newCost < dp[newRow][newCol]) {
                    dp[newRow][newCol] = newCost;
                    pq.push({newCost, newRow, newCol});
                }
            }
        }
    }

    return dp[rows - 1][cols - 1];
}

int main() {
    int n, m;
    cout << "Enter the number of rows and columns in the grid: ";
    cin >> n >> m;

    vector<vector<int>> grid(n, vector<int>(m));
    cout << "Enter the values of the grid:\n";
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            cin >> grid[i][j];
        }
    }

    cout << "Shortest Path Cost: " << shortestPath(grid) << endl;

    return 0;
}
