public:
    CityGrid(int rows, int cols) : rows(rows), cols(cols) {
        grid.resize(rows, vector<int>(cols, 0));
    }

    void setIntersection(int row, int col, int value) {
        grid[row][col] = value;
    }

    int shortestPath(int startRow, int startCol, int endRow, int endCol) {
        vector<vector<int>> dist(rows, vector<int>(cols, INT_MAX));
        dist[startRow][startCol] = 0;

        unordered_set<int> visited;
        queue<pair<int, int>> q;
        q.push({startRow, startCol});

        vector<pair<int, int>> directions = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
        auto indexCalculator = [this](int row, int col) { return row * cols + col; };

        while (!q.empty()) {
            auto [currentRow, currentCol] = q.front();
            q.pop();

            for (const auto& [dr, dc] : directions) {
                int newRow = currentRow + dr;
                int newCol = currentCol + dc;

                if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols) {
                    if (dist[currentRow][currentCol] + 1 < dist[newRow][newCol]) {
                        dist[newRow][newCol] = dist[currentRow][currentCol] + 1;
                        int index = indexCalculator(newRow, newCol);
                        if (visited.find(index) == visited.end()) {
                            visited.insert(index);
                            q.push({newRow, newCol});
                        }
                    }
                }
            }
        }
        visited.clear();
        return dist[endRow][endCol] == INT_MAX ? -1 : dist[endRow][endCol];
    }

