#include <iostream>
#include <vector>
#include <unordered_set>
#include <climits>

using namespace std;

// Function to check if a position is within grid bounds
bool isValid(int x, int y, int n, int m) {
    return x >= 0 && x < n && y >= 0 && y < m;
}

// Function to calculate the shortest path using dynamic programming
int shortestPathDP(const vector<vector<int>>& grid, int n, int m) {
    vector<vector<int>> dp(n, vector<int>(m, INT_MAX));
    unordered_set<pair<int, int>, hash_pair> visited;

    // Initialize the start of the path
    dp[0][0] = grid[0][0];
    visited.insert({0, 0});

    // Dynamic Programming approach to calculate the shortest path
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            if (visited.find({i, j}) != visited.end()) {
                continue;  // Skip already visited intersections
            }

            if (isValid(i - 1, j, n, m) && visited.find({i - 1, j}) != visited.end()) {
                dp[i][j] = min(dp[i][j], dp[i - 1][j] + grid[i][j]);
            }
            if (isValid(i, j - 1, n, m) && visited.find({i, j - 1}) != visited.end()) {
                dp[i][j] = min(dp[i][j], dp[i][j - 1] + grid[i][j]);
            }

            visited.insert({i, j});

            // Optimize memory: clear visited intersections if it exceeds the limit
            if (visited.size() > 500) {
                visited.clear();
                visited.insert({i, j});
            }
        }
    }

    return dp[n - 1][m - 1];
}

int main() {
    int n, m;
    cin >> n >> m;  // Grid dimensions
    vector<vector<int>> grid(n, vector<int>(m));

    // Reading the grid
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            cin >> grid[i][j];
        }
    }

    int result = shortestPathDP(grid, n, m);
    cout << "Shortest Path Cost: " << result << endl;

    return 0;
}

// Custom hash function for unordered_set pair
struct hash_pair {
    template <class T1, class T2>
    size_t operator()(const pair<T1, T2>& pair) const {
        auto hash1 = hash<T1>{}(pair.first);
        auto hash2 = hash<T2>{}(pair.second);
        return hash1 ^ hash2;
    }
};
