    int cols = grid[0].size();

    std::vector<std::vector<int>> dp(rows, std::vector<int>(cols, std::numeric_limits<int>::max()));
    dp[start_x][start_y] = 0;

    std::unordered_set<int> activeSet;
    activeSet.insert(start_x * cols + start_y);

    while (!activeSet.empty()) {
        std::unordered_set<int> newSet;

        for (int i : activeSet) {
            int x = i / cols;
            int y = i % cols;
            int currentCost = dp[x][y];

            if (x > 0) {
                int newCost = currentCost + grid[x - 1][y];
                if (newCost < dp[x - 1][y]) {
                    dp[x - 1][y] = newCost;
                    newSet.insert((x - 1) * cols + y);
                }
            }

            if (x < rows - 1) {
                int newCost = currentCost + grid[x + 1][y];
                if (newCost < dp[x + 1][y]) {
                    dp[x + 1][y] = newCost;
                    newSet.insert((x + 1) * cols + y);
                }
            }

            if (y > 0) {
                int newCost = currentCost + grid[x][y - 1];
                if (newCost < dp[x][y - 1]) {
                    dp[x][y - 1] = newCost;
                    newSet.insert(x * cols + y - 1);
                }
            }

            if (y < cols - 1) {
