#include <unordered_set>
#include <limits>

const int INF = std::numeric_limits<int>::max();

struct Intersection {
    int x, y;
};

int computeShortestPath(const std::vector<std::vector<int>>& grid, const Intersection& start, const Intersection& end) {
    int rows = grid.size(), cols = grid[0].size();
    std::vector<std::vector<int>> dp(rows, std::vector<int>(cols, INF));
    std::vector<std::vector<bool>> visited(rows, std::vector<bool>(cols, false));
    std::unordered_set<int> currentSet;

    dp[start.x][start.y] = 0;

    for (int steps = 0; steps < rows * cols; ++steps) {
        int minDistance = INF;
        Intersection current{-1, -1};

        // Find the intersection with the minimum tentative distance
        for (int r = 0; r < rows; ++r) {
            for (int c = 0; c < cols; ++c) {
                if (!visited[r][c] && dp[r][c] < minDistance) {
                    minDistance = dp[r][c];
                    current = {r, c};
                }
            }
        }

        // If the end has been reached, break the loop
        if (current.x == end.x && current.y == end.y) break;

        visited[current.x][current.y] = true;
        currentSet.insert(current.x * cols + current.y); // Insert current intersection

        if (currentSet.size() > 500) {
            currentSet.clear(); // Ensure the set doesn't exceed 500 elements
        }

        // Update distances for neighbors
        std::vector<Intersection> neighbors = {
            {current.x - 1, current.y}, {current.x + 1, current.y},
            {current.x, current.y - 1}, {current.x, current.y + 1}};

        for (const auto& neighbor : neighbors) {
            if (neighbor.x >= 0 && neighbor.x < rows && neighbor.y >= 0 && neighbor.y < cols) {
                int newDistance = dp[current.x][current.y] + grid[neighbor.x][neighbor.y];
                dp[neighbor.x][neighbor.y] = std::min(dp[neighbor.x][neighbor.y], newDistance);
            }
        }
    }

    return dp[end.x][end.y];
}

int main() {
    std::vector<std::vector<int>> grid = {
        {1, 3, 1},
        {1, 5, 1},
        {4, 2, 1}
    };

    Intersection start{0, 0};
    Intersection end{2, 2};

    int shortestPath = computeShortestPath(grid, start, end);
    std::cout << "Shortest Path Distance: " << shortestPath << std::endl;

    return 0;
}
