const (
	MaxEntries = 1000
	BufferSize = 10
)

type TemperatureBuffer struct {
	Data []float64
}

func (tb *TemperatureBuffer) AddTemperature(t float64) error {
	if len(tb.Data) >= BufferSize {
		return errors.New("buffer overflow: too many entries")
	}
	tb.Data = append(tb.Data, t)
	return nil
}

func (tb *TemperatureBuffer) MovingAverage() (float64, error) {
	if len(tb.Data) == 0 {
		return 0, errors.New("empty buffer: no data to compute average")
	}
	var sum float64
	for _, v := range tb.Data {
		sum += v
	}
	return sum / float64(len(tb.Data)), nil
}

func processTemperatureData(tempData []float64) {
	logger := logrus.New()
	logger.Out = os.Stdout

	if len(tempData) > MaxEntries {
		logger.Error("too many temperature entries")
		return
	}

	buffer := &TemperatureBuffer{}

	for _, temp := range tempData {
		if err := buffer.AddTemperature(temp); err != nil {
			logger.Warn(err)
			continue
		}

		avg, err := buffer.MovingAverage()
		if err != nil {
			logger.Warn(err)
			continue
		}

		logger.Info(fmt.Sprintf("Moving average: %v", avg))
	}
}

