package main

import (
	"log"
	"sync"

	"github.com/something/buffer" // Hypothetical buffer package
)

const bufferCapacity = 20
const warningThreshold = 15

type TemperatureDataProcessor struct {
	buf *buffer.Buffer
	mu  sync.Mutex
}

func NewTemperatureDataProcessor() *TemperatureDataProcessor {
	return &TemperatureDataProcessor{
		buf: buffer.New(bufferCapacity),
	}
}

func (p *TemperatureDataProcessor) ProcessTemperatureData(data []float64) {
	p.mu.Lock()
	defer p.mu.Unlock()

	if len(data) == 0 {
		log.Println("Warning: No temperature data provided")
		return
	}

	for _, temp := range data {
		if p.buf.Size() >= bufferCapacity {
			log.Println("Info: Buffer full, discarding oldest entry")
			_, err := p.buf.Pop()
			if err != nil {
				log.Println("Error: Failed to pop from buffer:", err)
				continue
			}
		}

		if p.buf.Size() >= warningThreshold {
			log.Println("Warning: Buffer is approaching capacity, size:", p.buf.Size())
		}

		err := p.buf.Push(temp)
		if err != nil {
			log.Println("Error: Failed to push temperature data into buffer:", err)
			continue
		}

		log.Printf("Debug: Pushed temperature data %.2f to buffer", temp)
	}

	p.computeMovingAverage()
}

func (p *TemperatureDataProcessor) computeMovingAverage() {
	total := 0.0
	count := p.buf.Size()

	for i := 0; i < count; i++ {
		val, err := p.buf.Pop()
		if err != nil {
			log.Println("Error: Failed to pop from buffer during moving average computation:", err)
			continue
		}

		total += val.(float64)
		err = p.buf.Push(val)
		if err != nil {
			log.Println("Error: Failed to push back into buffer during moving average computation:", err)
			continue
		}
	}

	if count > 0 {
		average := total / float64(count)
		log.Printf("Info: Computed moving average: %.2f", average)
	} else {
		log.Println("Warning: No data in buffer to compute moving average")
	}
}

func main() {
	log.SetFlags(log.LstdFlags | log.Lshortfile)

	dataProcessor := NewTemperatureDataProcessor()
	temperatureStream := []float64{23.5, 22.0, 21.3, 20.7, 24.2, 25.1, 26.3, 20.9, 23.0, 22.8} // Example data

	dataProcessor.ProcessTemperatureData(temperatureStream)
}
