		sum += v
	}
	return sum / float64(len(b.data))
}

type Node struct {
	value float64
	next  *Node
}

type LinkedList struct {
	head *Node
}

func (l *LinkedList) Add(value float64) {
	newNode := &Node{value: value}
	if l.head == nil {
		l.head = newNode
	} else {
		current := l.head
		for current.next != nil {
			current = current.next
		}
		current.next = newNode
	}
}

func main() {
	log.SetOutput(os.Stdout)
	buffer := NewBuffer(20)
	threshold := 30.0
	analysisList := &LinkedList{}
	temperatureData := generateTemperatureData(1000)

