		if len(buffer.data) >= buffer.maxCap {
			log.Println("Warning: Buffer capacity max reached, oldest data will be discarded.")
		}
		buffer.Push(temp)
		movingAverage := buffer.CalculateMovingAverage()
		log.Printf("Current moving average: %.2f\n", movingAverage)

		if temp > threshold {
			log.Println("Threshold reached, adding temperature to LinkedList.")
			analysisList.Add(temp)
		}
