using namespace std;

int maxSubArraySum(const vector<int>& nums) {
    if (nums.empty())
        return 0;

    int maxSum = nums[0];
    int currentSum = nums[0];
    for (size_t i = 1; i < nums.size(); ++i) {
        currentSum = max(nums[i], currentSum + nums[i]);
        maxSum = max(maxSum, currentSum);
    }
    return maxSum;
