#include <stdexcept>

class LimitedStack {
private:
    std::stack<int> s;
    static const int MAX_SIZE = 50;

public:
    void push(int value) {
        if(s.size() >= MAX_SIZE) {
            throw std::overflow_error("Stack exceeds maximum size.");
        }
        s.push(value);
    }

    void pop() {
        if(s.empty()) {
            throw std::underflow_error("Stack is empty.");
        }
        s.pop();
    }

    int top() {
        if(s.empty()) {
            throw std::underflow_error("Stack is empty.");
        }
        return s.top();
    }

    bool empty() const {
        return s.empty();
    }
};

int maxSubArraySum(const std::vector<int>& nums, std::vector<std::vector<int>>& subarrays) {
    if(nums.empty()) return 0;

    LimitedStack ls;
    int maxSum = nums[0], currentSum = nums[0];
    ls.push(nums[0]);
    subarrays.push_back({nums[0]});
    std::vector<int> currentSubarray = {nums[0]};

    for(size_t i = 1; i < nums.size(); ++i) {
        if(currentSum < 0) {
            currentSum = 0;
            while(!ls.empty()) {
                ls.pop();
            }
            currentSubarray.clear();
        }

        currentSum += nums[i];
        ls.push(nums[i]);
        currentSubarray.push_back(nums[i]);

        if(currentSum > maxSum) {
            maxSum = currentSum;
            subarrays.clear();
            subarrays.push_back(currentSubarray);
        } else if(currentSum == maxSum) {
            subarrays.push_back(currentSubarray);
        }
    }

    return maxSum;
}

