	if n <= 1 {
		memo.Store(n, uint64(n))
		return uint64(n)
	}

	// Calculate Fibonacci value using recursive calls, storing or retrieving values
	value := fibonacci(n-1) + fibonacci(n-2)
	memo.LoadOrStore(n, value)

	// Backup every 100th value
	if n%100 == 0 {
		backup = append(backup, value)
	}

	return value
}

