package main

import (
	"fmt"
	"sync"
)

// Fibonacci structure with sync.Map and a slice for backup
type Fibonacci struct {
	cache   sync.Map
	backup  [][]int
	maxSize int
}

func NewFibonacci(maxSize int) *Fibonacci {
	return &Fibonacci{
		cache:   sync.Map{},
		maxSize: maxSize,
	}
}

// Calculate Fibonacci number using memoization with sync.Map and backup mechanism
func (f *Fibonacci) Fib(n int) int {
	if n <= 1 {
		return n
	}

	if cachedValue, found := f.cache.Load(n); found {
		return cachedValue.(int)
	}

	value := f.Fib(n-1) + f.Fib(n-2)

	// Store or Load the value in the map
	actual, _ := f.cache.LoadOrStore(n, value)

	if n%100 == 0 {
		f.Backup(n, actual.(int))
	}

	return actual.(int)
}

// Backup mechanism
func (f *Fibonacci) Backup(n int, value int) {
	if len(f.backup) == 0 || len(f.backup[len(f.backup)-1]) >= f.maxSize {
		f.backup = append(f.backup, []int{value})
	} else {
		f.backup[len(f.backup)-1] = append(f.backup[len(f.backup)-1], value)
	}
}

func main() {
	fibCalc := NewFibonacci(10)

	for i := 0; i <= 1000; i++ {
		fmt.Printf("Fib(%d) = %d\n", i, fibCalc.Fib(i))
	}
}
