std::vector<int> mergeSortedArrays(const std::vector<std::vector<int>>& arrays) {
    std::vector<int> result;
    using Element = std::pair<int, std::pair<int, int>>; // (value, (array index, element index))
    auto compare = [](const Element& a, const Element& b) { return a.first > b.first; };
    std::priority_queue<Element, std::vector<Element>, decltype(compare)> pq(compare);

    // Initialize priority queue with the first element of each array
    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            pq.push({arrays[i][0], {i, 0}});
        }
