        Element current = pq.top(); pq.pop();
        result.push_back(current.first);

        int arrayIndex = current.second.first;
        int elementIndex = current.second.second;

        // If there is a next element in the same array, push it to the priority queue
        if (elementIndex + 1 < arrays[arrayIndex].size()) {
            pq.push({arrays[arrayIndex][elementIndex + 1], {arrayIndex, elementIndex + 1}});
        }
    }

    return result;
}

