import java.util.PriorityQueue;
import java.util.concurrent.TimeUnit;

class Task implements Comparable<Task> {
    int priority;
    long duration; // in milliseconds

    public Task(int priority, long duration) {
        this.priority = priority;
        this.duration = duration;
    }

    @Override
    public int compareTo(Task other) {
        return Integer.compare(other.priority, this.priority);
    }
}

public class TaskProcessor {
    private PriorityQueue<Task> queue;
    private static final int MAX_TASKS = 100;

    public TaskProcessor() {
        this.queue = new PriorityQueue<>();
    }

    public boolean addTask(Task task) {
        if (queue.size() < MAX_TASKS) {
            return queue.offer(task);
        } else {
            System.out.println("Task queue is full.");
            return false;
        }
    }

    public Task pollTask() {
        try {
            return queue.poll();
        } catch (Exception e) {
            System.out.println("Failed to poll task: " + e.getMessage());
            return null;
        }
    }

    public Task peekTask() {
        try {
            return queue.peek();
        } catch (Exception e) {
            System.out.println("Failed to peek task: " + e.getMessage());
            return null;
        }
    }

    public void clearTasks() {
        queue.clear();
    }

    public long processTasks() {
        long totalTime = 0;
        long startTime = System.currentTimeMillis();
        while (!queue.isEmpty()) {
            Task task = queue.poll();
            if (task != null) {
                try {
                    TimeUnit.MILLISECONDS.sleep(task.duration);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    System.out.println("Processing interrupted: " + e.getMessage());
                }
                totalTime += task.duration;
            }
        }
        long endTime = System.currentTimeMillis();
        System.out.println("Total time taken to execute all tasks: " + (endTime - startTime) + " milliseconds.");
        return totalTime;
    }
}
