import java.util.PriorityQueue;
import java.util.LinkedList;
import java.util.HashMap;
import java.util.Comparator;

class Task {
    int priority;
    int duration;

    Task(int priority, int duration) {
        this.priority = priority;
        this.duration = duration;
    }

    public int getPriority() {
        return this.priority;
    }

    public int getDuration() {
        return this.duration;
    }
}

public class TaskProcessor {
    private static final int MAX_CAPACITY = 100;

    public void processTasks(LinkedList<Task> tasks) {
        PriorityQueue<Task> taskQueue = new PriorityQueue<>(Comparator.comparingInt(Task::getPriority).reversed());
        LinkedList<Task> processedTasks = new LinkedList<>();
        HashMap<Task, Integer> durationMap = new HashMap<>();
        int totalDuration = 0;

        for (Task task : tasks) {
            if (taskQueue.size() >= MAX_CAPACITY) {
                while (taskQueue.size() >= MAX_CAPACITY) {
                    Task processedTask = taskQueue.poll();
                    processedTasks.add(processedTask);
                    durationMap.put(processedTask, processedTask.getDuration());
                }
            }
            taskQueue.add(task);
        }

        // Process remaining tasks in the queue
        while (!taskQueue.isEmpty()) {
            Task processedTask = taskQueue.poll();
            processedTasks.add(processedTask);
            durationMap.put(processedTask, processedTask.getDuration());
        }

        // Calculate total duration
        for (int duration : durationMap.values()) {
            totalDuration += duration;
        }

        taskQueue.clear();
        System.out.println("Total Processing Time: " + totalDuration + " ms");
    }
}
