func maxSubArraySum(arr [100]int, n int) int {
	maxSoFar, maxEndingHere := arr[0], arr[0]
	for i := 1; i < n; i++ {
		if maxEndingHere+arr[i] > arr[i] {
			maxEndingHere += arr[i]
		} else {
			maxEndingHere = arr[i]
