    void addProduct(const std::string& name, const std::string& genre, double price, double discount) {
        if (productMap.size() < 500 && productStack.size() < 150) {
            Product product = {name, genre, price, discount};
            productMap[name] = product;
            productStack.push(name);
        } else {
            std::cout << "Cannot add more products. Limit reached." << std::endl;
        }
    }

    void removeProduct() {
        if (!productStack.empty()) {
            std::string name = productStack.top();
            productMap.erase(name);
            productStack.pop();
        } else {
            std::cout << "No products to remove." << std::endl;
        }
    }

    void swapTopTwoProducts() {
        if (productStack.size() >= 2) {
            std::string topProduct = productStack.top();
            productStack.pop();
            std::string secondProduct = productStack.top();
            productStack.pop();
            productMap[topProduct].price -= productMap[topProduct].discount; // Apply discount
            productMap[secondProduct].price -= productMap[secondProduct].discount; // Apply discount
            productStack.push(topProduct);
            productStack.push(secondProduct);
        } else {
            std::cout << "Not enough products to swap." << std::endl;
        }
    }

    void calculateTotal() {
        double total = 0.0;
        for (const auto& entry : productMap) {
            const Product& product = entry.second;
            total += (product.price - product.discount);
