    std::queue<Product> transactionQueue;
    const int MAX_STACK_SIZE = 150;

public:
    void addProduct(const Product& product) {
        if (productStack.size() < MAX_STACK_SIZE) {
            productStack.push(product);
        }
        if (productMap.size() < 500) {
            productMap[product.name] = product;
        }
    }

    void removeProduct() {
        if (!productStack.empty()) {
            Product topProduct = productStack.top();
            productMap.erase(topProduct.name);
            productStack.pop();
        }
    }

    void swapProducts() {
        if (productStack.size() >= 2) {
            Product first = productStack.top();
            productStack.pop();
            Product second = productStack.top();
            productStack.pop();
            productStack.push(first);
            productStack.push(second);
        }
    }

    void enqueueTransaction(const Product& product) {
        transactionQueue.push(product);
    }

    void processTransaction() {
        if (!transactionQueue.empty()) {
            Product transaction = transactionQueue.front();
            transactionQueue.pop();
            // Process transaction accordingly
            std::cout << "Processed transaction for: " << transaction.name << std::endl;
        }
    }

    void sortByPrice() {
        std::vector<Product> products;
        for (const auto& pair : productMap) {
            products.push_back(pair.second);
        }
        std::sort(products.begin(), products.end(), [](const Product& a, const Product& b) {
            return a.price < b.price;
        });
        updateProductMap(products);
    }

    void sortByGenre() {
        std::vector<Product> products;
        for (const auto& pair : productMap) {
            products.push_back(pair.second);
        }
        std::sort(products.begin(), products.end(), [](const Product& a, const Product& b) {
            return a.genre < b.genre;
        });
        updateProductMap(products);
    }

private:
    void updateProductMap(const std::vector<Product>& products) {
        productMap.clear();
        for (const Product& product : products) {
            if (productMap.size() < 500) {
                productMap[product.name] = product;
            }
        }
    }
};

int main() {
    BookStore store;

    Product book1 = {"Book1", "Fiction", 20.0, 5.0};
    Product book2 = {"Book2", "Non-Fiction", 15.0, 3.0};

    store.addProduct(book1);
    store.addProduct(book2);

    store.sortByPrice();
    store.enqueueTransaction(book1);
    store.processTransaction();

    return 0;
}
