// Function to merge sorted arrays using a min-heap
vector<int> mergeSortedArrays(const vector<vector<int>>& arrays) {
    using Element = pair<int, pair<int, int>>; // {value, {array_index, element_index}}
    priority_queue<Element, vector<Element>, greater<Element>> minHeap;
    vector<int> result;

    // Initialize minHeap with first element of each array
    for (int i = 0; i < arrays.size(); ++i) {
        if (!arrays[i].empty()) {
            minHeap.push({arrays[i][0], {i, 0}});
        }
    }

    // Merge process
    while (!minHeap.empty()) {
        Element smallest = minHeap.top();
        minHeap.pop();
        int value = smallest.first;
        int arrayIndex = smallest.second.first;
        int elementIndex = smallest.second.second;
        result.push_back(value);

        // If there's a next element in the same array, push it to the minHeap
        if (elementIndex + 1 < arrays[arrayIndex].size()) {
            minHeap.push({arrays[arrayIndex][elementIndex + 1], {arrayIndex, elementIndex + 1}});
        }
    }

    return result;
}

