bool compareByAge(const Employee& e1, const Employee& e2) {
    return e1.getAge() < e2.getAge();
}

bool compareByName(const Employee& e1, const Employee& e2) {
    return e1.getName() < e2.getName();
}

// Stable sorting function
void stableSortEmployees(std::deque<Employee>& employees) {
    if (employees.empty()) {
        throw std::invalid_argument("Employee list is empty.");
    }

    std::stable_sort(employees.begin(), employees.end(), compareByName);
    std::stable_sort(employees.begin(), employees.end(), compareByAge);
}

int main() {
    try {
        std::deque<Employee> employees;

        // Input handling: Ensure capacity constraint is preserved
        if (employees.size() > 800) {
            throw std::overflow_error("Deque capacity exceeded (Max: 800 employees).");
        }

        // Example input
        employees.emplace_back("Alice", 30);
        employees.emplace_back("Bob", 25);
        employees.emplace_back("Charlie", 25);
        employees.emplace_back("Dave", 35);

        // Sorting employees
        stableSortEmployees(employees);

        // Display sorted employees
        for (const auto& employee : employees) {
            std::cout << employee.getName() << " - " << employee.getAge() << std::endl;
        }

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
