#include <string>
#include <deque>
#include <vector>
#include <algorithm>
#include <mutex>
#include <thread>
#include <stdexcept>

class Employee {
private:
    std::string name;
    int age;

public:
    Employee(std::string name, int age) : name(name), age(age) {}

    std::string getName() const { return name; }
    int getAge() const { return age; }

    friend std::ostream& operator<<(std::ostream& os, const Employee& e) {
        os << "Name: " << e.name << ", Age: " << e.age;
        return os;
    }
};

class ThreadSafeDeque {
private:
    std::deque<Employee> employees;
    std::mutex mtx;
    const size_t max_capacity = 800;

public:
    void push_back(const Employee& employee) {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.size() >= max_capacity) {
            throw std::overflow_error("Deque capacity exceeded!");
        }
        employees.push_back(employee);
    }

    void pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (!employees.empty()) {
            employees.pop_back();
        }
    }

    void stable_sort() {
        std::lock_guard<std::mutex> lock(mtx);
        std::stable_sort(employees.begin(), employees.end(), [](const Employee& a, const Employee& b) {
            if (a.getAge() != b.getAge()) {
                return a.getAge() < b.getAge();
            }
            return a.getName() < b.getName();
        });
    }

    void print() const {
        std::lock_guard<std::mutex> lock(mtx);
        for (const auto& employee : employees) {
            std::cout << employee << std::endl;
        }
    }
};

int main() {
    ThreadSafeDeque tsDeque;

    try {
        tsDeque.push_back(Employee("Alice", 30));
        tsDeque.push_back(Employee("Bob", 25));
        tsDeque.push_back(Employee("Charlie", 30));

        tsDeque.stable_sort();
        tsDeque.print();
    } catch (const std::exception& e) {
        std::cerr << "Exception: " << e.what() << std::endl;
    }

    return 0;
}
