    if (e1.getAge() != e2.getAge()) {
        return e1.getAge() < e2.getAge();
    }
    return e1.getName() < e2.getName();
}

class ThreadSafeDeque {
private:
    std::deque<Employee> employeeDeque;
    mutable std::mutex mtx;
    const size_t MAX_SIZE = 600;

public:
    void push_back(const Employee& employee) {
        std::lock_guard<std::mutex> lock(mtx);
        if (employeeDeque.size() < MAX_SIZE) {
            employeeDeque.push_back(employee);
        } else {
            throw std::runtime_error("Deque exceeded maximum size");
        }
    }

    void pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (!employeeDeque.empty()) {
            employeeDeque.pop_back();
        } else {
            throw std::runtime_error("Deque is empty");
        }
    }

    std::vector<Employee> getSortedEmployees() {
        std::lock_guard<std::mutex> lock(mtx);
        std::vector<Employee> sortedEmployees(employeeDeque.begin(), employeeDeque.end());
