#include <string>
#include <algorithm>
#include <mutex>
#include <memory>
#include <stdexcept>

class Employee {
    std::string name;
    int age;
    int priority;

public:
    Employee(const std::string& name, int age, int priority) : name(name), age(age), priority(priority) {
        if (name.empty() || age < 0 || priority < 0) {
            throw std::invalid_argument("Invalid employee parameters");
        }
    }

    std::string getName() const { return name; }
    int getAge() const { return age; }
    int getPriority() const { return priority; }

    // Custom comparison function for sorting by age then name
    static bool compareByAgeAndName(const Employee& e1, const Employee& e2) {
        if (e1.age == e2.age)
            return e1.name < e2.name;
        return e1.age < e2.age;
    }

    // Custom comparison for priority_queue (higher priority first)
    static bool compareByPriority(const Employee& e1, const Employee& e2) {
        return e1.priority < e2.priority;
    }
};

class EmployeeDeque {
    static const size_t MAX_SIZE = 600;
    std::deque<Employee> deque;
    std::mutex mtx;

public:
    bool push_back(const Employee& emp) {
        std::lock_guard<std::mutex> lock(mtx);
        if (deque.size() >= MAX_SIZE) {
            return false;
        }
        deque.push_back(emp);
        return true;
    }

    bool pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (!deque.empty()) {
            deque.pop_back();
            return true;
        }
        return false;
    }

    void stableSort() {
        std::lock_guard<std::mutex> lock(mtx);
        std::stable_sort(deque.begin(), deque.end(), Employee::compareByAgeAndName);
    }

    bool isEmpty() const {
        std::lock_guard<std::mutex> lock(mtx);
        return deque.empty();
    }
};

int main() {
    try {
        EmployeeDeque employeeDeque;

        std::vector<Employee> employees = {
            Employee("Alice", 30, 2),
            Employee("Bob", 25, 1),
            Employee("Charlie", 25, 3)
        };

        std::priority_queue<Employee, std::vector<Employee>, decltype(&Employee::compareByPriority)> priorityQueue(Employee::compareByPriority);

        for (const auto& emp : employees) {
            priorityQueue.push(emp);
        }

        while (!priorityQueue.empty()) {
            Employee emp = priorityQueue.top();
            priorityQueue.pop();
            // Add with priority handling before pushing to deque
            if (!employeeDeque.push_back(emp)) {
                std::cerr << "Deque is at maximum capacity\n";
                break;
            }
        }

        employeeDeque.stableSort();

        while (!employeeDeque.isEmpty()) {
            employeeDeque.pop_back();
        }

    } catch (const std::exception& e) {
        std::cerr << "Exception: " << e.what() << '\n';
    }

    return 0;
}
