use std::collections::HashMap;
use std::fs::File;
use std::io::{self, BufRead};
use std::path::Path;

fn read_file(file_path: &str) -> io::Result<Vec<String>> {
    let mut content = Vec::new();
    let file = File::open(file_path)?;
    let reader = io::BufReader::new(file);

    for line in reader.lines() {
        let line = line?;
        content.push(line);
    }

    Ok(content)
}

fn tokenize(text: Vec<String>) -> Vec<String> {
    text.iter()
        .flat_map(|line| {
            line.split_whitespace()
                .map(|word| word.to_lowercase().chars().filter(|c| c.is_alphanumeric()).collect::<String>())
                .collect::<Vec<String>>()
        })
        .collect()
}

fn count_word_frequencies(words: Vec<String>) -> Vec<(String, usize)> {
    let mut hash_map: HashMap<String, usize> = HashMap::new();

    for word in words.iter() {
        let counter = hash_map.entry(word.clone()).or_insert(0);
        *counter += 1;
        if hash_map.len() > 10_000 {
            break;
        }
    }

    let mut frequency_vector: Vec<(String, usize)> = hash_map.into_iter().collect();
    frequency_vector.sort_by(|a, b| b.1.cmp(&a.1));

    frequency_vector
}

fn main() {
    let file_path = "large_text.txt"; // Ensure this file path is correct
    let text = read_file(file_path).expect("Failed to read file");
    let words = tokenize(text);
    let frequencies = count_word_frequencies(words);

    for (word, count) in frequencies {
        println!("{}: {}", word, count);
    }
}
