use std::collections::{HashMap, VecDeque, BinaryHeap};
use std::fs::File;
use std::io::{self, BufRead};
use std::path::Path;
use std::cmp::Reverse;
use std::iter::FromIterator;

fn main() {
    let path = "large_text_file.txt";

    let file = File::open(&path).expect("Unable to open file");
    let reader = io::BufReader::new(file);

    let mut word_count: HashMap<String, usize> = HashMap::with_capacity(10_000);
    let mut word_queue: VecDeque<String> = VecDeque::new();

    for line in reader.lines() {
        if let Ok(line) = line {
            for word in line.split_whitespace() {
                let cleaned_word = word.to_lowercase().chars()
                    .filter(|c| c.is_alphabetic())
                    .collect::<String>();

                if !cleaned_word.is_empty() {
                    word_queue.push_back(cleaned_word);
                }
            }

            while let Some(word) = word_queue.pop_front() {
                let count = word_count.entry(word).or_insert(0);
                *count += 1;
            }
        }
    }

    // Use a BinaryHeap to maintain the top N frequent words
    let mut heap = BinaryHeap::new();
    for (word, &count) in &word_count {
        heap.push(Reverse((count, word)));
        if heap.len() > 10_000 {
            heap.pop();
        }
    }

    let mut top_words = Vec::from_iter(heap.into_sorted_vec().into_iter().map(|Reverse((count, word))| (word.clone(), count)));
    top_words.sort_by(|a, b| b.1.cmp(&a.1)); // Sort in descending order

    println!("Top words:");
    for (word, count) in top_words {
        println!("{}: {}", word, count);
    }
}
