use std::collections::{HashMap, LinkedList};
use std::time::{SystemTime, UNIX_EPOCH};
use thiserror::Error;

#[derive(Debug)]
struct Message {
    id: u32,
    timestamp: u64,
}

#[derive(Debug, Error)]
enum QueueError {
    #[error("Queue overflow: Cannot push more than 500 messages")]
    Overflow,
    #[error("Message not found for ID: {0}")]
    MessageNotFound(u32),
}

struct MessageQueue {
    messages: LinkedList<Message>,
    id_map: HashMap<u32, LinkedList<Message>::CursorMut>,
    max_size: usize,
}

impl MessageQueue {
    fn new(max_size: usize) -> Self {
        Self {
            messages: LinkedList::new(),
            id_map: HashMap::new(),
            max_size,
        }
    }

    fn push(&mut self, id: u32) -> Result<(), QueueError> {
        if self.messages.len() >= self.max_size {
            return Err(QueueError::Overflow);
        }

        let timestamp = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
        let message = Message { id, timestamp };
        self.messages.push_front(message);
        let cursor = self.messages.cursor_front_mut();
        self.id_map.insert(id, cursor);

        Ok(())
    }

    fn pop(&mut self) -> Option<Message> {
        if let Some(message) = self.messages.pop_front() {
            self.id_map.remove(&message.id);
            Some(message)
        } else {
            None
        }
    }

    fn lookup(&self, id: u32) -> Result<&Message, QueueError> {
        if let Some(cursor) = self.id_map.get(&id) {
            Ok(cursor.current().unwrap())
        } else {
            Err(QueueError::MessageNotFound(id))
        }
    }
}

fn main() {
    let mut queue = MessageQueue::new(500);

    // Example usage
    match queue.push(1) {
        Ok(_) => println!("Message pushed successfully."),
        Err(e) => println!("Error: {}", e),
    }

    match queue.lookup(1) {
        Ok(msg) => println!("Message found: {:?}", msg),
        Err(e) => println!("Error: {}", e),
    }

    match queue.pop() {
        Some(msg) => println!("Message popped: {:?}", msg),
        None => println!("No message to pop."),
    }
}
