use std::collections::LinkedList;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use std::thread;

struct Message {
    id: String,
    timestamp: Instant,
}

struct MessageQueue {
    list: LinkedList<Message>,
    max_size: usize,
}

impl MessageQueue {
    fn new(max_size: usize) -> Self {
        Self {
            list: LinkedList::new(),
            max_size,
        }
    }

    fn push(&mut self, message: Message) -> Result<(), &'static str> {
        if self.list.len() >= self.max_size {
            return Err("Queue overflow");
        }
        self.list.push_front(message);
        Ok(())
    }

    fn pop(&mut self) -> Option<Message> {
        self.list.pop_front()
    }

    fn lookup(&self, id: &str) -> Option<&Message> {
        for message in self.list.iter() {
            if message.id == id {
                return Some(message);
            }
        }
        None
    }

    fn expire(&mut self) {
        let thirty_seconds_ago = Instant::now() - Duration::from_secs(30);
        self.list.retain(|message| message.timestamp >= thirty_seconds_ago);
    }
}

fn main() {
    let queue = Arc::new(Mutex::new(MessageQueue::new(500)));

    // Spawn a thread to manage expiration
    let queue_clone = Arc::clone(&queue);
    thread::spawn(move || loop {
        thread::sleep(Duration::from_secs(5));
        let mut queue = queue_clone.lock().unwrap();
        queue.expire();
    });

    // Example message insertion and retrieval
    let message = Message {
        id: "msg1".to_string(),
        timestamp: Instant::now(),
    };

    {
        let mut queue = queue.lock().unwrap();
        queue.push(message).unwrap();
    }

    {
        let queue = queue.lock().unwrap();
        if let Some(msg) = queue.lookup("msg1") {
            println!("Found message with ID: {}", msg.id);
        } else {
            println!("Message not found");
        }
    }
}
