use std::time::{Duration, SystemTime};

const MAX_MESSAGES: usize = 500;
const MAX_AGE_SECONDS: u64 = 30;

#[derive(Debug, Clone)]
struct Message {
    id: u64,
    timestamp: SystemTime,
    content: String,
}

struct MessageQueue {
    queue: LinkedList<Message>,
}

impl MessageQueue {
    fn new() -> Self {
        Self {
            queue: LinkedList::new(),
        }
    }

    fn push(&mut self, message: Message) -> Result<(), &'static str> {
        self.cleanup();
        if self.queue.len() >= MAX_MESSAGES {
            return Err("Queue overflow");
        }

        self.queue.push_front(message);
        Ok(())
    }

    fn pop(&mut self) -> Option<Message> {
        self.cleanup();
        self.queue.pop_front()
    }

    fn get_by_id(&mut self, id: u64) -> Option<&Message> {
        self.cleanup();
        self.queue.iter().find(|&m| m.id == id)
    }

    fn cleanup(&mut self) {
        let now = SystemTime::now();
        self.queue.retain(|m| {
            match now.duration_since(m.timestamp) {
                Ok(age) => age.as_secs() < MAX_AGE_SECONDS,
                Err(_) => false,
            }
        });
    }
}

fn main() {
    let queue = Arc::new(Mutex::new(MessageQueue::new()));

    // Example usage in a multi-threaded context
    let queue_clone = Arc::clone(&queue);
    thread::spawn(move || {
        let message = Message {
            id: 1,
            timestamp: SystemTime::now(),
            content: "Hello World".to_string(),
        };

        let mut queue = queue_clone.lock().unwrap();
        match queue.push(message) {
            Ok(_) => println!("Message pushed"),
            Err(e) => println!("Error: {}", e),
        }
    });

    thread::sleep(Duration::from_secs(1));

    let queue_clone = Arc::clone(&queue);
    thread::spawn(move || {
        let mut queue = queue_clone.lock().unwrap();
        if let Some(message) = queue.pop() {
            println!("Popped message: {:?}", message);
        } else {
            println!("No message to pop");
        }
    });

    thread::sleep(Duration::from_secs(35));

    let queue_clone = Arc::clone(&queue);
    thread::spawn(move || {
        let mut queue = queue_clone.lock().unwrap();
        if let Some(message) = queue.get_by_id(1) {
            println!("Retrieved message: {:?}", message);
        } else {
            println!("No message with this ID");
        }
    });
}
