    queue: LinkedList<Message>,
    size_limit: usize,
}

impl MessageQueue {
    fn new(size_limit: usize) -> Self {
        Self {
            queue: LinkedList::new(),
            size_limit,
        }
    }

    fn push(&mut self, msg: Message) -> Result<(), &'static str> {
        if self.queue.len() >= self.size_limit {
            return Err("Queue overflow: Cannot add more messages.");
        }
        self.discard_old_messages();
        self.queue.push_front(msg);
        Ok(())
    }

