use std::collections::{HashMap, LinkedList};
use std::sync::{Arc, Mutex};
use std::time::{Duration, SystemTime};

#[derive(Clone, Debug)]
struct Message {
    id: String,
    timestamp: SystemTime,
}

struct MessageQueue {
    stack: LinkedList<Message>,
    map: HashMap<String, Message>,
    capacity: usize,
}

impl MessageQueue {
    fn new(capacity: usize) -> Self {
        MessageQueue {
            stack: LinkedList::new(),
            map: HashMap::new(),
            capacity,
        }
    }

    fn push(&mut self, message: Message) -> Result<(), &'static str> {
        if self.stack.len() >= self.capacity {
            return Err("Queue overflow");
        }
        if self.contains(&message.id) {
            return Err("Message with this ID already exists");
        }
        self.discard_old_messages();
        self.stack.push_back(message.clone());
        self.map.insert(message.id.clone(), message);
        Ok(())
    }

    fn pop(&mut self) -> Option<Message> {
        if let Some(message) = self.stack.pop_back() {
            self.map.remove(&message.id);
            Some(message)
        } else {
            None
        }
    }

    fn contains(&self, id: &String) -> bool {
        self.map.contains_key(id)
    }

    fn retrieve_by_id(&self, id: &String) -> Option<Message> {
        self.map.get(id).cloned()
    }

    fn discard_old_messages(&mut self) {
        let now = SystemTime::now();
        while let Some(msg) = self.stack.front() {
            if now.duration_since(msg.timestamp).unwrap_or(Duration::new(0, 0)) > Duration::new(30, 0) {
                self.stack.pop_front();
                self.map.remove(&msg.id);
            } else {
                break;
            }
        }
    }
}

fn main() {
    let queue = Arc::new(Mutex::new(MessageQueue::new(500)));

    // Example usage
    {
        let mut q = queue.lock().unwrap();
        let msg = Message {
            id: "msg1".to_string(),
            timestamp: SystemTime::now(),
        };
        q.push(msg).expect("Failed to push message");
    }

    {
        let mut q = queue.lock().unwrap();
        let retrieved = q.retrieve_by_id(&"msg1".to_string());
        println!("{:?}", retrieved);
    }

    {
        let mut q = queue.lock().unwrap();
        if let Some(popped) = q.pop() {
            println!("{:?}", popped);
        }
    }
}
