#include <iostream>
#include <unordered_set>
#include <mutex>

class CinemaReservationSystem {
private:
    std::unordered_set<int> bookedSeats;
    const int MAX_CAPACITY = 10000;
    std::mutex mtx;

public:
    bool reserveSeat(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (bookedSeats.size() >= MAX_CAPACITY) {
            throw std::runtime_error("Overbooking: Maximum capacity reached.");
        }
        if (bookedSeats.find(seatNumber) == bookedSeats.end()) {
            bookedSeats.insert(seatNumber);
            return true;
        }
        return false; // Seat already booked
    }

    bool cancelReservation(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (bookedSeats.find(seatNumber) != bookedSeats.end()) {
            bookedSeats.erase(seatNumber);
            return true;
        }
        return false; // Seat not found in reservations
    }

    bool isSeatAvailable(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        return bookedSeats.find(seatNumber) == bookedSeats.end();
    }
};

int main() {
    CinemaReservationSystem cinema;

    try {
        // Example usage:
        if (cinema.reserveSeat(100)) {
            std::cout << "Seat 100 reserved successfully.\n";
        } else {
            std::cout << "Seat 100 is already reserved.\n";
        }

        if (cinema.isSeatAvailable(101)) {
            std::cout << "Seat 101 is available.\n";
        }

        if (cinema.cancelReservation(100)) {
            std::cout << "Seat 100 reservation cancelled.\n";
        } else {
            std::cout << "Seat 100 was not reserved.\n";
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
