#include <iostream>
#include <stack>
#include <queue>
#include <string>
#include <unordered_map>
#include <vector>
#include <algorithm>

const int MAX_RESERVATIONS = 10000;

class Reservation {
public:
    std::string seatNumber;
    std::string customerName;

    Reservation(const std::string& seat, const std::string& customer) 
        : seatNumber(seat), customerName(customer) {}
};

// Comparator for priority queue to track frequently canceled seats.
struct CompareReservation {
    bool operator()(const Reservation& r1, const Reservation& r2) {
        return r1.seatNumber > r2.seatNumber; // Simple lexicographical comparison for demonstration
    }
};

// Cinema class to manage seat reservations
class Cinema {
private:
    std::stack<Reservation> reservationStack;
    std::priority_queue<Reservation, std::vector<Reservation>, CompareReservation> canceledReservations;
    std::unordered_map<std::string, bool> seatAvailability;

    void checkAvailability(const std::string& seatNumber) {
        if (seatAvailability.find(seatNumber) == seatAvailability.end() || seatAvailability[seatNumber]) {
            throw std::runtime_error("Seat is already reserved or does not exist.");
        }
    }

    void handleOverbooking() {
        if (reservationStack.size() >= MAX_RESERVATIONS) {
            throw std::runtime_error("Overbooking: Cannot exceed MAX_RESERVATIONS.");
        }
    }

public:
    Cinema(const std::vector<std::string>& seats) {
        for (const auto& seat : seats) {
            seatAvailability[seat] = false;
        }
    }

    void reserveSeat(const std::string& seatNumber, const std::string& customerName) {
        checkAvailability(seatNumber);
        handleOverbooking();

        reservationStack.push(Reservation(seatNumber, customerName));
        seatAvailability[seatNumber] = true;
    }

    void cancelReservation() {
        if (reservationStack.empty()) {
            throw std::runtime_error("No reservations to cancel.");
        }

        Reservation canceled = reservationStack.top();
        reservationStack.pop();
        canceledReservations.push(canceled);

        seatAvailability[canceled.seatNumber] = false;
    }

    void processReservations() {
        while (!reservationStack.empty()) {
            cancelReservation();
        }
    }

    void showCanceledReservations() {
        std::priority_queue<Reservation, std::vector<Reservation>, CompareReservation> tempQueue = canceledReservations;

        while (!tempQueue.empty()) {
            Reservation canceled = tempQueue.top();
            std::cout << "Canceled Reservation: " << canceled.seatNumber << " for " << canceled.customerName << std::endl;
            tempQueue.pop();
        }
    }
};

int main() {
    std::vector<std::string> seats = {"A1", "A2", "A3", "A4", "A5"};
    Cinema cinema(seats);

    try {
        cinema.reserveSeat("A1", "John Doe");
        cinema.reserveSeat("A2", "Jane Smith");
        cinema.cancelReservation();
        cinema.showCanceledReservations();
    } catch (const std::exception& e) {
        std::cerr << e.what() << std::endl;
    }

    return 0;
}
