#define MAX_RESERVATIONS 10000

struct Reservation {
    int seatNumber;
    std::string customerName;
};

class CinemaReservationSystem {
private:
    std::stack<Reservation> reservationsStack;
    std::priority_queue<int> canceledReservationsQueue;
    std::unordered_map<int, bool> seatAvailability; // true for available, false for booked

public:
    CinemaReservationSystem(int totalSeats) {
        for (int i = 1; i <= totalSeats; ++i) {
            seatAvailability[i] = true;
        }
    }

    void reserveSeat(int seatNumber, const std::string& customerName) {
        if (reservationsStack.size() >= MAX_RESERVATIONS) {
            throw std::overflow_error("Reservation limit exceeded.");
        }
        if (seatAvailability[seatNumber]) {
            reservationsStack.push({seatNumber, customerName});
            seatAvailability[seatNumber] = false;
            std::cout << "Reservation successful for seat " << seatNumber << " by " << customerName << ".\n";
        } else {
            std::cout << "Seat " << seatNumber << " is already booked.\n";
        }
    }

    void cancelReservation() {
        if (reservationsStack.empty()) {
            std::cout << "No reservations to cancel.\n";
            return;
        }
        Reservation lastReservation = reservationsStack.top();
        reservationsStack.pop();
        seatAvailability[lastReservation.seatNumber] = true;
        canceledReservationsQueue.push(lastReservation.seatNumber);
        std::cout << "Cancellation successful for seat " << lastReservation.seatNumber << ", reserved by " << lastReservation.customerName << ".\n";
    }

    void printCanceledSeatFrequency() {
        std::unordered_map<int, int> canceledFrequency;
        while (!canceledReservationsQueue.empty()) {
            int seat = canceledReservationsQueue.top();
            canceledReservationsQueue.pop();
            ++canceledFrequency[seat];
        }
        std::cout << "Frequently canceled seats:\n";
        for (const auto& entry : canceledFrequency) {
            std::cout << "Seat " << entry.first << " canceled " << entry.second << " times.\n";
        }
    }
};

int main() {
    CinemaReservationSystem cinema(100);

    try {
        cinema.reserveSeat(5, "John Doe");
        cinema.reserveSeat(5, "Alice");
        cinema.cancelReservation();
        cinema.cancelReservation();
        cinema.reserveSeat(10, "Bob Smith");
        cinema.reserveSeat(15, "Charlie Brown");
        cinema.cancelReservation();
        cinema.printCanceledSeatFrequency();
    } catch (const std::exception& e) {
        std::cerr << "Exception: " << e.what() << '\n';
    }

    return 0;
