import heapq
import datetime

class Task:
    def __init__(self, name, deadline):
        self.name = name
        self.deadline = deadline

    def __lt__(self, other):
        return self.deadline < other.deadline

class TaskManager:
    def __init__(self, capacity=50):
        self.capacity = capacity
        self.tasks = []
        heapq.heapify(self.tasks)

    def add_task(self, name, deadline):
        task = Task(name, deadline)
        if len(self.tasks) < self.capacity:
            heapq.heappush(self.tasks, task)
        else:
            if self.tasks[0].deadline > deadline:
                heapq.heapreplace(self.tasks, task)

    def pop_task(self):
        if self.tasks:
            return heapq.heappop(self.tasks)
        return None

    def replace_task(self, old_task, new_task):
        index = self.tasks.index(old_task)
        self.tasks[index] = new_task
        heapq.heapify(self.tasks)

    def get_tasks(self):
        return sorted(self.tasks)

# Example usage
if __name__ == "__main__":
    manager = TaskManager()
    manager.add_task("Task 1", datetime.datetime(2023, 10, 20))
    manager.add_task("Task 2", datetime.datetime(2023, 10, 18))

    print("Current tasks:")
    for task in manager.get_tasks():
        print(task.name, task.deadline)

    manager.pop_task()

    print("Tasks after popping one:")
    for task in manager.get_tasks():
        print(task.name, task.deadline)
