class Task:
    def __init__(self, name, priority):
        self.name = name
        self.priority = priority

class PriorityQueue:
    def __init__(self):
        self.queue = []
        self.capacity = 50

    def batch_initialize(self, tasks):
        if len(tasks) <= 10:
            for task in tasks:
                if len(self.queue) < self.capacity:
                    self.append(task)
        else:
            raise ValueError("Can only initialize with up to 10 tasks")

    def append(self, task):
        if len(self.queue) < self.capacity:
            self.queue.append(task)
            self.queue.sort(key=lambda x: x.priority, reverse=True)
        else:
            raise OverflowError("Priority queue has reached its capacity of 50 tasks")

    def pop(self):
        if self.queue:
            highest_priority_task = self.queue[0]
            self.queue = self.queue[1:]
            return highest_priority_task
        else:
            raise IndexError("Pop from empty priority queue")

    def count(self, priority_level):
        return sum(1 for task in self.queue if task.priority == priority_level)

# Example of batch initialization and usage:
tasks = [Task(f"Task {i}", i % 5) for i in range(10)]
pq = PriorityQueue()
pq.batch_initialize(tasks)

# Add a new task
pq.append(Task("New Task", 3))

# Remove the highest priority task
removed_task = pq.pop()

# Count the number of tasks with priority level 3
priority_count = pq.count(3)
