    private static final int MAX_TASKS = 200;
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());

    public TaskScheduler() {
        tasks = new TreeSet<>(Comparator.comparingInt(Task::getPriority).thenComparingInt(Task::getId));
    }

    public void addTask(int id, int priority) throws Exception {
        if (tasks.size() >= MAX_TASKS) {
            throw new Exception("Cannot add task: TreeSet is full!");
        }
        Task task = new Task(id, priority);
        tasks.add(task);
        logger.log(Level.INFO, "Task added: {0}", task);
    }

    public void removeTask(int id) throws Exception {
        Task taskToRemove = tasks.stream().filter(task -> task.getId() == id).findFirst()
                .orElseThrow(() -> new Exception("Task not found: ID=" + id));
        tasks.remove(taskToRemove);
        logger.log(Level.INFO, "Task removed: {0}", taskToRemove);
    }

    public Task fetchTask() throws Exception {
        if (tasks.isEmpty()) {
            throw new Exception("Cannot fetch task: TreeSet is empty!");
        }
        Task highestPriorityTask = tasks.first();
        tasks.remove(highestPriorityTask);
        logger.log(Level.INFO, "Task fetched: {0}", highestPriorityTask);
        return highestPriorityTask;
    }

    public int getTaskCount() {
        return tasks.size();
    }
}

