#include <iostream>
#include <vector>
#include <stdexcept>

struct Item {
    std::string name;
    int urgency;
};

class PriorityQueue {
    std::vector<Item> data;
    const int MAX_SIZE = 500;

    void heapifyUp(int index) {
        if (index <= 0) return;
        int parent = (index - 1) / 2;
        if (data[index].urgency > data[parent].urgency) {
            std::swap(data[index], data[parent]);
            heapifyUp(parent);
        }
    }

    void heapifyDown(int index) {
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        int largest = index;

        if (left < data.size() && data[left].urgency > data[largest].urgency)
            largest = left;

        if (right < data.size() && data[right].urgency > data[largest].urgency)
            largest = right;

        if (largest != index) {
            std::swap(data[index], data[largest]);
            heapifyDown(largest);
        }
    }

public:
    void push(const Item& item) {
        if (data.size() >= MAX_SIZE) {
            std::cerr << "Error: Priority queue is full." << std::endl;
            return;
        }
        data.push_back(item);
        heapifyUp(data.size() - 1);
    }

    void pop() {
        if (data.empty()) {
            std::cerr << "Error: Priority queue is empty." << std::endl;
            return;
        }
        std::swap(data.front(), data.back());
        data.pop_back();
        heapifyDown(0);
    }

    Item top() const {
        if (data.empty()) {
            throw std::runtime_error("Error: Priority queue is empty.");
        }
        return data.front();
    }

    void shift() {
        // Implement your shift operation to periodically check and adjust stock levels
        // This is a skeleton implementation and needs customization to fit sales patterns
        for (auto& item : data) {
            if (item.urgency > 0) item.urgency--; // Example shift operation
        }
        // Re-heapify the entire vector to maintain heap properties
        for (int i = data.size() / 2 - 1; i >= 0; --i) {
            heapifyDown(i);
        }
    }

    bool empty() const {
        return data.empty();
    }

    size_t size() const {
        return data.size();
    }
};

int main() {
