    // Example usage
    try {
        pq.push({"Laptop", 5});
        pq.push({"Smartphone", 10});
        pq.push({"Headphones", 3});

        std::cout << "Top item: " << pq.top().name << " with urgency " << pq.top().urgency << std::endl;

        pq.pop();
        std::cout << "Next top item: " << pq.top().name << " with urgency " << pq.top().urgency << std::endl;

