    fn new() -> Self {
        Library { entries: Vec::new() }
    }

    fn add_entry(&mut self, media: MediaType) -> Result<(), LibraryError> {
        if self.entries.len() >= 1000 {
            return Err(LibraryError::CollectionLimitReached);
        }
        match media {
            MediaType::Book(_) | MediaType::Movie(_) | MediaType::Music(_) => {
                self.entries.push(media);
                Ok(())
            }
            _ => Err(LibraryError::InvalidMediaType),
        }
    }

    fn update_entry(&mut self, index: usize, media: MediaType) -> Result<(), LibraryError> {
        if index >= self.entries.len() {
            return Err(LibraryError::InvalidMediaType);
        }
        match media {
            MediaType::Book(_) | MediaType::Movie(_) | MediaType::Music(_) => {
                self.entries.pop();
                self.entries.insert(index, media);
                Ok(())
            }
            _ => Err(LibraryError::InvalidMediaType),
        }
    }

    fn remove_entry(&mut self) -> Result<(), LibraryError> {
        if self.entries.is_empty() {
            return Err(LibraryError::InvalidMediaType);
        }
        self.entries.pop();
        Ok(())
    }
