        Library {
            collection: Vec::with_capacity(capacity),
            capacity,
        }
    }

    fn compress_collection(&mut self) {
        self.collection.shrink_to_fit();
    }

    fn add_media(&mut self, media: MediaType) -> Result<(), LibraryError> {
        if self.collection.len() >= self.capacity {
            return Err(LibraryError::ExceedsCapacity);
        }
        self.collection.push(media);

        if self.collection.len() % 100 == 0 {
