import java.util.HashSet;

public class StudentRecordManager {
    private HashSet<Student> studentRecords = new HashSet<>();
    private static final int MAX_RECORDS = 500;

    public boolean addStudent(Student student) {
        if (studentRecords.size() >= MAX_RECORDS) {
            System.out.println("Maximum student records reached. Cannot add more.");
            return false;
        }
        return studentRecords.add(student);
    }

    public boolean removeStudent(String studentId) {
        return studentRecords.removeIf(student -> student.getStudentId().equals(studentId));
    }

    public boolean containsStudent(String studentId) {
        return studentRecords.stream().anyMatch(student -> student.getStudentId().equals(studentId));
    }

    static class Student {
        private String studentId;
        private String name;
        private String grade;

        public Student(String studentId, String name, String grade) {
            this.studentId = studentId;
            this.name = name;
            this.grade = grade;
        }

        public String getStudentId() {
            return studentId;
        }

        public String getName() {
            return name;
        }

        public String getGrade() {
            return grade;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Student student = (Student) o;
            return studentId.equals(student.studentId);
        }

        @Override
        public int hashCode() {
            return studentId.hashCode();
        }
    }

    public static void main(String[] args) {
        StudentRecordManager manager = new StudentRecordManager();
        manager.addStudent(new Student("1", "John Doe", "A"));
        manager.addStudent(new Student("2", "Jane Smith", "B"));
        System.out.println(manager.containsStudent("1")); // true
        manager.removeStudent("1");
        System.out.println(manager.containsStudent("1")); // false
    }
}
