public class StudentRecordsManager {
    private HashSet<Student> studentsSet;
    private ArrayList<Student> studentsList;
    private LinkedList<Student> honorsList;
    private static final int MAX_STUDENTS = 500;
    private static final double HONORS_THRESHOLD = 90.0;

    public StudentRecordsManager() {
        studentsSet = new HashSet<>(100);
        studentsList = new ArrayList<>();
        honorsList = new LinkedList<>();
    }

    public boolean addStudent(Student student) {
        if (studentsSet.size() >= MAX_STUDENTS || studentsSet.contains(student)) {
            return false;
        }
        boolean added = studentsSet.add(student);
        if (added) {
            studentsList.add(student);
            if (student.getGrade() > HONORS_THRESHOLD) {
                honorsList.add(student);
            }
        }
        return added;
    }

    public boolean removeStudent(Student student) {
        if (!studentsSet.contains(student)) {
            return false;
        }
        boolean removed = studentsSet.remove(student);
        if (removed) {
            studentsList.remove(student);
            honorsList.remove(student);
        }
        return removed;
    }

    public boolean studentExists(String studentId) {
        for (Student student : studentsSet) {
            if (student.getStudentId().equals(studentId)) {
                return true;
            }
        }
        return false;
    }
