use smallvec::SmallVec;
use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct Task {
    priority: usize,
    description: String,
}

struct TaskManager {
    tasks: SmallVec<[Reverse<Task>; 200]>,
}

impl TaskManager {
    fn new() -> Self {
        TaskManager {
            tasks: SmallVec::new(),
        }
    }

    fn add_task(&mut self, task: Task) -> Result<(), &'static str> {
        if self.tasks.len() < self.tasks.capacity() {
            self.tasks.push(Reverse(task));
            Ok(())
        } else {
            Err("Task list is full. Cannot add more tasks.")
        }
    }

    fn pop_task(&mut self) -> Option<Task> {
        self.tasks.pop().map(|rev_task| rev_task.0)
    }

    fn update_task_priority<F>(&mut self, mut update_fn: F)
    where
        F: FnMut(&mut Task),
    {
        for rev_task in &mut self.tasks {
            update_fn(&mut rev_task.0);
        }
        self.tasks.sort_by(|a, b| a.cmp(b));
    }
}

fn main() {
    let mut manager = TaskManager::new();

    // Example usage
    manager.add_task(Task {
        priority: 1,
        description: "High priority task".to_string(),
    }).unwrap();

    manager.add_task(Task {
        priority: 5,
        description: "Low priority task".to_string(),
    }).unwrap();

    manager.update_task_priority(|task| {
        if task.description == "High priority task" {
            task.priority = 10;
        }
    });

    while let Some(task) = manager.pop_task() {
        println!("Processing task: {}", task.description);
    }
}
