            tasks: SmallVec::with_capacity(200).into_iter().collect(),
            smallvec_capacity: 200,
            completed_tasks: Vec::new(),
        }
    }

    fn add_task(&mut self, task: Task) -> Result<(), String> {
        if self.tasks.len() >= self.smallvec_capacity {
            return Err("Task queue overflow: Cannot add more tasks.".into());
        }
        self.tasks.push(task);
        Ok(())
    }

    fn update_task_priority(&mut self, task_description: &str, new_priority: u32) -> Result<(), String> {
        let mut found = false;
        let mut updated_tasks: BinaryHeap<Task> = BinaryHeap::new();

        while let Some(task) = self.tasks.pop() {
            if task.description == task_description {
                let updated_task = Task {
                    priority: new_priority,
                    description: task_description.to_string(),
                };
                updated_tasks.push(updated_task);
                found = true;
            } else {
                updated_tasks.push(task);
            }
        }

        self.tasks = updated_tasks;

        if found {
            Ok(())
        } else {
            Err("Task not found to update priority.".into())
        }
    }

    fn pop_task(&mut self) -> Option<Task> {
        self.tasks.pop().map(|task| {
            self.completed_tasks.push(task.clone());
            task
        })
    }
}

fn main() {
    let mut manager = TaskManager::new();

    // Example usage
    manager.add_task(Task {
        priority: 1,
        description: "Task 1".into(),
    }).unwrap();

    manager.update_task_priority("Task 1", 2).unwrap();

    let completed = manager.pop_task();
    println!("{:?}", completed);
    println!("{:?}", manager.completed_tasks);
}
