use smallvec::SmallVec;
use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct Task {
    id: usize,
    priority: usize,
}

pub struct TaskManager {
    queue: SmallVec<[Reverse<Task>; 200]>,
    completed_tasks: Vec<Task>,
    completed_count: usize,
}

impl TaskManager {
    pub fn new() -> Self {
        TaskManager {
            queue: SmallVec::new(),
            completed_tasks: Vec::new(),
            completed_count: 0,
        }
    }

    pub fn push(&mut self, task: Task) -> Result<(), &'static str> {
        if self.queue.len() < 200 {
            self.queue.push(Reverse(task));
            Ok(())
        } else {
            Err("Queue overflow: Cannot add more tasks.")
        }
    }

    pub fn pop(&mut self) -> Option<Task> {
        match self.queue.pop() {
            Some(Reverse(task)) => {
                self.completed_count += 1;
                self.completed_tasks.push(task.clone());
                Some(task)
            },
            None => None,
        }
    }

    pub fn update_priority(&mut self, task_id: usize, new_priority: usize) {
        for Reverse(task) in &mut self.queue {
            if task.id == task_id {
                task.priority = new_priority;
            }
        }
        self.queue.sort_by_key(|task| task.0.priority);
    }

    pub fn completed_task_count(&self) -> usize {
        self.completed_count
    }
}

fn main() {
    let mut manager = TaskManager::new();
    manager.push(Task { id: 1, priority: 2 }).ok();
    manager.push(Task { id: 2, priority: 1 }).ok();
    manager.update_priority(1, 3);

    while let Some(task) = manager.pop() {
        println!("Completed task: {}", task.id);
    }

    println!("Total completed tasks: {}", manager.completed_task_count());
}
