package main

import (
	"bufio"
	"fmt"
	"os"
	"sync"
)

type LRUCache struct {
	capacity int
	cache    map[string]*LRUNode
	head     *LRUNode
	tail     *LRUNode
	mutex    sync.Mutex
}

type LRUNode struct {
	key   string
	value int
	prev  *LRUNode
	next  *LRUNode
}

func NewLRUCache(capacity int) *LRUCache {
	return &LRUCache{
		capacity: capacity,
		cache:    make(map[string]*LRUNode),
		head:     nil,
		tail:     nil,
	}
}

func (lru *LRUCache) Get(key string) (int, bool) {
	lru.mutex.Lock()
	defer lru.mutex.Unlock()

	if node, exists := lru.cache[key]; exists {
		lru.moveToFront(node)
		return node.value, true
	}
	return 0, false
}

func (lru *LRUCache) Put(key string, value int) {
	lru.mutex.Lock()
	defer lru.mutex.Unlock()

	if node, exists := lru.cache[key]; exists {
		node.value += value
		lru.moveToFront(node)
	} else {
		node := &LRUNode{key: key, value: value}
		lru.cache[key] = node
		if len(lru.cache) > lru.capacity {
			delete(lru.cache, lru.tail.key)
			lru.removeNode(lru.tail)
		}
		lru.addToFront(node)
	}
}

func (lru *LRUCache) moveToFront(node *LRUNode) {
	lru.removeNode(node)
	lru.addToFront(node)
}

func (lru *LRUCache) addToFront(node *LRUNode) {
	node.prev = nil
	node.next = lru.head
	if lru.head != nil {
		lru.head.prev = node
	}
	lru.head = node
	if lru.tail == nil {
		lru.tail = node
	}
}

func (lru *LRUCache) removeNode(node *LRUNode) {
	if node.prev != nil {
		node.prev.next = node.next
	} else {
		lru.head = node.next
	}
	if node.next != nil {
		node.next.prev = node.prev
	} else {
		lru.tail = node.prev
	}
}

func processLogFiles(filePaths []string, lruCache *LRUCache, wg *sync.WaitGroup) {
	defer wg.Done()
	for _, filePath := range filePaths {
		file, err := os.Open(filePath)
		if err != nil {
			fmt.Printf("Failed to open file: %s\n", filePath)
			continue
		}
		defer file.Close()

		scanner := bufio.NewScanner(file)
		for scanner.Scan() {
			entry := scanner.Text()
			lruCache.Put(entry, 1)
		}

		if err := scanner.Err(); err != nil {
			fmt.Printf("Error reading file: %s\n", filePath)
		}
	}
}

func main() {
	filePaths := []string{"log1.txt", "log2.txt", "log3.txt"} // Sample file paths
	lruCache := NewLRUCache(20000)
	var wg sync.WaitGroup

	for _, filePath := range filePaths {
		wg.Add(1)
		go processLogFiles([]string{filePath}, lruCache, &wg)
	}

	wg.Wait()

	// Example: Access the cache
	value, exists := lruCache.Get("sample-log-entry")
	if exists {
		fmt.Printf("Log entry found with count: %d\n", value)
	} else {
		fmt.Println("Log entry not found")
	}
}
