type LRUCache struct {
	mutex  sync.Mutex
	capacity int
	cache   map[string]int
	order   []string
}

func NewLRUCache(cap int) *LRUCache {
	return &LRUCache{
		capacity: cap,
		cache:   make(map[string]int),
		order:   make([]string, 0, cap),
	}
}

func (lru *LRUCache) Increment(key string) {
	lru.mutex.Lock()
	defer lru.mutex.Unlock()
	if _, found := lru.cache[key]; found {
		lru.cache[key]++
		lru.moveToFront(key)
	} else {
		if len(lru.order) == lru.capacity {
			delete(lru.cache, lru.order[lru.capacity-1])
			lru.order = lru.order[:lru.capacity-1]
		}
		lru.cache[key] = 1
		lru.order = append([]string{key}, lru.order...)
	}
}

func (lru *LRUCache) moveToFront(key string) {
	for i, k := range lru.order {
		if k == key {
			copy(lru.order[1:], lru.order[:i])
			lru.order[0] = key
			break
		}
	}
}

func processLog(filePath string, cache *LRUCache, wg *sync.WaitGroup) {
	defer wg.Done()

	file, err := os.Open(filePath)
	if err != nil {
		fmt.Println("Error opening file:", err)
		return
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		line := scanner.Text()
		cache.Increment(line)
	}

