)

type LRUCache struct {
	mu       sync.Mutex
	entries  map[string]int
	capacity int
	order    []string
}

func NewLRUCache(initialSize, capacity int) *LRUCache {
	return &LRUCache{
		entries:  make(map[string]int, initialSize),
		capacity: capacity,
		order:    make([]string, 0, initialSize),
	}
}

func (lru *LRUCache) Access(key string) {
	lru.mu.Lock()
	defer lru.mu.Unlock()

	// Increment log count
	if _, exists := lru.entries[key]; exists {
		lru.entries[key]++
	} else {
		lru.entries[key] = 1
	}
	lru.updateOrder(key)

	// Evict LRU if capacity is exceeded
	if len(lru.entries) > lru.capacity {
		lru.evict()
	}
}

func (lru *LRUCache) updateOrder(key string) {
	// Remove the key if it exists to avoid duplication
	for i, k := range lru.order {
		if k == key {
			lru.order = append(lru.order[:i], lru.order[i+1:]...)
			break
		}
	}
	lru.order = append(lru.order, key)
}

func (lru *LRUCache) evict() {
	if len(lru.order) > 0 {
		evictKey := lru.order[0]
		lru.order = lru.order[1:]
		delete(lru.entries, evictKey)
	}
}

func processLogFile(filePath string, lru *LRUCache, wg *sync.WaitGroup) {
	defer wg.Done()

	file, err := os.Open(filePath)
	if err != nil {
		fmt.Printf("Error opening file %s: %v\n", filePath, err)
		return
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		logEntry := scanner.Text()
		lru.Access(logEntry)
	}

	if err := scanner.Err(); err != nil {
		fmt.Printf("Error reading file %s: %v\n", filePath, err)
	}
}

func main() {
	const initialSize = 1000
	const capacity = 20000

	lru := NewLRUCache(initialSize, capacity)
	var wg sync.WaitGroup

	logFiles := []string{"log1.txt", "log2.txt", "log3.txt"} // replace with actual log file paths

	for _, file := range logFiles {
		wg.Add(1)
		go processLogFile(file, lru, &wg)
	}

	wg.Wait()

