import (
	"bufio"
	"os"
	"sync"
)

// LogVector manages unique log entries with LRU eviction
type LogVector struct {
	sync.Mutex
	entries       map[string]int
	order         []string
	capacity      int
	resetThreshold int
}

// NewLogVector initializes the LogVector with given capacity
func NewLogVector(capacity int, resetThreshold int) *LogVector {
	return &LogVector{
		entries:       make(map[string]int, capacity),
		order:         make([]string, 0, capacity),
		capacity:      capacity,
		resetThreshold: resetThreshold,
	}
}

// Increment increments the count of a log entry
func (lv *LogVector) Increment(entry string) {
	lv.Lock()
	defer lv.Unlock()

	if count, exists := lv.entries[entry]; exists {
		lv.entries[entry] = count + 1
		if count+1 >= lv.resetThreshold {
			lv.entries[entry] = 0
		}
	} else {
		if len(lv.order) >= lv.capacity {
			oldest := lv.order[0]
			lv.order = lv.order[1:]
			delete(lv.entries, oldest)
		}
		lv.entries[entry] = 1
		lv.order = append(lv.order, entry)
	}
}

// Concurrently read and process log files
func processLogs(files []string, lv *LogVector, wg *sync.WaitGroup) {
	defer wg.Done()
	for _, file := range files {
		file, err := os.Open(file)
		if err != nil {
			continue
		}

		scanner := bufio.NewScanner(file)
		for scanner.Scan() {
			lv.Increment(scanner.Text())
		}
		file.Close()
	}
}

func main() {
	var wg sync.WaitGroup
	logVector := NewLogVector(20000, 100)

	files := []string{"logfile1.txt", "logfile2.txt", "logfile3.txt"}

	for _, file := range files {
		wg.Add(1)
		go processLogs([]string{file}, logVector, &wg)
	}

	wg.Wait()
}
