import queue

def floyd_warshall(graph, num_nodes):
    dist = [[float('inf')] * num_nodes for _ in range(num_nodes)]
    for u, v, w in graph:
        dist[u][v] = w

    q = queue.Queue(maxsize=1000)

    for i in range(num_nodes):
        dist[i][i] = 0
        q.put((i, i, 0))

    while not q.empty():
        batch_size = min(q.qsize(), 100)
        batch = []

        # Ensure never exceeds half capacity
        while len(batch) < batch_size and q.qsize() <= q.maxsize // 2:
            u, v, d = q.get()
            batch.append((u, v, d))

        for u, v, d in batch:
            for k in range(num_nodes):
                if dist[u][k] > dist[u][v] + dist[v][k]:
                    dist[u][k] = dist[u][v] + dist[v][k]
                    if q.qsize() < q.maxsize // 2:
                        q.put((u, k, dist[u][k]))

    return dist
