use arrayvec::ArrayVec;
use log::{error, info};
use std::collections::HashMap;

const MAX_EMPLOYEES: usize = 100;

// Employee data tuple (ID, scores)
type EmployeeData = (u32, Vec<f32>);

fn calculate_average(scores: &Vec<f32>) -> f32 {
    if scores.is_empty() {
        return 0.0;
    }
    scores.iter().sum::<f32>() / scores.len() as f32
}

fn process_employee_data(employee_data: ArrayVec<[EmployeeData; MAX_EMPLOYEES]>) -> HashMap<u32, f32> {
    let mut averages: HashMap<u32, f32> = HashMap::new();
    for (id, scores) in employee_data.iter() {
        if averages.contains_key(id) {
            error!("Duplicate data entry found for employee ID: {}", id);
        } else {
            let average_score = calculate_average(scores);
            averages.insert(*id, average_score);
            info!("Processed employee ID: {}, Average score: {}", id, average_score);
        }
    }
    averages
}

fn main() {
    env_logger::init(); // Initialize the logger

    let mut employee_data: ArrayVec<[EmployeeData; MAX_EMPLOYEES]> = ArrayVec::new();

    // Insert data for employees
    if employee_data.try_insert((101, vec![90.0, 85.5, 93.0])).is_err() {
        error!("Failed to insert data: Maximum capacity reached.");
