use log::{info, warn, error};

struct EmployeeProcessor {
    employees: ArrayVec<[(u32, Vec<u32>); 100]>,
}

impl EmployeeProcessor {
    fn new() -> Self {
        EmployeeProcessor {
            employees: ArrayVec::new(),
        }
    }

    fn insert(&mut self, employee_id: u32, scores: Vec<u32>) -> Result<(), &'static str> {
        if self.employees.len() >= 100 {
            error!("Cannot insert more than 100 employee entries.");
            return Err("Overflow error: Maximum number of employee entries reached.");
        }
        self.employees.push((employee_id, scores));
        info!("Inserted scores for employee ID: {}", employee_id);
        Ok(())
    }

    fn get(&self, employee_id: u32) -> Option<&Vec<u32>> {
        self.employees.iter().find(|&&(id, _)| id == employee_id).map(|&(_, ref scores)| scores)
    }

    fn remove(&mut self, employee_id: u32) -> bool {
        if let Some(pos) = self.employees.iter().position(|&(id, _)| id == employee_id) {
            self.employees.remove(pos);
            info!("Removed scores for employee ID: {}", employee_id);
            true
        } else {
            warn!("Employee ID {} not found for removal.", employee_id);
            false
        }
    }

    fn calculate_averages(&self) -> HashMap<u32, f32> {
        let mut averages = HashMap::new();
        for &(id, ref scores) in &self.employees {
            if scores.is_empty() {
                warn!("No scores found for employee ID {}", id);
                continue;
            }
            let average = scores.iter().copied().sum::<u32>() as f32 / scores.len() as f32;
            averages.insert(id, average);
            info!("Calculated average score for employee ID {}: {}", id, average);
        }
        averages
    }

    fn sort_by_employee_id(&mut self) {
        self.employees.sort_by_key(|&(id, _)| id);
        info!("Sorted employees by ID.");
    }
}

fn main() {
    env_logger::init();

    let mut processor = EmployeeProcessor::new();

    // Example usage
    if let Err(e) = processor.insert(1, vec![80, 90, 100]) {
        error!("{}", e);
    }
    if let Err(e) = processor.insert(2, vec![70, 85]) {
        error!("{}", e);
    }

    processor.sort_by_employee_id();
    let averages = processor.calculate_averages();

    for (id, avg) in averages {
        println!("Employee ID: {}, Average Score: {:.2}", id, avg);
    }
}
