use arrayvec::ArrayVec;
use std::collections::LinkedList;
use std::collections::HashMap;
use log::{info, warn};

fn main() {
    // Setup logger
    env_logger::init();

    const MAX_TUPLES: usize = 100;

    // Initialize the ArrayVec
    let mut employee_scores: ArrayVec<[(u32, Vec<u32>); MAX_TUPLES]> = ArrayVec::new();

    // Initialize LinkedList to track changes
    let mut change_history: LinkedList<String> = LinkedList::new();

    // Function to safely insert a tuple
    fn insert_tuple(av: &mut ArrayVec<[(u32, Vec<u32>); MAX_TUPLES]>, history: &mut LinkedList<String>, tuple: (u32, Vec<u32>)) -> Result<(), &str> {
        if av.try_push(tuple.clone()).is_err() {
            warn!("Cannot insert: Overflow error for employee ID {}", tuple.0);
            return Err("Overflow error");
        }
        history.push_back(format!("Inserted tuple: {:?}", tuple));
        info!("Inserted tuple: Employee ID {} with scores {:?}", tuple.0, tuple.1);
        Ok(())
    }

    // Function to get a tuple by employee ID
    fn get_tuple(av: &ArrayVec<[(u32, Vec<u32>); MAX_TUPLES]>, employee_id: u32) -> Option<[(u32, Vec<u32>); 1]> {
        av.iter().find(|&&(id, _)| id == employee_id).map(|&(id, ref scores)| [(id, scores.clone())])
    }

    // Function to remove a tuple by employee ID
    fn remove_tuple(av: &mut ArrayVec<[(u32, Vec<u32>); MAX_TUPLES]>, history: &mut LinkedList<String>, employee_id: u32) -> Option<(u32, Vec<u32>)> {
        let index = av.iter().position(|&(id, _)| id == employee_id)?;
        let removed_tuple = av.remove(index);
        history.push_back(format!("Removed tuple: {:?}", removed_tuple));
        info!("Removed tuple: Employee ID {}", removed_tuple.0);
        Some(removed_tuple)
    }

    // Function to calculate average scores per employee
    fn calculate_averages(av: &ArrayVec<[(u32, Vec<u32>); MAX_TUPLES]>) -> HashMap<u32, f64> {
        av.iter().map(|&(id, ref scores)| {
            let sum: u32 = scores.iter().sum();
            let count = scores.len();
            (id, sum as f64 / count as f64)
        }).collect()
    }

    // Function to sort the ArrayVec based on employee ID
    fn sort_by_id(av: &mut ArrayVec<[(u32, Vec<u32>); MAX_TUPLES]>) {
        av.sort_by_key(|&(id, _)| id);
    }

    // Example usage
    // Insert tuples
    let _ = insert_tuple(&mut employee_scores, &mut change_history, (101, vec![95, 87, 91]));
    let _ = insert_tuple(&mut employee_scores, &mut change_history, (102, vec![75, 82, 78]));

    // Remove a tuple
    let _ = remove_tuple(&mut employee_scores, &mut change_history, 102);

    // Sort tuples
    sort_by_id(&mut employee_scores);

    // Calculate averages
    let averages = calculate_averages(&employee_scores);
    info!("Average Scores: {:?}", averages);
}
