    for (int i = 0; i < 500 && i < 1000; ++i) {
        seen[i] = false;
    }

    for (auto num : nums) {
        // Use try-catch block for managing exceptions
        try {
            // Insert into map without exceeding size of 1000
            if (seen.size() < 1000) {
