class LimitedSizeDict:
    def __init__(self, capacity=500):
        self.capacity = capacity
        self.data = OrderedDict()

    def insert(self, key, value):
        if key in self.data:
            logging.info(f"Updating existing entry with key: {key}")
        if len(self.data) >= self.capacity and key not in self.data:
            self.data.popitem(last=False)
            logging.info("Evicted least recently used entry due to capacity limit.")
        self.data[key] = value
        self.data.move_to_end(key)
        logging.info(f"Inserted entry with key: {key}")

    def update(self, key, value):
        if key in self.data:
            self.data[key] = value
            self.data.move_to_end(key)
            logging.info(f"Updated entry with key: {key}")
        else:
            logging.error("Update failed. Key not found.")

    def delete(self, key):
        if key in self.data:
            del self.data[key]
            logging.info(f"Deleted entry with key: {key}")
        else:
            logging.error("Delete failed. Key not found.")

    def fetch(self, key):
        if key in self.data:
            self.data.move_to_end(key)
            return self.data[key]
        logging.error("Fetch failed. Key not found.")
        return None

