    void append(int data) {
        if (!head) {
            head = new Node(data);
            return;
        }
        Node* temp = head;
        while (temp->next)
            temp = temp->next;
        temp->next = new Node(data);
    }

    Node* detectLoopStart() {
        std::unordered_set<Node*> visited;
        Node* current = head;
        while (current) {
            if (visited.find(current) != visited.end()) {
                return current; // Loop detected
            }
            if (visited.size() >= 500) {
                visited.erase(visited.begin()); // Maintain set size within limits
            }
            visited.insert(current);
            current = current->next;
        }
        return nullptr; // No loop
    }

    int countNodesOutsideLoop() {
        std::unordered_set<Node*> visited;
        std::vector<Node*> nonLoopNodes;
        Node* current = head;
        Node* loopStart = detectLoopStart();

        while (current) {
            if (current == loopStart) break;
            nonLoopNodes.push_back(current);
            visited.insert(current);
            current = current->next;
        }

        return nonLoopNodes.size();
    }
};

