import java.util.HashMap;
import java.util.Stack;

public class StockAnalyzer {
    private Stack<Integer> priceStack;
    private HashMap<String, Integer> priceMap;
    private static final int MAX_CAPACITY = 500;
    private static final int WINDOW_SIZE = 30;

    public StockAnalyzer() {
        priceStack = new Stack<>();
        priceMap = new HashMap<>();
        priceMap.put("highest", Integer.MIN_VALUE);
        priceMap.put("lowest", Integer.MAX_VALUE);
    }

    public void addPrice(int price) {
        if (priceStack.size() >= MAX_CAPACITY) {
            priceStack.removeElementAt(0);
        }
        priceStack.push(price);
        updatePriceMap(price);
    }

    private void updatePriceMap(int price) {
        int highestPrice = priceMap.get("highest");
        int lowestPrice = priceMap.get("lowest");

        if (price > highestPrice) {
            priceMap.put("highest", price);
        }
        if (price < lowestPrice) {
            priceMap.put("lowest", price);
        }
    }

    public int computeGreatestProfit() {
        int maxProfit = 0;
        int minPrice = Integer.MAX_VALUE;

        for (Integer price : priceStack) {
            if (price < minPrice) {
                minPrice = price;
            } else {
                int profit = price - minPrice;
                if (profit > maxProfit) {
                    maxProfit = profit;
                }
            }
        }
        return maxProfit;
    }

    public void simulateRollingWindow(int currentDay) {
        if (currentDay % WINDOW_SIZE == 0) {
            clearStack();
        }
    }

    private void clearStack() {
        priceStack.clear();
        priceMap.put("highest", Integer.MIN_VALUE);
        priceMap.put("lowest", Integer.MAX_VALUE);
    }

    public static void main(String[] args) {
        StockAnalyzer analyzer = new StockAnalyzer();
        // Simulate adding prices and computing profit over 30 days.
        for (int day = 1; day <= 600; day++) {
            int randomPrice = (int) (Math.random() * 1000);
            analyzer.addPrice(randomPrice);
            if (day % WINDOW_SIZE == 0) {
                analyzer.simulateRollingWindow(day);
            }
        }

        int greatestProfit = analyzer.computeGreatestProfit();
        System.out.println("Greatest Profit Possible: " + greatestProfit);
    }
}
