use std::collections::BTreeMap;
use std::io;

struct MedianFinder {
    map: BTreeMap<i32, usize>,
    count: usize,
}

impl MedianFinder {
    fn new() -> Self {
        MedianFinder {
            map: BTreeMap::new(),
            count: 0,
        }
    }

    fn add_num(&mut self, num: i32) {
        *self.map.entry(num).or_insert(0) += 1;
        self.count += 1;
    }

    fn find_median(&self) -> Option<f32> {
        if self.count == 0 {
            return None;
        }

        let mut left_count = 0;
        let mut target1 = (self.count + 1) / 2;
        let mut target2 = self.count / 2 + 1;
        let mut median1 = None;
        let mut median2 = None;

        for (&key, &freq) in &self.map {
            left_count += freq;
            if median1.is_none() && left_count >= target1 {
                median1 = Some(key);
            }
            if median2.is_none() && left_count >= target2 {
                median2 = Some(key);
            }
            if median1.is_some() && median2.is_some() {
                break;
            }
        }

        Some((median1.unwrap() as f32 + median2.unwrap() as f32) / 2.0)
    }
}

fn main() {
    let mut finder = MedianFinder::new();
    let mut input = String::new();

    println!("Commands:");
    println!("1. Add an integer: add <number>");
    println!("2. Find median: median");
    println!("3. Exit: exit");

    loop {
        input.clear();
        io::stdin().read_line(&mut input).unwrap();
        let parts: Vec<&str> = input.trim().split_whitespace().collect();

        match parts.as_slice() {
            ["add", num] => {
                if let Ok(n) = num.parse::<i32>() {
                    finder.add_num(n);
                    println!("Number added.");
                } else {
                    println!("Invalid number.");
                }
            }
            ["median"] => {
                if let Some(median) = finder.find_median() {
                    println!("Current median: {}", median);
                } else {
                    println!("Stream is empty.");
                }
            }
            ["exit"] => break,
            _ => println!("Invalid command."),
        }
    }
}
