use std::collections::BTreeMap;
use std::io::{self, BufRead};

// Helper function to add an element to the BTreeMap with frequency handling
fn add_element(map: &mut BTreeMap<i32, usize>, num: i32) {
    *map.entry(num).or_insert(0) += 1;
}

// Function to find the median of the current element stream in the BTreeMap
fn find_median(map: &BTreeMap<i32, usize>, total_count: usize) -> f64 {
    let mut count = 0;
    let mut median_low = None;
    let mut median_high = None;

    for (&num, &freq) in map.iter() {
        count += freq;

        if median_low.is_none() && count >= (total_count + 1) / 2 {
            median_low = Some(num);
        }

        if count >= (total_count + 2) / 2 {
            median_high = Some(num);
            break;
        }
    }

    // Calculate median based on odd/even total count
    if total_count % 2 == 0 {
        (median_low.unwrap() as f64 + median_high.unwrap() as f64) / 2.0
    } else {
        median_high.unwrap() as f64
    }
}

