use std::collections::BTreeMap;
use std::io::{self, BufRead};

struct MedianFinder {
    left: BTreeMap<i32, usize>,
    right: BTreeMap<i32, usize>,
    left_count: usize,
    right_count: usize,
    total_count: usize,
}

impl MedianFinder {
    fn new() -> Self {
        MedianFinder {
            left: BTreeMap::new(),
            right: BTreeMap::new(),
            left_count: 0,
            right_count: 0,
            total_count: 0,
        }
    }

    fn add_num(&mut self, num: i32) {
        self.total_count += 1;

        if self.left_count == 0 || num <= *self.left.keys().last().unwrap() {
            self.left.entry(num).and_modify(|e| *e += 1).or_insert(1);
            self.left_count += 1;
        } else {
            self.right.entry(num).and_modify(|e| *e += 1).or_insert(1);
            self.right_count += 1;
        }

        self.balance();

        self.trim_excess();
    }

    fn balance(&mut self) {
        while self.left_count > self.right_count + 1 {
            if let Some((&num, _)) = self.left.iter().rev().next() {
                self.left.entry(num).and_modify(|e| *e -= 1);
                if *self.left.get(&num).unwrap() == 0 {
                    self.left.remove(&num);
                }
                self.left_count -= 1;

                self.right.entry(num).and_modify(|e| *e += 1).or_insert(1);
                self.right_count += 1;
            }
        }

        while self.right_count > self.left_count {
            if let Some((&num, _)) = self.right.iter().next() {
                self.right.entry(num).and_modify(|e| *e -= 1);
                if *self.right.get(&num).unwrap() == 0 {
                    self.right.remove(&num);
                }
                self.right_count -= 1;

                self.left.entry(num).and_modify(|e| *e += 1).or_insert(1);
                self.left_count += 1;
            }
        }
    }

    fn find_median(&self) -> f64 {
        if self.left_count == self.right_count {
            let left_max = *self.left.keys().last().unwrap() as f64;
            let right_min = *self.right.keys().next().unwrap() as f64;
            (left_max + right_min) / 2.0
        } else {
            *self.left.keys().last().unwrap() as f64
        }
    }

    fn trim_excess(&mut self) {
        while self.left_count > 1000 {
            if let Some((&num, &count)) = self.left.iter().next() {
                if count > 1 {
                    self.left.entry(num).and_modify(|e| *e -= 1);
                } else {
                    self.left.remove(&num);
                }
                self.left_count -= 1;
            }
        }

        while self.right_count > 1000 {
            if let Some((&num, &count)) = self.right.iter().rev().next() {
                if count > 1 {
                    self.right.entry(num).and_modify(|e| *e -= 1);
                } else {
                    self.right.remove(&num);
                }
                self.right_count -= 1;
            }
        }
    }
}

