    let stdin = io::stdin();
    let mut median_finder = MedianFinder::new();

    for line in stdin.lock().lines() {
        let num: i32 = line.unwrap().trim().parse().unwrap();
        median_finder.add_num(num);
        println!("Current median: {}", median_finder.find_median());
