struct MedianFinder {
    lower_half: BTreeMap<i32, i32>,
    upper_half: BTreeMap<i32, i32>,
    lower_count: usize, 
    upper_count: usize,
}

impl MedianFinder {
    pub fn new() -> Self {
        MedianFinder {
            lower_half: BTreeMap::new(),
            upper_half: BTreeMap::new(),
            lower_count: 0,
            upper_count: 0,
        }
    }

    pub fn insert(&mut self, num: i32) {
        if self.lower_count == 0 || num <= *self.lower_half.iter().next_back().unwrap().0 {
            *self.lower_half.entry(num).or_insert(0) += 1;
            self.lower_count += 1;
        } else {
            *self.upper_half.entry(num).or_insert(0) += 1;
            self.upper_count += 1;
        }
        self.rebalance();
        self.restrict_size();
    }

    pub fn find_median(&self) -> f64 {
        if self.lower_count > self.upper_count {
            *self.lower_half.iter().next_back().unwrap().0 as f64
        } else {
            (*self.lower_half.iter().next_back().unwrap().0 + 
             *self.upper_half.iter().next().unwrap().0) as f64 / 2.0
        }
    }

    fn rebalance(&mut self) {
        if self.lower_count > self.upper_count + 1 {
            let (val, count) = self.lower_half.iter().next_back().unwrap();
            *self.lower_half.get_mut(val).unwrap() -= 1;
            if *self.lower_half.get(val).unwrap() == 0 {
                self.lower_half.remove(val);
            }
            *self.upper_half.entry(*val).or_insert(0) += 1;
            self.lower_count -= 1;
            self.upper_count += 1;
        }

        if self.upper_count > self.lower_count {
            let (val, count) = self.upper_half.iter().next().unwrap();
            *self.upper_half.get_mut(val).unwrap() -= 1;
            if *self.upper_half.get(val).unwrap() == 0 {
                self.upper_half.remove(val);
            }
            *self.lower_half.entry(*val).or_insert(0) += 1;
            self.upper_count -= 1;
            self.lower_count += 1;
        }
    }

    fn restrict_size(&mut self) {
        while self.lower_half.len() > 1000 {
            let (val, count) = self.lower_half.iter().next().unwrap();
            *self.lower_half.get_mut(val).unwrap() -= 1;
            if *self.lower_half.get(val).unwrap() == 0 {
                self.lower_half.remove(val);
            }
            self.lower_count -= 1;
        }
        while self.upper_half.len() > 1000 {
            let (val, count) = self.upper_half.iter().next_back().unwrap();
            *self.upper_half.get_mut(val).unwrap() -= 1;
            if *self.upper_half.get(val).unwrap() == 0 {
                self.upper_half.remove(val);
            }
            self.upper_count -= 1;
        }
    }
