use std::io::{self, BufRead};

struct MedianFinder {
    map: BTreeMap<i32, usize>,
    buffer: VecDeque<i32>,
    count: usize,
}

impl MedianFinder {
    fn new() -> Self {
        MedianFinder {
            map: BTreeMap::new(),
            buffer: VecDeque::new(),
            count: 0,
        }
    }

    fn add_num(&mut self, num: i32) {
        self.buffer.push_back(num);
        if self.buffer.len() > 5000 {
            self.buffer.pop_front();
        }
        while !self.buffer.is_empty() && self.count < 2000 {
            let n = self.buffer.pop_front().unwrap();
            *self.map.entry(n).or_insert(0) += 1;
            self.count += 1;
        }
    }

    fn find_median(&self) -> Option<f32> {
        if self.count == 0 {
            return None;
        }

        let half = self.count / 2;
        let mut sum = 0;
        let mut first = None;
        let mut second = None;

        for (&key, &val) in self.map.iter() {
            sum += val;
            if first.is_none() && sum > half {
                first = Some(key);
            }
            if sum >= half + 1 {
                second = Some(key);
                break;
            }
        }

        match (first, second) {
            (Some(f), Some(s)) => Some((f + s) as f32 / 2.0),
            (Some(f), None) => Some(f as f32),
            _ => None,
        }
    }
}

