use std::collections::{BTreeMap, VecDeque};
use std::io::{self, BufRead};

struct MedianFinder {
    btree: BTreeMap<i32, i32>,
    buffer: VecDeque<i32>,
    max_size: usize,
}

impl MedianFinder {
    fn new(max_size: usize) -> Self {
        MedianFinder {
            btree: BTreeMap::new(),
            buffer: VecDeque::new(),
            max_size,
        }
    }

    fn add_num(&mut self, num: i32) {
        self.buffer.push_back(num);

        if self.buffer.len() > self.max_size {
            if let Some(front) = self.buffer.pop_front() {
                *self.btree.entry(front).or_insert(0) += 1;
                self.buffer.push_back(num);
            }
        }

        if self.btree.len() > 2000 {
            let smallest_key = *self.btree.keys().next().unwrap();
            let count = self.btree.get_mut(&smallest_key).unwrap();
            *count -= 1;
            if *count == 0 {
                self.btree.remove(&smallest_key);
            }
        }
    }

    fn find_median(&self) -> f64 {
        let mut total_count = 0;
        for &count in self.btree.values() {
            total_count += count;
        }

        let mut mid1 = total_count / 2;
        let mut mid2 = mid1;
        if total_count % 2 == 0 {
            mid2 -= 1;
        }

        let mut keys_iter = self.btree.iter();
        let mut current_count = 0;
        let mut med1 = 0;
        let mut med2 = 0;

        for (&key, &count) in keys_iter {
            current_count += count;
            if med1 == 0 && current_count > mid1 {
                med1 = key;
            }
            if med2 == 0 && current_count > mid2 {
                med2 = key;
                break;
            }
        }

        (med1 as f64 + med2 as f64) / 2.0
    }
}

fn main() {
    let stdin = io::stdin();
    let mut median_finder = MedianFinder::new(5000);

    for line in stdin.lock().lines() {
        let num: i32 = line.unwrap().parse().unwrap();
        median_finder.add_num(num);
        let median = median_finder.find_median();
        println!("Current median: {}", median);
    }
}
