func (list *LinkedList) append(value float64) {
	newNode := &Node{value: value}
	if list.tail == nil {
		list.head = newNode
		list.tail = newNode
	} else {
		list.tail.next = newNode
		list.tail = newNode
	}
	list.size++
}

func (list *LinkedList) removeFirst() float64 {
	if list.head == nil {
		return 0
	}
	value := list.head.value
	list.head = list.head.next
	if list.head == nil {
		list.tail = nil
	}
	list.size--
	return value
}

func (list *LinkedList) calculateAverage() float64 {
	if list.size == 0 {
		return 0
	}
	sum := 0.0
	count := 0
	for node := list.head; node != nil; node = node.next {
		sum += node.value
		count++
	}
	return sum / float64(count)
}

