// LinkedListNode represents a node in the linked list
type LinkedListNode struct {
	value float64
	next  *LinkedListNode
}

// LinkedList represents a simple linked list
type LinkedList struct {
	head *LinkedListNode
	tail *LinkedListNode
	size int
}

// Append adds a new value to the end of the linked list
func (ll *LinkedList) Append(value float64) {
	newNode := &LinkedListNode{value: value}
	if ll.tail == nil {
		ll.head = newNode
		ll.tail = newNode
	} else {
		ll.tail.next = newNode
		ll.tail = newNode
	}
	ll.size++
}

// RemoveFirst removes the first element from the linked list
func (ll *LinkedList) RemoveFirst() float64 {
	if ll.head == nil {
		return 0
	}
	value := ll.head.value
	ll.head = ll.head.next
	if ll.head == nil {
		ll.tail = nil
	}
	ll.size--
	return value
}

// Queue represents a FIFO queue based on linked list
type Queue struct {
	ll *LinkedList
}

// Enqueue adds an element to the queue
func (q *Queue) Enqueue(value float64) {
	q.ll.Append(value)
}

// Dequeue removes an element from the queue
func (q *Queue) Dequeue() float64 {
	return q.ll.RemoveFirst()
}

// RollingAverage computes the rolling average of stock prices
func RollingAverage(priceChannel <-chan float64, resultChannel chan<- float64, wg *sync.WaitGroup) {
	defer wg.Done()

	var sum float64
	bufferedPrices := make([]float64, 0, 1000)
	linkedList := &LinkedList{}

	for price := range priceChannel {
		if len(bufferedPrices) == 1000 {
			removed := linkedList.RemoveFirst()
			sum -= removed
			bufferedPrices = bufferedPrices[1:]
		}

		linkedList.Append(price)
		bufferedPrices = append(bufferedPrices, price)
		sum += price

		if len(bufferedPrices) == 1000 {
			average := sum / 1000
			resultChannel <- average
		}
	}
}

func main() {
	priceChannel := make(chan float64, 1000)
	resultChannel := make(chan float64, 1000)
	var wg sync.WaitGroup

	wg.Add(1)
	go RollingAverage(priceChannel, resultChannel, &wg)

	// Example values being sent to priceChannel
	go func() {
		for i := 0; i < 5000; i++ {
			priceChannel <- float64(i) // Simulated stock price data
		}
		close(priceChannel)
	}()

	// Collect results
	go func() {
		wg.Wait()
		close(resultChannel)
	}()

	for avg := range resultChannel {
		fmt.Printf("Rolling Average: %.2f\n", avg)
	}
}
