	CurrentlyIssued bool
}

// Library struct holding the books slice and genre map.
type Library struct {
	Books  []Book
	Genres map[string][]Book
}

// AddBook adds a new book to the library.
func (lib *Library) AddBook(book Book, genre string) {
	if len(lib.Books) >= 800 {
		fmt.Println("Cannot add more books, library is full.")
		return
	}
	lib.Books = append(lib.Books, book)
	lib.Genres[genre] = append(lib.Genres[genre], book)
}

// RemoveBook removes a book from the library by title.
func (lib *Library) RemoveBook(title string) {
	for i, b := range lib.Books {
		if b.Title == title {
			lib.Books = append(lib.Books[:i], lib.Books[i+1:]...)
			break
		}
	}
	// Also remove from genres
	for genre, books := range lib.Genres {
		for i, b := range books {
			if b.Title == title {
				lib.Genres[genre] = append(books[:i], books[i+1:]...)
				break
			}
		}
	}
}

// UpdateBookStatus updates the issued status of a book by title.
func (lib *Library) UpdateBookStatus(title string, issued bool) {
	for i := range lib.Books {
		if lib.Books[i].Title == title {
			lib.Books[i].CurrentlyIssued = issued
			break
		}
	}
}

// RetrieveBook retrieves book details by title.
func (lib *Library) RetrieveBook(title string) {
	for _, b := range lib.Books {
		if b.Title == title {
			fmt.Printf("Title: %s, Author: %s, Year: %d, Issued: %t\n", b.Title, b.Author, b.Year, b.CurrentlyIssued)
			return
		}
	}
	fmt.Println("Book not found.")
}

func main() {
	lib := Library{
		Books:  make([]Book, 0, 800),
		Genres: make(map[string][]Book),
	}

	book1 := Book{Title: "The Hobbit", Author: "J.R.R. Tolkien", Year: 1937, CurrentlyIssued: false}
	lib.AddBook(book1, "Fantasy")

	book2 := Book{Title: "1984", Author: "George Orwell", Year: 1949, CurrentlyIssued: true}
	lib.AddBook(book2, "Dystopian")

	lib.RetrieveBook("The Hobbit")
	lib.UpdateBookStatus("1984", false)
	lib.RemoveBook("1984")
	lib.RetrieveBook("1984")
}
