import threading
import queue
import time

class LogProcessor:
    def __init__(self):
        self.log_queue = queue.Queue()
        self.lock = threading.Lock()

    def process_logs(self):
        while True:
            try:
                log_message = self.log_queue.get(timeout=1)
                self.lock.acquire()
                print(f"Processing: {log_message}")
                time.sleep(0.1)  # Simulate log processing
                self.lock.release()
                self.log_queue.task_done()
            except queue.Empty:
                break

    def add_log(self, message):
        self.log_queue.put(message)

def main():
    log_processor = LogProcessor()
    num_threads = 5
    threads = []

    for i in range(num_threads):
        thread = threading.Thread(target=log_processor.process_logs)
        thread.start()
        threads.append(thread)

    for i in range(1000):
        log_processor.add_log(f"Log message {i}")

    for thread in threads:
        thread.join()

if __name__ == "__main__":
    main()
