void generatePermutations(std::vector<int>& nums, std::vector<int>& perm, std::set<std::vector<int>>& uniquePerms, std::vector<bool>& used) {
    if (perm.size() == nums.size()) {
        uniquePerms.insert(perm);
        return;
    }

    for (size_t i = 0; i < nums.size(); ++i) {
        if (!used[i]) {
            used[i] = true;
            perm.push_back(nums[i]);
            generatePermutations(nums, perm, uniquePerms, used);
            perm.pop_back();
            used[i] = false;
        }
    }
}

