    result.clear();  // Clear vector before populating to ensure no overflow

    for (const auto& p : uniquePerms) {
        result.push_back(p);
    }

    for (const auto& v : result) {
        for (int num : v) {
            std::cout << num << " ";
        }
        std::cout << std::endl;
