void generatePermutations(std::vector<int>& nums, std::vector<int>& current, std::unordered_set<std::string>& seen, std::stack<int>& stack) {
    if (current.size() == nums.size()) {
        std::string key;
        for (int num : current) {
            key += std::to_string(num) + ",";
        }
        if (seen.find(key) == seen.end()) {
            seen.insert(key);
            for (int num : current) {
                std::cout << num << " ";
            }
            std::cout << std::endl;
        }
        return;
    }

    for (size_t i = 0; i < nums.size(); ++i) {
        if (stack.count(i)) // Use stack to store indices used
            continue;

        stack.push(i);
        current.push_back(nums[i]);

        if (current.size() <= 1500) {
            generatePermutations(nums, current, seen, stack);
        }

        current.pop_back();
        stack.pop();
    }
}

