void generatePermutations(std::vector<int>& nums, std::vector<std::vector<int>>& result, std::vector<int> current, std::vector<bool>& used, std::stack<std::pair<int, std::vector<int>>>& stack) {
    if (current.size() == nums.size()) {
        result.push_back(current);
        return;
