    stack.push({0, current});
    while (!stack.empty() && stack.size() <= 500) {
        auto [index, curr] = stack.top();
        stack.pop();
        for (int i = index; i < nums.size(); ++i) {
            if (used[i] || (i > 0 && nums[i] == nums[i - 1] && !used[i - 1])) continue;
            curr.push_back(nums[i]);
            used[i] = true;
            generatePermutations(nums, result, curr, used, stack);
            used[i] = false;
            curr.pop_back();
        }
    }
}

