        this.timestamp = timestamp;
    }

    @Override
    public String toString() {
        return "Alert{" +
               "severity=" + severity +
               ", timestamp=" + timestamp +
               '}';
    }
}

class AlertComparator implements Comparator<Alert> {
    @Override
    public int compare(Alert a1, Alert a2) {
        return Integer.compare(a2.severity, a1.severity);  // reverse order for severity
    }
}

public class EmergencyAlertSystem {
    private PriorityQueue<Alert> alertQueue;

    public EmergencyAlertSystem() {
        alertQueue = new PriorityQueue<>(10, new AlertComparator());
    }

    public void addAlert(int severity, long timestamp) {
        if (alertQueue.size() < 10) {
            alertQueue.add(new Alert(severity, timestamp));
        } else {
            System.out.println("Maximum alert capacity reached.");
        }
    }

    public Alert peekAlert() {
        return alertQueue.peek();
    }

    public Alert processAlert() {
        return alertQueue.poll();
    }

    public void displayAlerts() {
        PriorityQueue<Alert> tempQueue = new PriorityQueue<>(alertQueue);
        while (!tempQueue.isEmpty()) {
            System.out.println(tempQueue.poll());
        }
    }

    public static void processEmergencyAlerts() {
        EmergencyAlertSystem system = new EmergencyAlertSystem();
        system.addAlert(5, System.currentTimeMillis());
        system.addAlert(2, System.currentTimeMillis());
        system.addAlert(8, System.currentTimeMillis());

        System.out.println("Alerts in the system:");
        system.displayAlerts();

        System.out.println("\nProcessing alert:");
        System.out.println(system.processAlert());

        System.out.println("\nCurrent top alert:");
        System.out.println(system.peekAlert());

        System.out.println("\nAlerts after processing:");
        system.displayAlerts();
    }

