    public int compareTo(EmergencyAlert other) {
        return Integer.compare(other.severity, this.severity);
    }

    @Override
    public String toString() {
        return "Severity: " + severity + ", Timestamp: " + timestamp;
    }
}

public class EmergencyAlertSystem {
    private PriorityQueue<EmergencyAlert> alertQueue;
    private ArrayList<EmergencyAlert> processedAlerts;

