            alertQueue.add(alert);
        } else {
            System.out.println("PriorityQueue is full. Cannot add more alerts.");
        }
    }

    public void processAlerts() {
        while (!alertQueue.isEmpty()) {
            EmergencyAlert alert = alertQueue.poll();
            System.out.println("Processing alert: " + alert);
            processedAlerts.add(alert);
        }
    }

    public void peekAlert() {
        EmergencyAlert alert = alertQueue.peek();
        if (alert != null) {
            System.out.println("Next alert to process: " + alert);
        } else {
            System.out.println("No alerts to process.");
        }
    }
