class ScoreStack {
private:
    std::stack<int> scores;
    static const size_t MAX_SIZE = 10;

public:
    void loadHighScores(const std::vector<int>& initialScores) {
        for (int score : initialScores) {
            pushScore(score);
        }
        sortScores();
    }

    void pushScore(int score) {
        if (scores.size() < MAX_SIZE) {
            scores.push(score);
        }
    }

    void sortScores() {
        std::vector<int> scoresVector;
        while (!scores.empty()) {
            scoresVector.push_back(scores.top());
            scores.pop();
        }
        std::sort(scoresVector.begin(), scoresVector.end(), std::greater<int>());
        for (int sortedScore : scoresVector) {
            scores.push(sortedScore);
        }
    }

    bool searchScore(int score) const {
        std::stack<int> tempStack = scores;
        while (!tempStack.empty()) {
            if (tempStack.top() == score) {
                return true;
            }
            tempStack.pop();
        }
        return false;
    }

    void printScores() const {
        std::stack<int> tempStack = scores;
        while (!tempStack.empty()) {
            std::cout << tempStack.top() << std::endl;
            tempStack.pop();
        }
    }
};

