    std::stack<int> highScores;
    std::vector<int> topScoresVec;
    const static size_t MAX_SIZE = 10;

public:
    void loadHighScores(const std::vector<int>& scores) {
        for (int score : scores) {
            if (highScores.size() < MAX_SIZE) {
                highScores.push(score);
            } else {
                std::cout << "Stack is full, cannot add more scores." << std::endl;
                break;
            }
        }
        sortHighScores();
    }

    void sortHighScores() {
        std::vector<int> tempVec;
        while (!highScores.empty()) {
            tempVec.push_back(highScores.top());
            highScores.pop();
        }
        std::sort(tempVec.begin(), tempVec.end(), std::greater<int>());
        for (int score : tempVec) {
            highScores.push(score);
        }
    }

    bool searchScore(int score) {
        std::vector<int> tempVec;
        while (!highScores.empty()) {
            if (highScores.top() == score) {
                return true;
            }
            tempVec.push_back(highScores.top());
            highScores.pop();
        }
        for (int scr : tempVec) {
            highScores.push(scr);
        }
        return false;
    }

    void addNewScore(int score) {
        if (highScores.size() < MAX_SIZE) {
            highScores.push(score);
            sortHighScores();
        } else {
            std::cout << "Stack is full, cannot add more scores." << std::endl;
        }
    }

    void moveTopScoreToVector() {
        if (!highScores.empty()) {
            topScoresVec.push_back(highScores.top());
            highScores.pop();
        }
    }

    void insertScoreInVector(int score, size_t position) {
        if (position <= topScoresVec.size()) {
            topScoresVec.insert(topScoresVec.begin() + position, score);
        } else {
            std::cout << "Invalid position." << std::endl;
        }
    }

    void printVectorScores() {
        for (int score : topScoresVec) {
            std::cout << score << " ";
        }
        std::cout << std::endl;
    }
};

