package main

import (
	"fmt"
	"sync"
	"time"
)

type StockPriceList struct {
	prices []float64
}

func (s *StockPriceList) Append(price float64) {
	if len(s.prices) >= 50 {
		s.prices = s.prices[1:] // Remove oldest price
	}
	s.prices = append(s.prices, price)
}

func (s *StockPriceList) Average() float64 {
	var sum float64
	for _, price := range s.prices {
		sum += price
	}
	return sum / float64(len(s.prices))
}

type Node struct {
	ticker string
	prices StockPriceList
	next   *Node
}

type TickerMap struct {
	head *Node
	size int
	lock sync.RWMutex
}

func (m *TickerMap) AddTicker(ticker string) *Node {
	m.lock.Lock()
	defer m.lock.Unlock()
	if m.size >= 100 {
		return nil // Limit reached
	}
	newNode := &Node{ticker: ticker}
	if m.head == nil {
		m.head = newNode
	} else {
		current := m.head
		for current.next != nil {
			current = current.next
		}
		current.next = newNode
	}
	m.size++
	return newNode
}

func (m *TickerMap) GetTickerNode(ticker string) *Node {
	m.lock.RLock()
	defer m.lock.RUnlock()
	current := m.head
	for current != nil {
		if current.ticker == ticker {
			return current
		}
		current = current.next
	}
	return nil
}

func streamStockQuotes(tickerMap *TickerMap, ticker string, priceStream <-chan float64) {
	node := tickerMap.AddTicker(ticker)
	if node == nil {
		fmt.Println("Ticker limit reached, cannot add", ticker)
		return
	}

	for price := range priceStream {
		node.prices.Append(price)
		time.Sleep(100 * time.Millisecond)
		fmt.Printf("Ticker: %s, Average Price: %f\n", ticker, node.prices.Average())
	}
}

func main() {
	tickerMap := &TickerMap{}

	tickers := []string{"AAPL", "TSLA", "GOOGL"}
	priceStreams := make([]chan float64, len(tickers))

	// Start goroutines for each ticker
	for i, ticker := range tickers {
		priceStreams[i] = make(chan float64)
		go streamStockQuotes(tickerMap, ticker, priceStreams[i])
	}

	// Simulate price updates
	go func() {
		for {
			priceStreams[0] <- 150.0 + float64(time.Now().Unix()%10) // AAPL
			priceStreams[1] <- 650.0 + float64(time.Now().Unix()%15) // TSLA
			priceStreams[2] <- 2800.0 + float64(time.Now().Unix()%20) // GOOGL
			time.Sleep(500 * time.Millisecond)
		}
	}()

	// Run indefinitely
	select {}
