use std::collections::{BTreeMap, BinaryHeap};
use std::cmp::Reverse;

struct InventoryManager {
    inventory: BTreeMap<u32, i32>,
    priority_queue: BinaryHeap<Reverse<(i32, u32)>>,
}

impl InventoryManager {
    fn new() -> Self {
        InventoryManager {
            inventory: BTreeMap::new(),
            priority_queue: BinaryHeap::new(),
        }
    }

    fn track_inventory_changes(&mut self, product_id: u32, change: i32) {
        if let Some(existing_change) = self.inventory.get(&product_id) {
            let new_change = existing_change + change;
            if new_change == 0 {
                self.inventory.remove(&product_id);
            } else {
                self.inventory.insert(product_id, new_change);
            }
        } else if self.inventory.len() < 100 {
            self.inventory.insert(product_id, change);
        }

        // Update the priority queue for restocking
        self.priority_queue.clear();
        for (&id, &change) in &self.inventory {
            self.priority_queue.push(Reverse((change, id)));
        }
    }

    fn get_sorted_inventory(&self) -> Vec<(u32, i32)> {
        self.inventory.iter().map(|(&id, &change)| (id, change)).collect()
    }

    fn get_restock_priority(&self) -> Vec<u32> {
        self.priority_queue
            .iter()
            .map(|&Reverse((_, id))| id)
            .collect()
    }
}
