std::unordered_set<int> detectDuplicateErrors(const std::vector<int>& errorCodes) {
    std::unordered_set<int> seenErrors(10);
    std::unordered_set<int> duplicateErrors(10);
    std::vector<int> recentDuplicates(5);

    // Analyze error codes
    for (int code : errorCodes) {
        if (seenErrors.find(code) != seenErrors.end()) {
            if (duplicateErrors.find(code) == duplicateErrors.end()) {
                duplicateErrors.insert(code);

                // Maintain most recent 5 duplicates
                if (recentDuplicates.size() >= 5) {
                    recentDuplicates.erase(recentDuplicates.begin());
                }
                recentDuplicates.push_back(code);
            }
        } else {
            seenErrors.insert(code);
        }
    }

    // Output count
    std::cout << "Unique duplicate error codes count: " << duplicateErrors.size() << std::endl;

    // Just to verify functionality
    std::cout << "Most recent 5 duplicate error codes: ";
    for (int code : recentDuplicates) {
        std::cout << code << " ";
    }
    std::cout << std::endl;

    return duplicateErrors;
}
