use std::collections::{BTreeSet, LinkedList};

struct VisitorTracker {
    unique_visitors: BTreeSet<String>,
    order_of_insertion: LinkedList<String>,
    max_capacity: usize,
}

impl VisitorTracker {
    fn new(max_capacity: usize) -> VisitorTracker {
        VisitorTracker {
            unique_visitors: BTreeSet::new(),
            order_of_insertion: LinkedList::new(),
            max_capacity,
        }
    }

    fn track_unique_visitors(&mut self, ids: Vec<String>) {
        for id in ids {
            if self.unique_visitors.len() < self.max_capacity {
                if self.unique_visitors.insert(id.clone()) {
                    self.order_of_insertion.push_back(id);
                }
            } else if !self.unique_visitors.contains(&id) {
                if let Some(front_id) = self.order_of_insertion.pop_front() {
                    self.unique_visitors.remove(&front_id);
                }
                self.unique_visitors.insert(id.clone());
                self.order_of_insertion.push_back(id);
            }
        }
    }

    fn display_unique_count(&self) -> usize {
        self.unique_visitors.len()
    }
}

fn main() {
    let mut tracker = VisitorTracker::new(100);
    let visitor_ids = vec![String::from("visitor1"), String::from("visitor2"), String::from("visitor3")];
    tracker.track_unique_visitors(visitor_ids);
    println!("Total unique visitors: {}", tracker.display_unique_count());
