use std::collections::LinkedList;

pub struct PlaybackQueue {
    tracks: LinkedList<String>,
    current_track: Option<usize>,
}

impl PlaybackQueue {
    pub fn new() -> PlaybackQueue {
        PlaybackQueue {
            tracks: LinkedList::new(),
            current_track: None,
        }
    }

    pub fn add_track(&mut self, track: String) {
        self.tracks.push_back(track);
        if self.current_track.is_none() {
            self.current_track = Some(0);
        }
    }

    pub fn remove_track(&mut self, track: &str) {
        if let Some(pos) = self.tracks.iter().position(|t| t == track) {
            self.tracks.remove(pos);
            if let Some(current_pos) = self.current_track {
                if pos <= current_pos && current_pos > 0 {
                    self.current_track = Some(current_pos - 1);
                }
                if self.tracks.is_empty() {
                    self.current_track = None;
                }
            }
        }
    }

    pub fn skip_next(&mut self) {
        if let Some(current_pos) = self.current_track {
            if current_pos < self.tracks.len() - 1 {
                self.current_track = Some(current_pos + 1);
            }
        }
    }

    pub fn skip_previous(&mut self) {
        if let Some(current_pos) = self.current_track {
            if current_pos > 0 {
                self.current_track = Some(current_pos - 1);
            }
        }
    }

    pub fn reset_playback(&mut self) {
        if !self.tracks.is_empty() {
            self.current_track = Some(0);
        }
    }

    pub fn current_track(&self) -> Option<&String> {
        if let Some(current_pos) = self.current_track {
            self.tracks.iter().nth(current_pos)
        } else {
            None
        }
    }
}
