struct PlaybackQueue {
    queue: LinkedList<String>,
    max_size: usize,
}

impl PlaybackQueue {
    fn new(max_size: usize) -> Self {
        PlaybackQueue {
            queue: LinkedList::new(),
            max_size,
        }
    }

    fn add_track(&mut self, track: String) {
        if self.queue.len() < self.max_size {
            self.queue.push_back(track);
        } else {
            println!("Queue is full. Cannot add more tracks.");
        }
    }

    fn remove_track(&mut self, track: &str) {
        let pos = self.queue.iter().position(|x| x == track);
        if let Some(pos) = pos {
            let mut cursor = self.queue.cursor_front_mut();
            cursor.move_next_by(pos);
            cursor.remove_current();
        } else {
            println!("Track not found in queue.");
        }
    }

    fn skip_next(&mut self) {
        if let Some(track) = self.queue.pop_front() {
            self.queue.push_back(track);
        } else {
            println!("No tracks to skip.");
        }
    }

    fn skip_previous(&mut self) {
        if let Some(track) = self.queue.pop_back() {
            self.queue.push_front(track);
        } else {
            println!("No tracks to skip backwards.");
        }
    }

    fn reset_to_first(&mut self) {
        if let Some(track) = self.queue.pop_front() {
            self.queue.push_back(track);
        }
    }

    fn current_state(&self) -> Vec<String> {
        self.queue.iter().cloned().collect()
    }
}

