            self.playback_queue.push_back(track);
            self.add_to_recently_played(track.clone());
            return Some(track);
        }
        None
    }

    pub fn skip_previous(&mut self) -> Option<Track> {
        if let Some(track) = self.playback_queue.pop_back() {
