        if let Some(track) = self.playlist.pop_front() {
            self.record_recent_track(&track);
            Some(track)
        } else {
            None
        }
    }

    fn skip_previous(&mut self) -> Option<String> {
        if let Some(track) = self.recent_tracks.pop_back() {
            self.playlist.push_front(track.clone());
            Some(track)
        } else {
