public class ResponseCounter {
    private static final int MAX_SIZE = 100;
    private ConcurrentMap<String, Integer> responseMap = new ConcurrentHashMap<>();
    private LinkedHashSet<String> archiveSet = new LinkedHashSet<>();

    public void safeIncrementCount(List<String> studentResponses) {
        for (String response : studentResponses) {
            responseMap.putIfAbsent(response, 0);
            responseMap.compute(response, (key, val) -> val + 1);

            if (responseMap.size() >= MAX_SIZE) {
                archiveSet.addAll(responseMap.keySet());
                responseMap.clear();
            }
        }
    }

