use rand::seq::SliceRandom;
use chrono::prelude::*;
use log::{info, LevelFilter};

struct EmailTask {
    email: String,
    timestamp: DateTime<Utc>,
    urgent: bool,
}

fn manage_email_queue() {
    let mut email_queue: VecDeque<EmailTask> = VecDeque::new();

    // Simulating adding tasks to the queue
    email_queue.push_back(EmailTask {
        email: "example1@example.com".to_string(),
        timestamp: Utc::now(),
        urgent: false,
    });
    email_queue.push_back(EmailTask {
        email: "urgent@example.com".to_string(),
        timestamp: Utc::now(),
        urgent: true,
    });

    // Shuffling the queue to prioritize urgent emails
    let mut email_vec: Vec<EmailTask> = email_queue.into();
    email_vec.sort_by(|a, b| b.urgent.cmp(&a.urgent));
    email_vec.shuffle(&mut rand::thread_rng());
