fn combine_small_data_streams<I, T>(streams: Vec<I>) -> Vec<T>
where
    I: Iterator<Item = T>,
{
    let mut combined_stream = Vec::new();
    let mut interim_results: SmallVec<[T; 10]> = SmallVec::new();

    for stream in streams {
        for item in stream {
            if interim_results.len() < 10 {
                interim_results.push(item);
            } else {
                for result in interim_results.drain(..) {
                    combined_stream.push(result);
                }
                interim_results.push(item);
            }
        }
        interim_results.clear();
    }

    combined_stream
