use smallvec::SmallVec;
use std::io::{self, Read};

fn combine_small_data_streams<R: Read>(streams: Vec<R>) -> Vec<u8> {
    let mut combined_stream: Vec<u8> = Vec::new();
    let mut buffer = [0u8; 1024];
    let max_inline_storage = 10;

    for mut stream in streams {
        let mut small_vec: SmallVec<[u8; 10]> = SmallVec::new();

        loop {
            let bytes_read = match stream.read(&mut buffer) {
                Ok(0) => break,
                Ok(n) => n,
                Err(_) => continue,
            };

            small_vec.clear();
            for &byte in &buffer[..bytes_read] {
                if small_vec.len() == max_inline_storage {
                    combined_stream.extend_from_slice(&small_vec);
                    small_vec.clear();
                }
                small_vec.push(byte);
            }
            if !small_vec.is_empty() {
                combined_stream.extend_from_slice(&small_vec);
            }
        }
    }

    combined_stream
}
