use smallvec::SmallVec;
use std::collections::HashMap;

fn combine_small_data_streams<T: Clone>(
    data_streams: Vec<Vec<T>>,
) -> (Vec<T>, HashMap<usize, Vec<T>>) {
    let mut result: Vec<T> = Vec::new();
    let mut interim_results: HashMap<usize, Vec<T>> = HashMap::new();
    let mut identifiers: Vec<usize> = Vec::new();

    for (stream_id, stream) in data_streams.into_iter().enumerate() {
        let mut small_vec: SmallVec<[T; 10]> = SmallVec::new();

        for item in stream {
            small_vec.push(item);

            if small_vec.len() == 10 {
                let interim_result: Vec<T> = small_vec.iter().cloned().collect();
                identifiers.push(stream_id);
                interim_results.insert(stream_id, interim_result);
                small_vec.clear();
            }
        }

        if !small_vec.is_empty() {
            let interim_result: Vec<T> = small_vec.iter().cloned().collect();
            identifiers.push(stream_id);
            interim_results.insert(stream_id, interim_result);
        }
    }

    for id in identifiers {
        if let Some(interim_result) = interim_results.get(&id) {
            result.extend(interim_result.clone());
        }
    }

    (result, interim_results)
}
