// EventProcessor represents an event processing system
type EventProcessor struct {
	buffer       *bytes.Buffer
	capacity     int
	mu           sync.Mutex
	batchSize    int
	flushInterval time.Duration
}

// NewEventProcessor initializes a new event processor with fixed capacity and settings
func NewEventProcessor(capacity, batchSize int, flushInterval time.Duration) *EventProcessor {
	return &EventProcessor{
		buffer:       bytes.NewBuffer(make([]byte, 0, capacity)),
		capacity:     capacity,
		batchSize:    batchSize,
		flushInterval: flushInterval,
	}
}

// logEvents processes event data from the application
func (e *EventProcessor) logEvents(events <-chan string) {
	ticker := time.NewTicker(e.flushInterval)
	defer ticker.Stop()

	for {
		select {
		case event, ok := <-events:
			if !ok {
				e.flush()
				return
			}
			e.processEvent(event)

		case <-ticker.C:
			e.flush()
		}
	}
}

// processEvent accumulates and parses event messages into the buffer
func (e *EventProcessor) processEvent(event string) error {
	e.mu.Lock()
	defer e.mu.Unlock()

	if e.buffer.Len()+len(event) > e.capacity {
		return errors.New("buffer capacity exceeded")
	}
	e.buffer.Write([]byte(event))

	if e.buffer.Len() >= e.batchSize {
		e.flush()
	}

	return nil
}

// flush empties the buffer and simulates event processing
func (e *EventProcessor) flush() {
	e.mu.Lock()
	defer e.mu.Unlock()

	if e.buffer.Len() == 0 {
		return
	}

	fmt.Printf("Processing: %s\n", e.buffer.Bytes())
	e.buffer.Reset()
}

