type buffer struct {
	sync.Mutex
	buf    bytes.Buffer
	count  int
	notify chan struct{}
}

func (b *buffer) write(data []byte) error {
	b.Lock()
	defer b.Unlock()
	if b.count >= maxBufferCapacity {
		return errors.New("buffer capacity exceeded")
	}
	b.buf.Write(data)
	b.count++
	b.notify <- struct{}{}
	return nil
}

func (b *buffer) read() ([]byte, error) {
	b.Lock()
	defer b.Unlock()
	if b.buf.Len() == 0 {
		return nil, errors.New("buffer is empty")
	}
	output := make([]byte, b.buf.Len())
	_, err := b.buf.Read(output)
	b.count = 0
	return output, err
}

func logEvents(critical chan []byte, normal chan []byte) {
	buf := &buffer{notify: make(chan struct{}, 1)}
	ticker := time.NewTicker(batchInterval)
	defer ticker.Stop()

	go func() {
		for {
			select {
			case msg := <-critical:
				err := buf.write(msg)
				if err != nil {
					fmt.Println("Error:", err)
				}
			case msg := <-normal:
				err := buf.write(msg)
				if err != nil {
					fmt.Println("Error:", err)
				}
			case <-ticker.C:
				if buf.count > 0 {
					data, err := buf.read()
					if err != nil {
						fmt.Println("Error:", err)
					} else {
						processEvents(data)
					}
				}
			case <-buf.notify:
				if buf.count > 0 {
					data, err := buf.read()
					if err != nil {
						fmt.Println("Error:", err)
					} else {
						processEvents(data)
