package main

import (
	"errors"
	"fmt"
)

type InventoryManager struct {
	inventory map[int]int
	history   []string
	maxSize   int
}

func NewInventoryManager(maxSize int) *InventoryManager {
	return &InventoryManager{
		inventory: make(map[int]int),
		history:   make([]string, 0),
		maxSize:   maxSize,
	}
}

func (im *InventoryManager) pushHistory(action string) {
	im.history = append(im.history, action)
}

func (im *InventoryManager) popHistory() (string, error) {
	if len(im.history) == 0 {
		return "", errors.New("history stack is empty")
	}
	action := im.history[len(im.history)-1]
	im.history = im.history[:len(im.history)-1]
	return action, nil
}

func (im *InventoryManager) Add(productID int, quantity int) error {
	if len(im.inventory) >= im.maxSize {
		return errors.New("inventory limit reached")
	}
	im.inventory[productID] += quantity
	im.pushHistory(fmt.Sprintf("Add: %d items for product %d", quantity, productID))
	return nil
}

func (im *InventoryManager) Remove(productID int, quantity int) error {
	if _, exists := im.inventory[productID]; !exists || im.inventory[productID] < quantity {
		return errors.New("insufficient quantity or product not found")
	}
	im.inventory[productID] -= quantity
	im.pushHistory(fmt.Sprintf("Remove: %d items for product %d", quantity, productID))
	return nil
}

func (im *InventoryManager) Modify(productID int, quantity int) error {
	if _, exists := im.inventory[productID]; !exists {
		return errors.New("product not found")
	}
	im.inventory[productID] = quantity
	im.pushHistory(fmt.Sprintf("Modify: product %d set to %d items", productID, quantity))
	return nil
}

func (im *InventoryManager) Check() {
	fmt.Println("Inventory Check:")
	for id, qty := range im.inventory {
		fmt.Printf("Product %d: %d items\n", id, qty)
	}
	im.pushHistory("Check Inventory")
}

func trackInventoryStatus() *InventoryManager {
	return NewInventoryManager(100)
}

func main() {
	manager := trackInventoryStatus()
	manager.Add(1, 50)
	manager.Check()
	manager.Modify(1, 30)
	manager.Remove(1, 10)
	manager.Check()
}
