package main

import (
	"errors"
	"fmt"
)

type InventoryOperation struct {
	action    string
	productID string
	quantity  int
}

func trackInventoryStatus() {
	inventory := make(map[string]int)
	operationsStack := []InventoryOperation{}

	// Inventory operations
	const maxInventorySize = 100
	const maxStackSize = 20

	add := func(productID string, quantity int) error {
		if len(inventory) >= maxInventorySize {
			return errors.New("maximum inventory size reached")
		}
		inventory[productID] += quantity
		operationsStack = append(operationsStack, InventoryOperation{"add", productID, quantity})
		clearStackIfNeeded()
		return nil
	}

	remove := func(productID string, quantity int) error {
		if qty, exists := inventory[productID]; exists && qty >= quantity {
			inventory[productID] -= quantity
			operationsStack = append(operationsStack, InventoryOperation{"remove", productID, quantity})
			clearStackIfNeeded()
			return nil
		}
		return errors.New("insufficient stock or product does not exist")
	}

	modify := func(productID string, quantity int) error {
		if _, exists := inventory[productID]; exists {
			inventory[productID] = quantity
			operationsStack = append(operationsStack, InventoryOperation{"modify", productID, quantity})
			clearStackIfNeeded()
			return nil
		}
		return errors.New("product does not exist")
	}

	check := func(productID string) (int, error) {
		if qty, exists := inventory[productID]; exists {
			return qty, nil
		}
		return 0, errors.New("product does not exist")
	}

	pushOperation := func(op InventoryOperation) {
		operationsStack = append(operationsStack, op)
		clearStackIfNeeded()
	}

	popOperation := func() (InventoryOperation, error) {
		if len(operationsStack) == 0 {
			return InventoryOperation{}, errors.New("no operations to pop")
		}
		op := operationsStack[len(operationsStack)-1]
		operationsStack = operationsStack[:len(operationsStack)-1]
		return op, nil
	}

	clearStackIfNeeded := func() {
		if len(operationsStack) > maxStackSize {
			operationsStack = operationsStack[1:]
		}
	}

	// Example usage:
	err := add("P001", 50)
	if err != nil {
		fmt.Println(err)
	}
	err = add("P002", 30)
	if err != nil {
		fmt.Println(err)
	}
	err = modify("P001", 60)
	if err != nil {
		fmt.Println(err)
	}
	qty, err := check("P001")
	if err == nil {
		fmt.Printf("Product P001 Quantity: %d\n", qty)
	} else {
		fmt.Println(err)
	}
}

func main() {
	trackInventoryStatus()
}
