        // Normalize local by removing dots and converting to lowercase
        local.erase(std::remove(local.begin(), local.end(), '.'), local.end());
        std::transform(local.begin(), local.end(), local.begin(), ::tolower);

        // Convert domain to lowercase
        std::transform(domain.begin(), domain.end(), domain.begin(), ::tolower);

        uniqueEmails.insert(local + "@" + domain);
    }

    std::vector<std::string> filteredEmails(uniqueEmails.begin(), uniqueEmails.end());
    std::sort(filteredEmails.begin(), filteredEmails.end());

    if (filteredEmails.size() > 50) {
        filteredEmails.resize(50);
    }

    return filteredEmails;
