std::vector<std::string> filterUniqueEmails(const std::vector<std::string>& emails) {
    std::set<std::string> uniqueEmailSet;
    auto preprocess = [](const std::string& email) -> std::string {
        std::string lowerEmail;
        size_t atPosition = email.find('@');
        for (size_t i = 0; i < email.size(); ++i) {
            if (email[i] != '.' || i > atPosition) {
                lowerEmail += std::tolower(email[i]);
            }
        }
        return lowerEmail;
    };

    for (const auto& email : emails) {
        uniqueEmailSet.insert(preprocess(email));
    }

    std::priority_queue<std::string, std::vector<std::string>, std::greater<std::string>> pq;
    for (const auto& email : uniqueEmailSet) {
        pq.push(email);
    }

    std::vector<std::string> sortedEmailList;
    while (!pq.empty() && sortedEmailList.size() < 50) {
        sortedEmailList.push_back(pq.top());
        pq.pop();
    }

    return sortedEmailList;
}
