std::vector<std::string> filterUniqueEmails(std::vector<std::string> emails) {
    std::set<std::string> uniqueEmails;
    std::stack<std::string> emailStack;
    std::priority_queue<std::string, std::vector<std::string>, std::greater<std::string>> emailQueue;

    // Preprocess emails
    for (auto& email : emails) {
        std::string processedEmail;
        for (char c : email) {
            processedEmail += std::tolower(c);
        }
        auto atPos = processedEmail.find('@');
        if (atPos != std::string::npos) {
            std::string local = processedEmail.substr(0, atPos);
            std::string domain = processedEmail.substr(atPos);
            local.erase(std::remove(local.begin(), local.end(), '.'), local.end());
            processedEmail = local + domain;
        }

        emailStack.push(processedEmail);

        // Ensure we have backup capability; top of the stack is the most recent
        while (!emailStack.empty()) {
            std::string currentEmail = emailStack.top();
            emailStack.pop();
            uniqueEmails.insert(currentEmail);
            if (uniqueEmails.size() >= 50) break;
        }
    }

    // Use priority_queue to process emails
    for (const auto& email : uniqueEmails) {
        emailQueue.push(email);
    }

    std::vector<std::string> sortedUniqueEmails;
    while (!emailQueue.empty()) {
        sortedUniqueEmails.push_back(emailQueue.top());
        emailQueue.pop();
