struct LogEntry {
    std::string timestamp;
    std::string content;
};

bool compareLogEntry(const LogEntry& log1, const LogEntry& log2) {
    return log1.timestamp < log2.timestamp;
}

void mergeLogs(LogEntry& existingLog, const LogEntry& newLog) {
    existingLog.content += "\n" + newLog.content;
}

std::vector<LogEntry> sortLogsByTimestamp(const std::deque<LogEntry>& logStream, const std::string& cutoffTime) {
    std::deque<LogEntry> logDeque;
    for (const auto& log : logStream) {
        // Insert or merge the log
        auto it = std::find_if(logDeque.begin(), logDeque.end(),
            [&log](const LogEntry& existingLog) {
                return existingLog.timestamp == log.timestamp;
            });

        if (it != logDeque.end()) {
            // Merge contents of logs with duplicate timestamps
            mergeLogs(*it, log);
        } else {
            // Insert log maintaining chronological order
            auto pos = std::lower_bound(logDeque.begin(), logDeque.end(), log, compareLogEntry);
            logDeque.insert(pos, log);
        }

        // Ensure deque does not exceed 100 elements, but retains at least 10
        while (logDeque.size() > 100) {
            if (logDeque.size() > 10) {
                logDeque.pop_front();
            } else {
                break;
            }
        }
    }

    // Transfer logs after cutoffTime to a vector
    std::vector<LogEntry> sortedLogs;
    for (const auto& log : logDeque) {
        if (log.timestamp > cutoffTime) {
            sortedLogs.push_back(log);
        }
    }

    return sortedLogs;
}
