        for item in high_priority_inventory.iter_mut() {
            if item.0 == *product_id {
                item.1 += quantity_change;
                found = true;
                break;
            }
        }

        if high_priority_ids.contains(product_id) && !found && high_priority_inventory.len() < 10 {
            high_priority_inventory.push((*product_id, *quantity_change));
