#include <iostream>
#include <list>
#include <deque>
#include <algorithm>

struct Task {
    int id;
    std::string status;
    bool urgent;
};

void batchProcessTasks(std::list<Task>& tasks, const std::list<Task>& pendingUpdates) {
    std::deque<Task> processingQueue;

    // Insert updates into the processing queue
    for (const auto& task : pendingUpdates) {
        if (task.urgent) {
            processingQueue.emplace_front(task);
        } else {
            processingQueue.push_back(task);
        }
    }

    // Process tasks from the processing queue
    while (!processingQueue.empty()) {
        Task processedTask = processingQueue.front();
        processingQueue.pop_front();

        auto it = std::find_if(tasks.begin(), tasks.end(), [&processedTask](const Task& t) {
            return t.id == processedTask.id;
        });

        if (it != tasks.end()) {
            if (processedTask.status == "completed") {
                tasks.erase(it);
            } else {
                *it = processedTask;
            }
        } else {
            if (processedTask.status != "completed" && tasks.size() < 50) {
                tasks.push_back(processedTask);
            }
        }
    }
}

int main() {
    std::list<Task> tasks = {{1, "pending", false}, {2, "pending", true}};
    std::list<Task> pendingUpdates = {{1, "completed", false}, {3, "pending", true}};

    batchProcessTasks(tasks, pendingUpdates);

    for (const Task& task : tasks) {
        std::cout << "Task ID: " << task.id << ", Status: " << task.status << ", Urgent: " << task.urgent << std::endl;
    }

    return 0;
