        Queue<PDFMetadata> bufferQueue = new LinkedList<>(pdfMetadataList);

        while (!bufferQueue.isEmpty()) {
            PDFMetadata metaData = bufferQueue.poll();
            String version = metaData.version;
            List<String> fileList = versionMap.get(version);

            if (fileList == null) {
                fileList = new ArrayList<>();
                versionMap.put(version, fileList);
            }

            if (fileList.size() < 5) {
                fileList.add(metaData.fileName);
            }
        }

        return versionMap;
    }
