        while (!processingQueue.isEmpty()) {
            PdfMetadata pdf = processingQueue.poll();
            String version = pdf.getVersion();
            versionMap.putIfAbsent(version, new ArrayList<>());
            List<String> filesForVersion = versionMap.get(version);
            if (filesForVersion.size() < 5) {
