pub fn manage_student_grades() {
    let mut grades: ArrayVec<[StudentGrade; 50]> = ArrayVec::new();
    let mut top_grades: BinaryHeap<f32> = BinaryHeap::new();

    // Function to add a new grade
    fn add_grade(grades: &mut ArrayVec<[StudentGrade; 50]>, id: u32, grade: f32) {
        if grades.len() < 50 {
            grades.push(StudentGrade { id, grade });
            update_top_grades(&mut top_grades, grade);
        }
    }

    // Function to update an existing grade
    fn update_grade(grades: &mut ArrayVec<[StudentGrade; 50]>, id: u32, new_grade: f32) {
        if let Some(index) = grades.iter().position(|g| g.id == id) {
            grades[index].grade = new_grade;
            rebuild_top_grades(grades, &mut top_grades);
        }
    }

    // Function to delete a grade
    fn delete_grade(grades: &mut ArrayVec<[StudentGrade; 50]>, id: u32) {
        if let Some(index) = grades.iter().position(|g| g.id == id) {
            grades.remove(index);
            rebuild_top_grades(grades, &mut top_grades);
        }
    }

    // Function to compute the average of all grades
    fn compute_average(grades: &ArrayVec<[StudentGrade; 50]>) -> f32 {
        let sum: f32 = grades.iter().map(|g| g.grade).sum();
        if grades.len() == 0 {
            0.0
        } else {
            sum / grades.len() as f32
        }
    }

    // Function to update top 5 grades using BinaryHeap
    fn update_top_grades(top_grades: &mut BinaryHeap<f32>, grade: f32) {
        top_grades.push(grade);
        if top_grades.len() > 5 {
            top_grades.pop();
        }
    }

    // Function to rebuild top 5 grades
    fn rebuild_top_grades(grades: &ArrayVec<[StudentGrade; 50]>, top_grades: &mut BinaryHeap<f32>) {
        *top_grades = grades.iter().map(|g| g.grade).collect();
        while top_grades.len() > 5 {
            top_grades.pop();
        }
    }
}
