    fn add_grade(grades: &mut ArrayVec<GradeEntry, 50>, student_id: u32, grade: f32) {
        if grades.len() < 50 {
            grades.push(GradeEntry { student_id, grade });
        }
        update_top_grades(&mut top_grades, grade);
    }

    fn update_grade(grades: &mut ArrayVec<GradeEntry, 50>, student_id: u32, new_grade: f32) {
        for (index, entry) in grades.iter_mut().enumerate() {
            if entry.student_id == student_id {
                grades.update_at(index, GradeEntry { student_id, grade: new_grade });
                update_top_grades(&mut top_grades, new_grade);
                break;
            }
        }
    }

    fn delete_grade(grades: &mut ArrayVec<GradeEntry, 50>, student_id: u32) {
        for index in 0..grades.len() {
            if grades[index].student_id == student_id {
                grades.remove_at(index);
                break;
            }
        }
    }

    fn compute_average(grades: &ArrayVec<GradeEntry, 50>) -> f32 {
        let sum: f32 = grades.iter().map(|entry| entry.grade).sum();
        sum / grades.len() as f32
    }

    fn update_top_grades(top_grades: &mut BinaryHeap<f32>, new_grade: f32) {
        top_grades.push(new_grade);
        if top_grades.len() > 5 {
            top_grades.pop();
        }
    }

    fn peek_top_grade(top_grades: &BinaryHeap<f32>) -> Option<&f32> {
        top_grades.peek()
    }
}
