    std::unordered_map<char, char> bracketPairs = {{')', '('}, {'}', '{'}, {']', '['}};

    for (char ch : str) {
        if (bracketPairs.count(ch)) { // If it's a closing bracket
            if (stk.empty() || stk.top() != bracketPairs[ch]) {
                return false;
            }
            stk.pop();
        } else if (ch == '(' || ch == '{' || ch == '[') { // If it's an opening bracket
            if (stk.size() >= 10) {
