#include <iostream>
#include <vector>
#include <deque>

bool validateBrackets(const std::string& str) {
    std::vector<char> stack;
    std::deque<char> unmatched;
    const std::unordered_map<char, char> bracketPairs = {{')', '('}, {'}', '{'}, {']', '['}};

    for (char ch : str) {
        if (ch == '(' || ch == '{' || ch == '[') {
            if (stack.size() < 10) {
                stack.push_back(ch);
            } else {
                return false;  // Stack exceeded limit
            }
        } else if (ch == ')' || ch == '}' || ch == ']') {
            if (!stack.empty() && stack.back() == bracketPairs.at(ch)) {
                stack.pop_back();
            } else if (unmatched.size() < 5) {
                unmatched.push_back(ch);
            } else {
                return false;  // Unmatched deque exceeded limit
            }
        }
    }

    while (!stack.empty()) {
        if (unmatched.size() < 5) {
            unmatched.push_back(stack.back());
            stack.pop_back();
        } else {
            return false;  // Unmatched deque exceeded limit
        }
    }

    return stack.empty() && unmatched.empty();
}
