#include <deque>
#include <algorithm>

bool validateBrackets(const std::string& input) {
    std::vector<char> stack;
    std::deque<char> unmatched;
    for (char bracket : input) {
        if (bracket == '{' || bracket == '(' || bracket == '[') {
            if (stack.size() < 10) {
                stack.push_back(bracket);
            } else {
                unmatched.push_back(bracket);
                if (unmatched.size() > 5) {
                    unmatched.pop_front();
                }
            }
        } else if (bracket == '}' || bracket == ')' || bracket == ']') {
            if (!stack.empty()) {
                char top = stack.back();
                if ((top == '{' && bracket == '}') || 
                    (top == '(' && bracket == ')') || 
                    (top == '[' && bracket == ']')) {
                    stack.pop_back();
                } else {
                    unmatched.push_back(bracket);
                    if (unmatched.size() > 5) {
                        unmatched.pop_front();
                    }
                }
            } else {
                unmatched.push_back(bracket);
                if (unmatched.size() > 5) {
                    unmatched.pop_front();
                }
            }
        }
    }

    std::sort(unmatched.begin(), unmatched.end());

    return stack.empty() && unmatched.empty();
}

int main() {
    std::string testInput = "{[()]}";
    if (validateBrackets(testInput)) {
        std::cout << "Balanced" << std::endl;
    } else {
        std::cout << "Unbalanced" << std::endl;
    }
    return 0;
}
