func (c *ResourceCache) PeriodicBackup(interval time.Duration) {
	ticker := time.NewTicker(interval)
	go func() {
		for {
			select {
			case <-ticker.C:
				c.Backup()
			}
		}
	}()
}

func (c *ResourceCache) Backup() []ResourceStatus {
	var backup []ResourceStatus
	c.resources.Range(func(_, value interface{}) bool {
		if status, ok := value.(ResourceStatus); ok {
			backup = append(backup, status)
		}
		return true
	})
	return backup
}

