            throw new IllegalArgumentException("Cannot check more than 10 words for anagrams.");
        }

        HashMap<String, Integer> wordCountMap = new HashMap<>();
        for (String word : words) {
            String normalizedWord = normalize(word);
            wordCountMap.put(normalizedWord, 0);
        }

        String[] textWords = text.split("\\W+");

        for (String textWord : textWords) {
            String normalizedTextWord = normalize(textWord);
            if (wordCountMap.containsKey(normalizedTextWord)) {
                int count = wordCountMap.get(normalizedTextWord);
                wordCountMap.put(normalizedTextWord, count + 1);
            }
        }

        for (String word : words) {
            String normalizedWord = normalize(word);
            result.put(word, wordCountMap.get(normalizedWord));
        }

        return result;
    }

    private static String normalize(String word) {
        char[] chars = word.toLowerCase().toCharArray();
        java.util.Arrays.sort(chars);
        return new String(chars);
    }

    public static void main(String[] args) {
        String article = "The article with details focusing on certain words and their anagrams.";
        String[] wordsToCheck = {"details", "rat", "anagrams"};
        HashMap<String, Integer> occurrences = detectAnagramOccurrences(article, wordsToCheck);

        occurrences.forEach((word, count) -> System.out.println(word + ": " + count));
    }
