public class AnagramDetector {

    public static HashMap<String, Integer> detectAnagramOccurrences(String articleText, List<String> wordsToCheck) {
        HashMap<String, Integer> anagramOccurrences = new HashMap<>();
        LinkedList<String> tempAnagrams = new LinkedList<>();

        if (wordsToCheck.size() > 10) {
            throw new IllegalArgumentException("List of words to check must contain 10 or fewer elements.");
        }

        for (String word : wordsToCheck) {
            int count = findAnagrams(articleText, word);
            anagramOccurrences.put(word, count);
        }

        List<String> sortedKeys = new LinkedList<>(anagramOccurrences.keySet());
        sortedKeys.sort(String::compareTo);

        HashMap<String, Integer> sortedAnagramOccurrences = new HashMap<>();
        for (String key : sortedKeys) {
            sortedAnagramOccurrences.put(key, anagramOccurrences.get(key));
        }

        return sortedAnagramOccurrences;
    }

    private static int findAnagrams(String text, String word) {
        int count = 0;
        String sortedWord = sortString(word);

        for (String candidate : text.split("\\s+")) {
            if (sortString(candidate).equals(sortedWord)) {
                count++;
            }
        }

        return count;
    }

    private static String sortString(String input) {
        char[] chars = input.toCharArray();
        java.util.Arrays.sort(chars);
        return new String(chars);
    }
