struct Response {
    int participantID;
    int rating;
};

class SurveyData {
private:
    std::vector<Response> responses;

    void sortByID() {
        std::sort(responses.begin(), responses.end(),
                  [](const Response &a, const Response &b) {
                      return a.participantID < b.participantID;
                  });
    }

    int findParticipantIndex(int participantID) {
        auto it = std::find_if(responses.begin(), responses.end(),
                               [participantID](const Response &response) {
                                   return response.participantID == participantID;
                               });
        if (it != responses.end()) {
            return std::distance(responses.begin(), it);
        } else {
            return -1;
        }
    }

public:
    void addResponse(int participantID, int rating) {
        if (responses.size() >= 100) {
            std::cout << "Max participant limit reached." << std::endl;
            return;
        }
        if (findParticipantIndex(participantID) != -1) {
            std::cout << "Participant ID must be unique." << std::endl;
            return;
        }
        responses.push_back({participantID, rating});
        sortByID();
    }

    bool updateResponse(int participantID, int rating) {
        int index = findParticipantIndex(participantID);
        if (index != -1) {
            responses[index].rating = rating;
            return true;
        }
        return false;
    }

    bool deleteResponse(int participantID) {
        int index = findParticipantIndex(participantID);
        if (index != -1) {
            responses.erase(responses.begin() + index);
            return true;
        }
        return false;
    }

    int queryResponse(int participantID) {
        int index = findParticipantIndex(participantID);
        if (index != -1) {
            return responses[index].rating;
        }
        return -1; // Indicates participant not found
    }
};

int main() {
    SurveyData survey;
    survey.addResponse(1, 5);
    survey.addResponse(2, 3);
    std::cout << "Rating for participant 1: " << survey.queryResponse(1) << std::endl;
    survey.updateResponse(2, 4);
    std::cout << "Updated rating for participant 2: " << survey.queryResponse(2) << std::endl;
    survey.deleteResponse(1);
    std::cout << "Rating for participant 1 after deletion: " << survey.queryResponse(1) << std::endl;
    return 0;
}
