        if (responses.size() >= 100) {
            std::cerr << "Maximum number of participants reached." << std::endl;
            return;
        }
        auto it = std::find_if(responses.begin(), responses.end(), [participantID](const Response& r) {
            return r.participantID == participantID;
        });

        if (it != responses.end()) {
            std::cerr << "Participant ID must be unique." << std::endl;
            return;
        }

        responses.push_back({participantID, rating});
        std::sort(responses.begin(), responses.end(), [](const Response& a, const Response& b) {
            return a.participantID < b.participantID;
        });
    }

    void updateRating(int participantID, int newRating) {
        auto it = std::find_if(responses.begin(), responses.end(), [participantID](const Response& r) {
            return r.participantID == participantID;
        });

        if (it != responses.end()) {
            it->rating = newRating;
        } else {
            std::cerr << "Participant ID not found." << std::endl;
        }
    }

    void deleteResponse(int participantID) {
        auto it = std::remove_if(responses.begin(), responses.end(), [participantID](const Response& r) {
            return r.participantID == participantID;
        });

        if (it != responses.end()) {
            responses.erase(it, responses.end());
        } else {
            std::cerr << "Participant ID not found." << std::endl;
        }
    }

    int queryRating(int participantID) {
        auto it = std::find_if(responses.begin(), responses.end(), [participantID](const Response& r) {
            return r.participantID == participantID;
        });

        if (it != responses.end()) {
            return it->rating;
        } else {
            std::cerr << "Participant ID not found." << std::endl;
            return -1;
        }
    }

    double calculateAverageRating() {
        if (responses.empty()) return 0.0;
        int sum = std::accumulate(responses.begin(), responses.end(), 0, [](int acc, const Response& r) {
            return acc + r.rating;
        });
        return static_cast<double>(sum) / responses.size();
    }
};
