use std::collections::HashMap;

fn analyze_feedback(feedback: &str) -> HashMap<String, usize> {
    let mut word_count = HashMap::new();
    let feedback = feedback.to_lowercase();
    let words = feedback.split_whitespace()
                        .map(|word| word.trim_matches(|c: char| !c.is_alphabetic()));

    for word in words {
        if !word.is_empty() {
            *word_count.entry(word.to_string()).or_insert(0) += 1;
        }
    }

    if word_count.len() > 50 {
        let mut sorted_entries: Vec<_> = word_count.into_iter().collect();
        sorted_entries.sort_by(|a, b| b.1.cmp(&a.1));
        sorted_entries.truncate(50);
        return HashMap::from_iter(sorted_entries);
    }

    word_count
}
