// Employee struct to hold employee details
type Employee struct {
	Name     string
	ID       int
	Position string
	Salary   float64
}

// Stack struct to hold employees and enforce a maximum of 100 records
type Stack struct {
	records []Employee
	limit   int
}

// Map to access employee records by ID
var employeeMap = make(map[int]Employee)

// Error messages
var errStackFull = errors.New("stack is full")
var errStackEmpty = errors.New("stack is empty")

// Initialize a stack with a limit of 100 records
func newStack() *Stack {
	return &Stack{
		records: make([]Employee, 0, 100),
		limit:   100,
	}
}

// Push function to add an employee record to the stack
func (s *Stack) push(employee Employee) error {
	if len(s.records) >= s.limit {
		return errStackFull
	}
	s.records = append(s.records, employee)
	employeeMap[employee.ID] = employee
	return nil
}

// Pop function to remove the most recent employee record from the stack
func (s *Stack) pop() (Employee, error) {
	if len(s.records) == 0 {
		return Employee{}, errStackEmpty
	}
	employee := s.records[len(s.records)-1]
	s.records = s.records[:len(s.records)-1]
	delete(employeeMap, employee.ID)
	return employee, nil
}

// Search function to retrieve an employee record by ID
func search(id int) (Employee, bool) {
	employee, found := employeeMap[id]
	return employee, found
}

// Usage example
func manageEmployeeRecords() {
	stack := newStack()

	// Add employee records
	stack.push(Employee{"John Doe", 101, "Software Engineer", 75000})
	stack.push(Employee{"Jane Smith", 102, "Project Manager", 85000})

	// Retrieve an employee record by ID
	if emp, found := search(101); found {
		fmt.Printf("Found: %+v\n", emp)
	} else {
		fmt.Println("Employee not found")
	}

	// Remove an employee record
	if emp, err := stack.pop(); err == nil {
		fmt.Printf("Popped: %+v\n", emp)
	} else {
		fmt.Println(err)
	}

	// Deleting an employee record
	delete(employeeMap, 102)

	// Trying to retrieve a deleted employee
	if emp, found := search(102); found {
		fmt.Printf("Found: %+v\n", emp)
	} else {
		fmt.Println("Employee not found")
	}
}

func main() {
	manageEmployeeRecords()
}
