std::vector<double> computeRollingAverages(const std::vector<double>& temperatures, int windowSize) {
    std::vector<double> rollingAverages;
    std::vector<double> intermediate;

    int n = temperatures.size();

    for (int i = 0; i < n; ++i) {
        int start = std::max(0, i - windowSize / 2);
        int end = std::min(n - 1, i + windowSize / 2);

        intermediate.clear();
        for (int j = start; j <= end; ++j) {
            intermediate.push_back(temperatures[j]);
        }

        double sum = std::accumulate(intermediate.begin(), intermediate.end(), 0.0);
        double average = sum / intermediate.size();

        if (rollingAverages.size() >= 10) {
            rollingAverages.erase(rollingAverages.begin());
        }
        rollingAverages.emplace_back(average);
    }

    return rollingAverages;
}
