std::vector<double> computeRollingAverages(const std::vector<double>& temperatures, int windowSize) {
    std::vector<double> result;
    std::vector<double> intermediate;
    std::unordered_set<double> uniqueAverages;

    int n = temperatures.size();

    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        int count = 0;

        for (int j = i; j < std::min(i + windowSize, n); ++j) {
            sum += temperatures[j];
            count++;
        }

        double average = sum / count;

        if (uniqueAverages.find(average) == uniqueAverages.end()) {
            uniqueAverages.insert(average);
            intermediate.push_back(average);
        }
    }

    for (int i = 0; i < intermediate.size() && result.size() < 10; ++i) {
        result.push_back(intermediate[i]);
