import java.util.*;

public class ContactMerger {

    public static LinkedList<String> mergeContactLists(Collection<LinkedList<String>> contactLists) {
        HashMap<String, Integer> contactFrequency = new HashMap<>();
        LinkedList<String> mergedContacts = new LinkedList<>();

        // Count occurrences of each contact
        for (LinkedList<String> list : contactLists) {
            for (String contact : list) {
                contactFrequency.put(contact, contactFrequency.getOrDefault(contact, 0) + 1);
            }
        }

        // Add contacts occurring in more than one list and remove duplicates
        for (LinkedList<String> list : contactLists) {
            for (String contact : list) {
                if (contactFrequency.get(contact) > 1 && !mergedContacts.contains(contact)) {
                    mergedContacts.add(contact);
                }
            }
        }

        // Sort alphabetically
        Collections.sort(mergedContacts);

        // Restrict size to 100 contacts
        while (mergedContacts.size() > 100) {
            mergedContacts.removeLast();
        }

        return mergedContacts;
    }
}
