type LogBuffer struct {
	buffer   *bytes.Buffer
	capacity int
	logs     []string
}

func NewLogBuffer(capacity int) *LogBuffer {
	return &LogBuffer{
		buffer:   new(bytes.Buffer),
		capacity: capacity,
		logs:     make([]string, 0, capacity),
	}
}

func (lb *LogBuffer) push(logEntry string) {
	if len(lb.logs) >= lb.capacity {
		lb.pop()
	}
	lb.logs = append(lb.logs, logEntry)
	lb.buffer.WriteString(logEntry + "\n")
}

func (lb *LogBuffer) pop() {
	if len(lb.logs) > 0 {
		lb.logs = lb.logs[1:]
		bufContent := strings.Join(lb.logs, "\n")
		lb.buffer.Reset()
		lb.buffer.WriteString(bufContent)
	}
}

func (lb *LogBuffer) searchErrorPatterns(pattern string) map[string]int {
	report := make(map[string]int)
	logEntries := strings.Split(lb.buffer.String(), "\n")
	for _, entry := range logEntries {
		if strings.Contains(entry, pattern) {
			report[entry]++
		}
	}
	return report
}

