package main

import (
	"bufio"
	"bytes"
	"fmt"
	"strings"
)

type LogBuffer struct {
	buffer *bytes.Buffer
	size   int
	maxSize int
	logCount int
}

func NewLogBuffer(maxSize int) *LogBuffer {
	return &LogBuffer{
		buffer:  new(bytes.Buffer),
		maxSize: maxSize,
	}
}

func (lb *LogBuffer) Push(logs []string) {
	for i, log := range logs {
		if lb.logCount == lb.maxSize {
			lb.Pop()
		}
		if i%2 == 0 && lb.logCount < lb.maxSize {
			lb.buffer.WriteString(log + "\n")
			lb.logCount++
		}
	}
}

func (lb *LogBuffer) Pop() {
	scanner := bufio.NewScanner(lb.buffer)
	if scanner.Scan() {
		offset := len(scanner.Text()) + 1
		lb.buffer.Next(offset)
		lb.logCount--
	}
}

func (lb *LogBuffer) SearchErrors(pattern string) map[string]int {
	errorFrequency := make(map[string]int)
	scanner := bufio.NewScanner(lb.buffer)
	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, pattern) {
			errorFrequency[line]++
		}
	}
	return errorFrequency
}

type ErrorReportArchive struct {
	reports []map[string]int
}

func NewErrorReportArchive() *ErrorReportArchive {
	return &ErrorReportArchive{
		reports: make([]map[string]int, 0),
	}
}

func (era *ErrorReportArchive) AddReport(report map[string]int) {
	era.reports = append(era.reports, report)
}

func (era *ErrorReportArchive) RemoveReport(index int) {
	if index >= 0 && index < len(era.reports) {
		era.reports = append(era.reports[:index], era.reports[index+1:]...)
	}
}

func processLogFile(logs []string) map[string]int {
	logBuffer := NewLogBuffer(1000)
	errorPattern := "ERROR"

	logBuffer.Push(logs)
	foundErrors := logBuffer.SearchErrors(errorPattern)

	errorArchive := NewErrorReportArchive()
	errorArchive.AddReport(foundErrors)

	return foundErrors
}

func main() {
	logs := []string{"INFO: Network up", "ERROR: Connection lost", "INFO: Reconnected", "ERROR: Connection lost", "INFO: Network stable", "ERROR: Timeout"}
	report := processLogFile(logs)
	fmt.Println("Error Report:", report)
}
