fn detect_cycle_in_graph(graph: &HashMap<i32, Vec<i32>>) -> bool {
    fn dfs(node: i32, visited: &mut HashSet<i32>, rec_stack: &mut HashSet<i32>, graph: &HashMap<i32, Vec<i32>>) -> bool {
        if rec_stack.contains(&node) {
            return true;
        }
        if visited.contains(&node) {
            return false;
        }
        visited.insert(node);
        rec_stack.insert(node);

        if let Some(neighbors) = graph.get(&node) {
            for &neighbor in neighbors {
                if dfs(neighbor, visited, rec_stack, graph) {
                    return true;
                }
            }
        }

        rec_stack.remove(&node);
        false
    }

    let mut visited = HashSet::new();
    let mut rec_stack = HashSet::new();

    for &node in graph.keys() {
        if dfs(node, &mut visited, &mut rec_stack, graph) {
            return true;
        }
