use std::collections::{HashMap, HashSet};

fn detect_cycle_in_graph(graph: &HashMap<i32, Vec<i32>>) -> (bool, Vec<Vec<i32>>) {
    let mut visited = HashSet::with_capacity(10);
    let mut cycles = Vec::new();

    fn dfs(
        node: i32,
        graph: &HashMap<i32, Vec<i32>>,
        visited: &mut HashSet<i32>,
        path: &mut Vec<i32>,
        cycles: &mut Vec<Vec<i32>>,
    ) -> bool {
        if visited.contains(&node) {
            let start_pos = path.iter().position(|&x| x == node).unwrap_or(0);
            cycles.push(path[start_pos..].to_vec());
            return true;
        }

        if visited.len() >= 10 {
            return false; // Avoid exceeding maximum size of the HashSet
        }

        visited.insert(node);
        path.push(node);

        if let Some(neighbors) = graph.get(&node) {
            for &neighbor in neighbors {
                if dfs(neighbor, graph, visited, path, cycles) {
                    return true;
                }
            }
        }

        visited.remove(&node);
        path.pop();
        false
    }

    for &node in graph.keys() {
        if dfs(node, graph, &mut visited, &mut Vec::new(), &mut cycles) {
            return (true, cycles);
        }
    }

    (false, cycles)
}
