import java.util.ArrayList;
import java.util.PriorityQueue;
import java.util.Stack;

class Meeting {
    private int urgency;
    private boolean completed;

    public Meeting(int urgency) {
        this.urgency = urgency;
        this.completed = false;
    }

    public int getUrgency() {
        return urgency;
    }

    public void markCompleted() {
        this.completed = true;
    }

    @Override
    public String toString() {
        return "Meeting{urgency=" + urgency + ", completed=" + completed + '}';
    }
}

public class MeetingScheduler {

    public ArrayList<Meeting> organizeMeetings(ArrayList<Meeting> meetings) {
        PriorityQueue<Meeting> meetingQueue = new PriorityQueue<>((m1, m2) -> m2.getUrgency() - m1.getUrgency());
        Stack<Meeting> rescheduleStack = new Stack<>();
        ArrayList<Meeting> processedMeetings = new ArrayList<>();

        // Add meetings to the priority queue with a limit of 10
        for (Meeting meeting : meetings) {
            meetingQueue.offer(meeting);
            if (meetingQueue.size() > 10) {
                rescheduleStack.push(meetingQueue.poll());
            }
        }

        // Process meetings according to urgency
        while (!meetingQueue.isEmpty()) {
            Meeting meeting = meetingQueue.poll();
            meeting.markCompleted();
            processedMeetings.add(meeting);
        }

        // Handle rescheduled meetings
        while (!rescheduleStack.isEmpty()) {
            meetingQueue.offer(rescheduleStack.pop());
            if (!meetingQueue.isEmpty()) {
                Meeting meeting = meetingQueue.poll();
                meeting.markCompleted();
                processedMeetings.add(meeting);
            }
        }

        return processedMeetings;
    }
}
