        PriorityQueue<Meeting> priorityQueue = new PriorityQueue<>(Comparator.comparingInt(Meeting::getUrgency).reversed());
        Stack<Meeting> rescheduleStack = new Stack<>();
        HashSet<String> uniqueMeetingIds = new HashSet<>();
        ArrayList<Meeting> completedMeetings = new ArrayList<>();

        for (Meeting meeting : meetings) {
            if (!uniqueMeetingIds.contains(meeting.getId())) {
                uniqueMeetingIds.add(meeting.getId());
                priorityQueue.offer(meeting);
            }
        }

        while (!priorityQueue.isEmpty()) {
            Meeting meeting = priorityQueue.poll();
            completedMeetings.add(new Meeting(meeting.getUrgency(), meeting.getId() + " completed"));

            if (completedMeetings.size() >= 10) {
                rescheduleStack.push(meeting);
            }
        }

        while (!rescheduleStack.isEmpty()) {
            Meeting meeting = rescheduleStack.pop();
            priorityQueue.offer(meeting);
        }

        return completedMeetings;
