};

void analyzeStudentPerformance(const std::vector<StudentPerformance>& students) {
    if (students.size() > 100) {
        std::cerr << "Error: Student vector size exceeds 100." << std::endl;
        return;
    }

    std::map<std::string, double> totalGrades;
    std::map<std::string, int> courseCounts;
    std::stack<std::map<std::string, double>> history;

    for (const auto& student : students) {
        for (const auto& subjectGrade : student.grades) {
            totalGrades[subjectGrade.first] += subjectGrade.second;
            courseCounts[subjectGrade.first]++;
        }
    }

    std::map<std::string, double> averageGrades;
    for (const auto& totalGrade : totalGrades) {
        averageGrades[totalGrade.first] = totalGrade.second / courseCounts[totalGrade.first];
    }

    history.push(averageGrades);

    for (const auto& averageGrade : averageGrades) {
        std::cout << "Average grade for course " << averageGrade.first << ": " << averageGrade.second << std::endl;
    }
}

int main() {
    std::vector<StudentPerformance> students = {
        { { {"Math", 85}, {"Science", 90} } },
        { { {"Math", 78}, {"Science", 85} } }
    };

    analyzeStudentPerformance(students);

