class Node:
    def __init__(self, order_id):
        self.order_id = order_id
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, order_id):
        if not self.head:
            self.head = Node(order_id)
        else:
            current = self.head
            while current.next:
                current = current.next
            current.next = Node(order_id)

    def move_to_end(self, order_id):
        if not self.head or self.head.order_id == order_id:
            return
        prev = None
        current = self.head
        while current and current.order_id != order_id:
            prev = current
            current = current.next
        if current:
            if prev:
                prev.next = current.next
            else:
                self.head = current.next
            self.append(order_id)

def track_online_orders(order_tracking_system, orders):
    assert isinstance(order_tracking_system, dict), "The tracking system must be a dictionary."

    order_history = LinkedList()

    for order_id, status in orders:
        if len(order_tracking_system) >= 1000 and order_id not in order_tracking_system:
            return "Error: Cannot exceed 1000 orders in the tracking system."

        order_tracking_system[order_id] = status
        order_history.move_to_end(order_id)
