class Node:
    def __init__(self, order_id):
        self.order_id = order_id
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, order_id):
        new_node = Node(order_id)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def pop(self):
        if not self.head:
            return None
        if not self.head.next:
            value = self.head.order_id
            self.head = None
            return value
        prev = None
        current = self.head
        while current.next:
            prev = current
            current = current.next
        prev.next = None
        return current.order_id

    def remove(self, order_id):
        current = self.head
        prev = None
        while current:
            if current.order_id == order_id:
                if prev:
                    prev.next = current.next
                else:
                    self.head = current.next
                return
            prev = current
            current = current.next

def track_online_orders(order_tracking, orders):
    assert isinstance(order_tracking, dict), "Order tracking system must be a dictionary."
    order_history = LinkedList()

    for order_id, status in orders:
        if order_id in order_tracking:
            order_history.remove(order_id)
        elif len(order_tracking) >= 1000:
            return "Error: Cannot add more than 1000 orders."

        order_tracking[order_id] = status
        order_history.append(order_id)

        if len(order_tracking) > 1000:
            oldest_order_id = order_history.pop()
            del order_tracking[oldest_order_id]

    assert isinstance(order_tracking, dict), "Order tracking system must remain a dictionary."
